  Future<void> createOrSwitchWorkbook(String name) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workbookName = name.trim().isEmpty ? '默认工作本' : name.trim();
    final workspace = _requireWorkspaceRoot();
    final manifestPath = await _writeWorkbookManifest(
      workspace,
      currentName: workbookName,
      addName: workbookName,
    );
    final workbookWorkspace =
        _workbookWorkspaceDir(workspace, currentName: workbookName);
    await _loadExistingArtifacts(workbookWorkspace);
    state = state.copyWith(
      currentWorkbookName: workbookName,
      workspacePath: workbookWorkspace.path,
      workbookManifestPath: manifestPath,
      lastMessage: '已切换到工作本：$workbookName。',
      lastError: '',
    );
    await _appendEventLedgerRecord(
      eventType: 'workspace_lifecycle',
      module: 'workspace',
      action: 'create_workbook',
      status: 'completed',
      targetId: 'WB_${_stableHash(workbookName)}',
      targetName: workbookName,
      artifactPath: manifestPath,
      source: 'workbook_manifest',
      metadata: {
        'current_workbook': workbookName,
        'workbook_manifest_path': manifestPath,
      },
    );
    notifyListeners();
  }

  Future<void> deleteWorkbook(String name) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workbookName = name.trim();
    if (workbookName.isEmpty) {
      return;
    }
    final workspace = _requireWorkspaceRoot();
    final result = await _deleteWorkbookFromManifest(workspace, workbookName);
    if (result == null) {
      state = state.copyWith(
        lastError: '无法删除工作本：$workbookName；请确认记录存在且至少保留一个工作本。',
        lastMessage: '',
      );
      notifyListeners();
      return;
    }
    await _deleteWorkbookAssetDirectory(workspace, workbookName);
    final (manifestPath, currentName, workbookNames) = result;
    final workbookWorkspace =
        _workbookWorkspaceDir(workspace, currentName: currentName);
    await _loadExistingArtifacts(workbookWorkspace);
    state = state.copyWith(
      currentWorkbookName: currentName,
      workspacePath: workbookWorkspace.path,
      workbookManifestPath: manifestPath,
      workbookNames: workbookNames,
      lastMessage: '已删除工作本：$workbookName。',
      lastError: '',
    );
    await _appendEventLedgerRecord(
      eventType: 'workspace_lifecycle',
      module: 'workspace',
      action: 'delete_workbook',
      status: 'completed',
      targetId: 'WB_${_stableHash(workbookName)}',
      targetName: workbookName,
      artifactPath: manifestPath,
      source: 'workbook_manifest',
      metadata: {
        'deleted_workbook': workbookName,
        'next_current_workbook': currentName,
        'remaining_workbook_count': workbookNames.length,
      },
    );
    notifyListeners();
  }

  Future<void> pickAndImportFile() async {
    if (!_canRunDesktop()) {
      return;
    }
    final file = await openFile(
      acceptedTypeGroups: const [
        XTypeGroup(
          label: 'Knowledge sources',
          extensions: ['md', 'txt', 'pdf', 'docx'],
        ),
      ],
    );
    if (file == null) {
      state = state.copyWith(
        lastMessage: '未选择文件；导入未执行。',
        phase: Rc6RuntimePhase.ready,
      );
      notifyListeners();
      return;
    }
    await importFilePath(file.path);
  }

  Future<void> pickAndImportFolder() async {
    if (!_canRunDesktop()) {
      return;
    }
    final path = await getDirectoryPath();
    if (path == null) {
      state = state.copyWith(
        lastMessage: '未选择文件夹；导入未执行。',
        phase: Rc6RuntimePhase.ready,
      );
      notifyListeners();
      return;
    }
    await importFolderPath(path);
  }

  Future<void> importOwnerInputFolder() async {
    await importFolderPath(r'D:\HeiTang-Codex-WorkSpace\input');
  }

  Future<void> importLocalPath(String path) async {
    if (!_canRunDesktop()) {
      return;
    }
    final normalized = path.trim().replaceAll('"', '');
    if (normalized.isEmpty) {
      _fail('请输入要导入的本地文件或文件夹路径。');
      return;
    }
    final type = await FileSystemEntity.type(normalized);
    if (type == FileSystemEntityType.directory) {
      await importFolderPath(normalized);
      return;
    }
    if (type == FileSystemEntityType.file) {
      await importFilePath(normalized);
      return;
    }
    _fail('未找到本地路径：$normalized');
  }

  Future<void> pickAndRunRealInputFolderE2E({String query = '赚钱 小生意'}) async {
