          })}\n',
      mode: FileMode.append,
      encoding: utf8,
    );
    await _appendEventLedgerRecord(
      eventType: 'validate_knowledge_base',
      module: 'knowledge_base',
      action: 'save_retrieval_validation_report',
      status: 'completed',
      targetId: _listOfStrings(payload['selected_kb_ids']).join(','),
      targetName: payload['query'].toString(),
      artifactPath: reportPath,
      source: 'runtime',
      metadata: {
        'query': payload['query'],
        'selected_kb_ids': payload['selected_kb_ids'],
        'result_count': payload['result_count'],
        'conflict_count': payload['conflict_count'],
        'citation_coverage': payload['citation_coverage'],
        'report_path': reportPath,
        'markdown_report_path': markdownPath,
        'history_path': historyPath,
        'scope_resolution': payload['scope_resolution'],
        'primary_knowledge_base_id': payload['primary_knowledge_base_id'],
        'used_knowledge_base_ids': payload['used_knowledge_base_ids'],
        'knowledge_base_version_ids': payload['knowledge_base_version_ids'],
        'answer_status': payload['answer_status'],
        'evidence_status': payload['evidence_status'],
        'risk_level': payload['risk_level'],
        'missing_evidence': payload['missing_evidence'],
        'exception_count': payload['exception_count'],
        'human_review_required': payload['human_review_required'],
        'semantic_reasoning_status': payload['semantic_reasoning_status'],
        'rule_engine_status': payload['rule_engine_status'],
        'retrieval_plan_path': payload['retrieval_plan_path'],
        'rerank_report_path': payload['rerank_report_path'],
        'citation_coverage_report_path':
            payload['citation_coverage_report_path'],
        'conflict_report_path': payload['conflict_report_path'],
        'external_validation_boundary_path':
            payload['external_validation_boundary_path'],
      },
    );
    await runOrdinaryUiExternalSourceVerificationAcceptance();
    state = state.copyWith(
      retrievalValidationReportPath: reportPath,
      retrievalValidationMarkdownPath: markdownPath,
      retrievalValidationHistoryPath: historyPath,
      lastMessage: '检索验证报告和历史已保存。',
      lastError: '',
    );
    notifyListeners();
    return reportPath;
  }

  Future<void> generateMarkdown({
    Rc6DocumentGenerationConfig config = const Rc6DocumentGenerationConfig(),
  }) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final kbDir = Directory(_join(workspace.path, 'kb'));
    if (!await kbDir.exists()) {
      _fail('请先构建知识库，再生成文档。');
      return;
    }
    final existingManifest = await _readJsonObject(
        _join(workspace.path, 'doc', 'generation_manifest.json'));
    final historyBeforeClear =
        _listOfMaps(existingManifest['generation_history']);
    await _clearWorkspacePath(_join(workspace.path, 'doc'));
    await _runCoreAction(
      actionId: 'generate_markdown',
      arguments: [
        'generate-md',
        '--package',
        kbDir.path,
        '--output',
        _join(workspace.path, 'doc'),
        '--title',
        config.title,
      ],
      outputPath: _join(workspace.path, 'doc'),
      nextPhase: Rc6RuntimePhase.documentGenerated,
      successMessage: 'Markdown 文档已生成。',
    );
    if (state.lastResult?.passed == true) {
      await _writeReadingNotes(config: config);
      await _writeDocumentGenerationManifest(
        config: config,
        existingHistory: historyBeforeClear,
      );
      await _appendOrchestrationPlanRecord(
        layer: 'document',
        action: 'generate_document',
        artifact: _join(workspace.path, 'doc', 'generation_manifest.json'),
        status: 'completed',
        resources: {
          'kb_package': kbDir.path,
          'template': config.templateMode,
          'generation_type': config.generationType,
          'output_format': config.outputFormat,
        },
      );
    }
    await _loadExistingArtifacts();
    notifyListeners();
  }

  Future<void> exportMarkdownDocument() async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final docDir = Directory(_join(workspace.path, 'doc'));
    final generated = File(_join(docDir.path, 'generated.md'));
    final notes = File(_join(docDir.path, 'reading_notes.md'));
    final edited = File(_join(docDir.path, 'edited_document.md'));
    if (!await generated.exists() &&
        !await notes.exists() &&
        !await edited.exists()) {
      _fail('请先在文档生成页生成 Markdown 草稿。');
      return;
    }
    state = state.copyWith(
      running: true,
      lastMessage: '正在导出 Markdown 文档...',
      lastError: '',
    );
    notifyListeners();
    final exportDir = Directory(_join(workspace.path, 'export'));
    await _clearWorkspacePath(exportDir.path);
    await exportDir.create(recursive: true);
    final source = await edited.exists()
        ? edited
        : await notes.exists()
            ? notes
            : generated;
    final exported = File(_join(exportDir.path, 'reading_notes_export.md'));
    await source.copy(exported.path);
    final binding = await _documentGenerationBinding(workspace);
    final manifest = {
      'schema_version': 'rc10_document_export.v1',
      'status': 'pass',
      'format': 'markdown',
      ...binding.toJson(),
      'source': source.path,
      'output': exported.path,
      'size_bytes': await exported.length(),
      'workspace': workspace.path,
      'generation_manifest': _join(docDir.path, 'generation_manifest.json'),
      'edit_manifest':
          await File(_join(docDir.path, 'edit_manifest.json')).exists()
              ? _join(docDir.path, 'edit_manifest.json')
              : '',
      'generation_config': await _latestDocumentGenerationConfig(workspace),
    };
    await File(_join(exportDir.path, 'export_manifest.json')).writeAsString(
      const JsonEncoder.withIndent('  ').convert(manifest),
      encoding: utf8,
    );
    await _appendOrchestrationPlanRecord(
      layer: 'document',
      action: 'export_document',
      artifact: _join(exportDir.path, 'export_manifest.json'),
      status: 'completed',
      resources: {
        'format': 'markdown',
        'source': source.path,
        'output': exported.path,
      },
    );
    await _appendEventLedgerRecord(
      eventType: 'export_document',
      module: 'document_generation',
      action: 'export_document_md',
      status: 'completed',
      targetId: 'document_export_md',
      targetName: 'Markdown 文档导出',
      artifactPath: exported.path,
      source: 'document_generation',
      metadata: {
        'format': 'md',
        'manifest_path': _join(exportDir.path, 'export_manifest.json'),
        'adapter': 'local_markdown',
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'generated_document_export_md',
      artifactType: 'generated_document',
      title: 'Markdown 文档导出',
      sourceModule: 'document_generation',
      sourceId: 'export_document_md',
      filePath: exported.path,
      status: 'completed',
      metadata: {
        'format': 'md',
        'manifest_path': _join(exportDir.path, 'export_manifest.json'),
        'adapter': 'local_markdown',
      },
    );
    state = state.copyWith(
      running: false,
      phase: Rc6RuntimePhase.documentGenerated,
      exportedDocumentPath: exported.path,
      exportManifestPath: _join(exportDir.path, 'export_manifest.json'),
      lastMessage: 'Markdown 文档已导出。',
      lastError: '',
    );
    await _loadExistingArtifacts();
    notifyListeners();
  }

  Future<void> clearDocumentGenerationHistory() async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final manifestPath =
        _join(workspace.path, 'doc', 'generation_manifest.json');
    final manifest = await _readJsonObject(manifestPath);
    if (manifest.isEmpty) {
      _fail('暂无生成历史可删除。');
      return;
    }
    manifest['generation_history'] = <Map<String, dynamic>>[];
    manifest['history_cleared_at'] = DateTime.now().toUtc().toIso8601String();
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(manifest),
      encoding: utf8,
    );
    state = state.copyWith(
      documentGenerationHistoryCount: 0,
      lastMessage: '文档生成历史已清空；正文和导出产物已保留。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<void> deleteLatestDocumentGenerationHistory() async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final manifestPath =
        _join(workspace.path, 'doc', 'generation_manifest.json');
    final manifest = await _readJsonObject(manifestPath);
    final history =
        _listOfMaps(manifest['generation_history']).toList(growable: true);
    if (history.isEmpty) {
      _fail('暂无生成历史可删除。');
      return;
    }
    final deleted = history.removeLast();
    manifest['generation_history'] = history;
    manifest['latest_history_deleted_at'] =
        DateTime.now().toUtc().toIso8601String();
    manifest['latest_history_deleted_event'] =
        (deleted['event'] ?? '').toString();
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(manifest),
      encoding: utf8,
    );
    state = state.copyWith(
      documentGenerationHistoryCount: history.length,
      lastMessage: '最近一条文档生成历史已删除；正文和导出产物已保留。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<String> registerDocumentTemplateLibrary({
    bool includeTestTemplate = false,
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final templateRoot =
        Directory(_joinNested(workspace.path, 'doc/templates'));
    final entriesRoot = Directory(_join(templateRoot.path, 'entries'));
    await entriesRoot.create(recursive: true);
    final createdAt = DateTime.now().toUtc().toIso8601String();
    final templates = _documentTemplateRegistryEntries(
      includeTestTemplate: includeTestTemplate,
    );
    final entryRecords = <Map<String, Object?>>[];
    for (final template in templates) {
      final templateId = template['template_id']!.toString();
      final entryPath = _join(entriesRoot.path, '$templateId.json');
      final entry = {
        'schema_version': 'prd_v3_document_template_registry_entry.v1',
        ...template,
        'entry_path': entryPath,
        'created_at': createdAt,
        'source_module': 'document_generation',
        'secret_plaintext_written': false,
      };
      await _writeJsonFile(entryPath, entry);
      entryRecords.add({
        ...entry,
        'entry_path': entryPath,
      });
    }
    final manifestPath =
        _join(templateRoot.path, 'document_template_registry_manifest.json');
    final validationPath = _join(
        templateRoot.path, 'document_template_registry_validation_report.json');
    final auditPath =
        _join(templateRoot.path, 'document_template_registry_audit.jsonl');
    final manifest = {
      'schema_version': 'prd_v3_document_template_registry.v1',
      'status': 'pass',
      'workspace': workspace.path,
      'template_count': entryRecords.length,
      'template_ids': entryRecords
          .map((entry) => entry['template_id'].toString())
          .toList(growable: false),
      'templates': entryRecords,
      'manifest_path': manifestPath,
      'validation_report_path': validationPath,
      'audit_log_path': auditPath,
      'artifact_lifecycle': {
        'open_supported': true,
        'export_supported': true,
        'delete_supported_for_test_marked_entries_only': true,
        'restart_recovery_supported': true,
      },
      'created_at': createdAt,
      'secret_plaintext_written': false,
    };
    await _writeJsonFile(manifestPath, manifest);
    final missingEntries = <String>[
      for (final entry in entryRecords)
        if (!await File(entry['entry_path'].toString()).exists())
          entry['template_id'].toString(),
    ];
    await _writeJsonFile(validationPath, {
      'schema_version': 'prd_v3_document_template_registry_validation.v1',
      'status': missingEntries.isEmpty ? 'pass' : 'blocked',
      'manifest_path': manifestPath,
      'entry_count': entryRecords.length,
      'missing_entries': missingEntries,
      'has_builtin_templates': entryRecords.any((entry) =>
          entry['template_id'] == 'industry_analysis_report_template'),
      'has_output_formats': entryRecords
          .every((entry) => _listOfStrings(entry['output_formats']).isNotEmpty),
      'has_required_variables': entryRecords
          .every((entry) => _listOfStrings(entry['variables']).isNotEmpty),
      'test_marked_entries': entryRecords
          .where((entry) => entry['test_marker'] == true)
          .map((entry) => entry['template_id'].toString())
          .toList(growable: false),
      'secret_plaintext_written': false,
      'validated_at': createdAt,
    });
    await File(auditPath).parent.create(recursive: true);
    await File(auditPath).writeAsString(
      '${jsonEncode({
            'schema_version':
                'prd_v3_document_template_registry_audit_event.v1',
            'event_type': 'document_template_registry_created',
            'template_count': entryRecords.length,
            'manifest_path': manifestPath,
            'validation_report_path': validationPath,
            'created_at': createdAt,
            'secret_plaintext_written': false,
          })}\n',
      mode: FileMode.append,
      encoding: utf8,
    );
    await _appendOrchestrationPlanRecord(
      layer: 'document',
      action: 'register_document_template_library',
      artifact: manifestPath,
      status: missingEntries.isEmpty ? 'completed' : 'blocked',
      resources: {
        'template_count': entryRecords.length,
        'validation_report_path': validationPath,
        'audit_log_path': auditPath,
      },
    );
    await _appendEventLedgerRecord(
      eventType: 'document_template_registry_created',
      module: 'document_generation',
      action: 'register_document_template_library',
      status: missingEntries.isEmpty ? 'completed' : 'blocked',
      targetId: 'document_template_registry',
      targetName: 'Document Template Registry',
      artifactPath: manifestPath,
      source: 'document_template_registry',
      metadata: {
        'template_count': entryRecords.length,
        'validation_report_path': validationPath,
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'document_template_registry_manifest',
      artifactType: 'document_template_registry',
      title: 'Document Template Registry',
      sourceModule: 'document_generation',
      sourceId: 'document_template_registry',
      filePath: manifestPath,
      status: missingEntries.isEmpty ? 'completed' : 'blocked',
      metadata: {
        'validation_report_path': validationPath,
        'audit_log_path': auditPath,
        'template_count': entryRecords.length,
      },
    );
    for (final entry
        in entryRecords.where((row) => row['test_marker'] == true)) {
      await _upsertArtifactRecord(
        artifactId: entry['template_id'].toString(),
        artifactType: 'document_template_registry_entry',
        title: entry['title'].toString(),
        sourceModule: 'document_generation',
        sourceId: 'document_template_registry',
        filePath: entry['entry_path'].toString(),
        status: 'completed',
        metadata: {
          'test_marker': true,
          'registry_manifest_path': manifestPath,
        },
      );
    }
    state = state.copyWith(
      lastMessage: '文档模板注册表已写入并完成校验。',
      lastError: '',
    );
    await _loadExistingArtifacts();
    notifyListeners();
    return manifestPath;
  }

  Future<String> readDocumentTemplateRegistryPreview({
    int maxCharacters = 6000,
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final manifestPath = _joinNested(workspace.path,
        'doc/templates/document_template_registry_manifest.json');
    final file = File(manifestPath);
    if (!await file.exists()) {
      _fail('文档模板注册表不存在，请先创建模板注册表。');
      return '';
    }
    final text = await file.readAsString(encoding: utf8);
    state = state.copyWith(
      lastMessage: '文档模板注册表已打开。',
      lastError: '',
    );
    notifyListeners();
    if (text.length <= maxCharacters) {
      return text;
    }
    return '${text.substring(0, maxCharacters)}\n\n... 预览已截断，完整内容请打开注册表文件查看。';
  }

