  Future<void> deleteTestDocumentTemplateRegistryEntry() async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final manifestPath = _joinNested(workspace.path,
        'doc/templates/document_template_registry_manifest.json');
    final manifest = await _readJsonObject(manifestPath);
    final entries = _listOfMaps(manifest['templates']).toList(growable: true);
    final testEntries =
        entries.where((entry) => entry['test_marker'] == true).toList();
    if (testEntries.isEmpty) {
      _fail('没有带 test 标记的文档模板注册项可删除。');
      return;
    }
    final deleted = testEntries.first;
    final deletedId = deleted['template_id'].toString();
    final deletedPath = deleted['entry_path'].toString();
    if (!deletedId.startsWith('test_')) {
      _fail('拒绝删除未带 test 前缀的模板注册项。');
      return;
    }
    final workspacePath = workspace.absolute.path;
    if (deletedPath.isEmpty ||
        !_isInsideDirectory(File(deletedPath).absolute.path, workspacePath)) {
      _fail('拒绝删除工作区外的模板注册项。');
      return;
    }
    if (await File(deletedPath).exists()) {
      await File(deletedPath).delete();
    }
    final remaining = entries
        .where((entry) => entry['template_id'].toString() != deletedId)
        .toList(growable: false);
    manifest['templates'] = remaining;
    manifest['template_count'] = remaining.length;
    manifest['template_ids'] = remaining
        .map((entry) => entry['template_id'].toString())
        .toList(growable: false);
    manifest['last_deleted_test_template_id'] = deletedId;
    manifest['last_deleted_test_template_at'] =
        DateTime.now().toUtc().toIso8601String();
    await _writeJsonFile(manifestPath, manifest);
    final auditPath = _joinNested(
        workspace.path, 'doc/templates/document_template_registry_audit.jsonl');
    await File(auditPath).parent.create(recursive: true);
    await File(auditPath).writeAsString(
      '${jsonEncode({
            'schema_version':
                'prd_v3_document_template_registry_audit_event.v1',
            'event_type': 'document_template_registry_test_entry_deleted',
            'template_id': deletedId,
            'entry_path': deletedPath,
            'created_at': DateTime.now().toUtc().toIso8601String(),
            'secret_plaintext_written': false,
          })}\n',
      mode: FileMode.append,
      encoding: utf8,
    );
    await _appendEventLedgerRecord(
      eventType: 'delete_artifact',
      module: 'document_generation',
      action: 'delete_test_document_template_registry_entry',
      status: 'completed',
      targetId: deletedId,
      targetName: 'Test Document Template Registry Entry',
      artifactPath: deletedPath,
      source: 'document_template_registry',
      metadata: {
        'test_marker': true,
        'registry_manifest_path': manifestPath,
      },
    );
    await _markArtifactRecordDeleted(
      artifactId: deletedId,
      status: 'deleted',
      metadata: {
        'test_marker': true,
        'deleted_entry_path': deletedPath,
        'registry_manifest_path': manifestPath,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '测试文档模板注册项已删除，内置模板注册表已保留。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<String> readLatestDocumentGenerationHistoryMarkdown({
    int maxCharacters = 6000,
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final manifest = await _readJsonObject(
        _join(workspace.path, 'doc', 'generation_manifest.json'));
    final history = _listOfMaps(manifest['generation_history']);
    if (history.isEmpty) {
      _fail('暂无可重新打开的文档生成历史。');
      return '';
    }
    final outputPath = (history.last['history_markdown'] ??
            history.last['output_markdown'] ??
            '')
        .toString();
    if (outputPath.trim().isEmpty) {
      _fail('最近一条文档生成历史没有可打开的 Markdown 产物。');
      return '';
    }
    final workspacePath = workspace.absolute.path;
    final file = File(outputPath).absolute;
    if (!_isInsideDirectory(file.path, workspacePath)) {
      _fail('无法重新打开：历史产物不在当前工作区内。');
      return '';
    }
    if (_extension(file.path).toLowerCase() != '.md') {
      _fail('无法重新打开：当前只支持 Markdown 历史产物。');
      return '';
    }
    if (!await file.exists()) {
      _fail('无法重新打开：历史 Markdown 文件不存在。');
      return '';
    }
    final text = await file.readAsString(encoding: utf8);
    state = state.copyWith(
      lastMessage: '最近一条文档生成历史已重新打开。',
      lastError: '',
    );
    notifyListeners();
    if (text.length <= maxCharacters) {
      return text;
    }
    return '${text.substring(0, maxCharacters)}\n\n... 预览已截断，完整内容请复制路径后在本地查看。';
  }

  Future<String> saveEditedDocument(String markdown) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final docDir = Directory(_join(workspace.path, 'doc'));
    final generated = File(_join(docDir.path, 'generated.md'));
    final notes = File(_join(docDir.path, 'reading_notes.md'));
    if (!await generated.exists() && !await notes.exists()) {
      _fail('请先生成正文，再保存编辑稿。');
      return '';
    }
    final trimmed = markdown.trim();
    if (trimmed.isEmpty) {
      _fail('编辑正文不能为空。');
      return '';
    }
    state = state.copyWith(
      running: true,
      lastMessage: '正在保存编辑稿...',
      lastError: '',
    );
    notifyListeners();
    await docDir.create(recursive: true);
    final edited = File(_join(docDir.path, 'edited_document.md'));
    await edited.writeAsString(markdown, encoding: utf8);
    final source = await notes.exists() ? notes.path : generated.path;
    final manifestPath = _join(docDir.path, 'edit_manifest.json');
    final binding = await _documentGenerationBinding(workspace);
    final payload = {
      'schema_version': 'prd_v2_document_edit.v1',
      'status': 'pass',
      'workspace': workspace.path,
      ...binding.toJson(),
      'source_document': source,
      'edited_output_markdown': edited.path,
      'generation_manifest': _join(docDir.path, 'generation_manifest.json'),
      'generation_config': await _latestDocumentGenerationConfig(workspace),
      'size_bytes': await edited.length(),
      'saved_at': DateTime.now().toUtc().toIso8601String(),
      'secret_plaintext_written': false,
    };
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(payload),
      encoding: utf8,
    );
    state = state.copyWith(
      running: false,
      phase: Rc6RuntimePhase.documentGenerated,
      editedDocumentPath: edited.path,
      editManifestPath: manifestPath,
      lastMessage: '编辑稿已保存。导出将优先使用编辑稿。',
      lastError: '',
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      editedDocumentPath: edited.path,
      editManifestPath: manifestPath,
      lastMessage: '编辑稿已保存。导出将优先使用编辑稿。',
      lastError: '',
    );
    notifyListeners();
    return edited.path;
  }

  Future<void> exportDocumentFormat(String format) async {
    final normalized = format.trim().toLowerCase();
    if (normalized == 'md' || normalized == 'markdown') {
      await exportMarkdownDocument();
      return;
    }
    if (normalized == 'json' || normalized == 'csv') {
      await _exportStructuredDocumentFormat(normalized);
      return;
    }
    if (normalized == 'txt' ||
        const {'docx', 'pdf', 'pptx', 'xlsx'}.contains(normalized)) {
      await _exportLocalDocumentAdapterFormat(normalized);
      return;
    }
    if (normalized == 'xls') {
      await _exportLocalDocumentAdapterFormat('xlsx');
      return;
    }
    _fail('暂不支持该导出格式：$format');
    return;
  }

  Future<void> _exportLocalDocumentAdapterFormat(String format) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final normalized = format.trim().toLowerCase();
    if (!const {'txt', 'docx', 'pdf', 'pptx', 'xlsx'}.contains(normalized)) {
      _fail('暂不支持该导出格式：$format');
      return;
    }
    final docDir = Directory(_join(workspace.path, 'doc'));
    final markdown = await _currentDocumentMarkdown(workspace);
    if (markdown.trim().isEmpty) {
      _fail('请先生成文档，再导出 ${normalized.toUpperCase()}。');
      return;
    }
    state = state.copyWith(
      running: true,
      lastMessage: '正在导出 ${normalized.toUpperCase()} 文件...',
      lastError: '',
    );
    notifyListeners();
    final exportDir = Directory(_join(workspace.path, 'export', normalized));
    await _clearWorkspacePath(exportDir.path);
    await exportDir.create(recursive: true);
    final output = File(_join(exportDir.path, 'generated.$normalized'));
    final structured = normalized == 'xlsx'
        ? await _structuredDocumentExportPayload(workspace)
        : const <String, Object?>{};
    switch (normalized) {
      case 'txt':
        await output.writeAsString(_markdownToPlainText(markdown),
            encoding: utf8);
      case 'docx':
        await _writeDocxFile(output, markdown);
      case 'pdf':
        await _writePdfFile(output, markdown);
      case 'pptx':
        await _writePptxFile(output, markdown);
      case 'xlsx':
        await _writeXlsxFile(output, structured);
    }
    final manifestPath = _join(exportDir.path, 'generated_file_report.json');
    final binding = await _documentGenerationBinding(workspace);
    final manifest = {
      'schema_version': 'prd_v3_builtin_document_export_adapter.v1',
      'status': 'pass',
      'format': normalized,
      'adapter': 'builtin_local_${normalized}_adapter',
      ...binding.toJson(),
      'source_markdown':
          await File(_join(docDir.path, 'edited_document.md')).exists()
              ? _join(docDir.path, 'edited_document.md')
              : await File(_join(docDir.path, 'reading_notes.md')).exists()
                  ? _join(docDir.path, 'reading_notes.md')
                  : _join(docDir.path, 'generated.md'),
      'output': output.path,
      'size_bytes': await output.length(),
      'workspace': workspace.path,
      'generation_manifest': _join(docDir.path, 'generation_manifest.json'),
      'generation_config': await _latestDocumentGenerationConfig(workspace),
      'secret_plaintext_written': false,
      'created_at': DateTime.now().toUtc().toIso8601String(),
    };
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(manifest),
      encoding: utf8,
    );
    await _appendOrchestrationPlanRecord(
      layer: 'document',
      action: 'export_document',
      artifact: manifestPath,
      status: 'completed',
      resources: {
        'format': normalized,
        'adapter': 'builtin_local_${normalized}_adapter',
        'output': output.path,
      },
    );
    await _appendEventLedgerRecord(
      eventType: 'export_document',
      module: 'document_generation',
      action: 'export_document_$normalized',
      status: 'completed',
      targetId: 'document_export_$normalized',
      targetName: '${normalized.toUpperCase()} 文档导出',
      artifactPath: output.path,
      source: 'document_generation',
      metadata: {
        'format': normalized,
        'manifest_path': manifestPath,
        'adapter': 'builtin_local_${normalized}_adapter',
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'generated_document_export_$normalized',
      artifactType: 'generated_document',
      title: '${normalized.toUpperCase()} 文档导出',
      sourceModule: 'document_generation',
      sourceId: 'export_document_$normalized',
      filePath: output.path,
      status: 'completed',
      metadata: {
        'format': normalized,
        'manifest_path': manifestPath,
        'adapter': 'builtin_local_${normalized}_adapter',
      },
    );
    state = state.copyWith(
      running: false,
      phase: Rc6RuntimePhase.documentGenerated,
      exportedDocumentPath: output.path,
      exportManifestPath: manifestPath,
      lastMessage: '${normalized.toUpperCase()} 文档已导出。',
      lastError: '',
    );
    await _loadExistingArtifacts();
    notifyListeners();
  }

  Future<void> _exportStructuredDocumentFormat(String format) async {
