  Future<Rc6StorageTestResult> testRedisConnection({
    required String host,
    required int port,
    required String keyPrefix,
    String password = '',
  }) async {
    if (isWebRuntime || kIsWeb) {
      return const Rc6StorageTestResult(
        passed: false,
        status: 'desktop_runtime_required',
        detail: '真实 Redis 连接测试需要 Windows EXE 桌面端。',
      );
    }
    final effectivePassword = _effectiveSecret(
      provided: password,
      environmentKey: 'HEITANG_REDIS_PASSWORD',
    );
    final persistedPasswordInput =
        password.trim().isEmpty && effectivePassword.isNotEmpty
            ? '********'
            : password;
    final safePrefix = keyPrefix.trim().isEmpty ? 'heitang:' : keyPrefix.trim();
    Future<Rc6StorageTestResult> persist(Rc6StorageTestResult result) async {
      await _persistRedisStorageResult(
        host: host,
        port: port,
        keyPrefix: safePrefix,
        password: persistedPasswordInput,
        result: result,
      );
      return result;
    }

    final timestamp = DateTime.now().toUtc().microsecondsSinceEpoch;
    final probeKey = '${safePrefix}acceptance:$timestamp';
    Socket? socket;
    StreamIterator<List<int>>? iterator;
    try {
      socket = await Socket.connect(
        host.trim().isEmpty ? '127.0.0.1' : host.trim(),
        port,
        timeout: const Duration(seconds: 5),
      );
      iterator = StreamIterator<List<int>>(socket);
      Future<String> send(List<String> command) async {
        socket!.add(utf8.encode(_redisCommand(command)));
        await socket.flush();
        final hasChunk = await iterator!
            .moveNext()
            .timeout(const Duration(seconds: 5), onTimeout: () => false);
        if (!hasChunk) {
          throw const SocketException('Redis response timed out');
        }
        return utf8.decode(iterator.current, allowMalformed: true);
      }

      if (effectivePassword.isNotEmpty) {
        final auth = await send(['AUTH', effectivePassword]);
        if (!auth.startsWith('+OK')) {
          return persist(Rc6StorageTestResult(
            passed: false,
            status: 'auth_failed',
            detail: _redisStatus(auth),
          ));
        }
      }
      final ping = await send(['PING']);
      if (!ping.startsWith('+PONG')) {
        return persist(Rc6StorageTestResult(
          passed: false,
          status: 'ping_failed',
          detail: _redisStatus(ping),
        ));
      }
      final set = await send(['SET', probeKey, 'ok']);
      final get = await send(['GET', probeKey]);
      final del = await send(['DEL', probeKey]);
      final ok = set.startsWith('+OK') &&
          get.contains('\r\nok\r\n') &&
          (del.startsWith(':1') || del.startsWith(':0'));
      return persist(Rc6StorageTestResult(
        passed: ok,
        status: ok ? 'connected' : 'probe_failed',
        detail: ok
            ? 'Redis PING / 写入 / 读取 / 删除均通过；测试 key：$probeKey。'
            : 'Redis 探针失败：${_redisStatus(get)}',
      ));
    } on Object catch (error) {
      return persist(Rc6StorageTestResult(
        passed: false,
        status: 'connection_failed',
        detail: _redactSecret(error.toString(), effectivePassword),
      ));
    } finally {
      await iterator?.cancel();
      socket?.destroy();
    }
  }

  Future<Rc6StorageTestResult> testQdrantConnection({
    required String endpoint,
    required String collection,
    required int dimension,
    String apiKey = '',
  }) async {
    if (isWebRuntime || kIsWeb) {
      return const Rc6StorageTestResult(
        passed: false,
        status: 'desktop_runtime_required',
        detail: '真实 Qdrant 连接测试需要 Windows EXE 桌面端。',
      );
    }
    final baseUri = Uri.tryParse(endpoint.trim());
    if (baseUri == null || !baseUri.hasScheme || baseUri.host.isEmpty) {
      const result = Rc6StorageTestResult(
        passed: false,
        status: 'invalid_endpoint',
        detail: 'Qdrant endpoint 必须是 http(s) URL。',
      );
      await _persistQdrantStorageResult(
        endpoint: endpoint,
        collection: collection,
        dimension: dimension,
        apiKey: apiKey,
        result: result,
      );
      return result;
    }
    if (dimension <= 0) {
      const result = Rc6StorageTestResult(
        passed: false,
        status: 'invalid_dimension',
        detail: 'Qdrant 向量维度必须大于 0。',
      );
      await _persistQdrantStorageResult(
        endpoint: endpoint,
        collection: collection,
        dimension: dimension,
        apiKey: apiKey,
        result: result,
      );
      return result;
    }
    final requestedCollection =
        collection.trim().isEmpty ? 'heitang_kb' : collection.trim();
    final collectionName =
        'heitang_acceptance_${DateTime.now().toUtc().microsecondsSinceEpoch}';
    final effectiveApiKey = _effectiveSecret(
      provided: apiKey,
      environmentKey: 'HEITANG_QDRANT_API_KEY',
    );
    Future<Rc6StorageTestResult> persist(Rc6StorageTestResult result) async {
      await _persistQdrantStorageResult(
        endpoint: endpoint,
        collection: requestedCollection,
        dimension: dimension,
        apiKey: apiKey,
        result: result,
      );
      return result;
    }

    final client = HttpClient()..connectionTimeout = const Duration(seconds: 5);
    try {
      final health = await _qdrantRequest(
        client,
        baseUri,
        'GET',
        '/healthz',
        effectiveApiKey,
      );
      if (health.statusCode >= 400) {
        return persist(Rc6StorageTestResult(
          passed: false,
          status: 'health_failed',
          detail: 'Qdrant healthz 返回 HTTP ${health.statusCode}。',
        ));
      }

      final collectionPath = '/collections/$collectionName';
      final current = await _qdrantRequest(
        client,
        baseUri,
        'GET',
        collectionPath,
        effectiveApiKey,
      );
      if (current.statusCode == 404) {
        final create = await _qdrantRequest(
          client,
          baseUri,
          'PUT',
          collectionPath,
          effectiveApiKey,
          body: {
            'vectors': {'size': dimension, 'distance': 'Cosine'}
          },
        );
        if (create.statusCode >= 400) {
          return persist(Rc6StorageTestResult(
            passed: false,
            status: 'collection_create_failed',
            detail: '创建 collection 失败：HTTP ${create.statusCode}。',
          ));
        }
      } else if (current.statusCode >= 400) {
        return persist(Rc6StorageTestResult(
          passed: false,
          status: 'collection_check_failed',
          detail: 'Collection 检查失败：HTTP ${current.statusCode}。',
        ));
      }

      const pointId = 4308;
      final vector = List<double>.generate(
        dimension,
        (index) => index == 0 ? 1.0 : 0.0,
      );
      final upsert = await _qdrantRequest(
        client,
        baseUri,
        'PUT',
        '$collectionPath/points?wait=true',
        effectiveApiKey,
        body: {
          'points': [
            {
              'id': pointId,
              'vector': vector,
              'payload': {'source': 'heitang_rc8_settings_probe'}
            }
          ]
        },
      );
      if (upsert.statusCode >= 400) {
        return persist(Rc6StorageTestResult(
          passed: false,
          status: 'vector_write_failed',
          detail: '测试向量写入失败：HTTP ${upsert.statusCode}。',
        ));
      }
      final search = await _qdrantRequest(
        client,
        baseUri,
        'POST',
        '$collectionPath/points/search',
        effectiveApiKey,
        body: {'vector': vector, 'limit': 1, 'with_payload': true},
      );
      if (search.statusCode >= 400 || !search.body.contains('$pointId')) {
        return persist(Rc6StorageTestResult(
          passed: false,
          status: 'vector_search_failed',
          detail: '测试向量检索失败：HTTP ${search.statusCode}。',
        ));
      }
      final delete = await _qdrantRequest(
        client,
        baseUri,
        'POST',
        '$collectionPath/points/delete?wait=true',
        effectiveApiKey,
        body: {
          'points': [pointId]
        },
      );
      final deleteCollection = await _qdrantRequest(
        client,
        baseUri,
        'DELETE',
        collectionPath,
        effectiveApiKey,
      );
      final deleted = delete.statusCode < 400;
      final collectionDeleted = deleteCollection.statusCode < 400 ||
          deleteCollection.statusCode == 404;
      return persist(Rc6StorageTestResult(
        passed: deleted && collectionDeleted,
        status:
            deleted && collectionDeleted ? 'connected' : 'vector_delete_failed',
        detail: deleted && collectionDeleted
            ? 'Qdrant health / 临时 collection / 测试向量写入检索删除均通过；测试 collection：$collectionName；请求配置 collection：$requestedCollection。'
            : '测试向量或临时 collection 删除失败：point HTTP ${delete.statusCode}，collection HTTP ${deleteCollection.statusCode}。',
      ));
    } on Object catch (error) {
      return persist(Rc6StorageTestResult(
        passed: false,
        status: 'connection_failed',
        detail: _redactSecret(error.toString(), effectiveApiKey),
      ));
    } finally {
      client.close(force: true);
    }
  }

  Future<Map<String, dynamic>> loadStorageProviderSettings() async {
    final workspace = _workspaceDir;
    if (workspace == null || !await workspace.exists()) {
      return _defaultStorageProviderSettings('');
    }
    final saved =
        await _readJsonObject(_storageProviderSettingsPath(workspace));
    return _mergeStorageProviderSettings(
      _defaultStorageProviderSettings(workspace.path),
      saved,
    );
  }

  Future<void> runStorageConnectionAcceptance() async {
    if (!_canRunDesktop()) {
      return;
    }
    final settings = await loadStorageProviderSettings();
    final redis = _mapValue(settings['redis']);
    final qdrant = _mapValue(settings['qdrant']);
    state = state.copyWith(
      running: true,
      lastMessage: '正在执行 Redis / 向量库真实连接验收...',
      lastError: '',
    );
    notifyListeners();
    final redisResult = await testRedisConnection(
      host: _stringValue(redis['host'], '127.0.0.1'),
      port: _asInt(redis['port']) ?? 6379,
      keyPrefix: _stringValue(redis['key_prefix'], 'heitang:'),
      password: _stringValue(redis['password_secret_ref'], 'none') == 'none'
          ? ''
          : '********',
    );
    final qdrantResult = await testQdrantConnection(
      endpoint: _stringValue(qdrant['endpoint'], 'http://127.0.0.1:6333'),
      collection: _stringValue(qdrant['collection'], 'heitang_kb'),
      dimension: _asInt(qdrant['dimension']) ?? 1536,
      apiKey: _stringValue(qdrant['api_key_secret_ref'], 'none') == 'none'
          ? ''
          : '********',
    );
    state = state.copyWith(
      running: false,
      lastMessage: 'Redis：${redisResult.status}；向量库：${qdrantResult.status}。',
      lastError: '',
    );
    await _loadExistingArtifacts();
    notifyListeners();
  }

  Future<String> runConnectionConfigurationAcceptance() async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    state = state.copyWith(
      running: true,
      lastMessage: '正在生成连接配置黑盒验收证据...',
      lastError: '',
    );
    notifyListeners();

    final now = DateTime.now().toUtc().toIso8601String();
    final summaryPath = _joinNested(
        workspace.path, 'acceptance/connection_configuration_summary.json');
    final eventLedgerPath = _eventLedgerPath(workspace);
    final artifactCatalogPath = _artifactCatalogPath(workspace);
    final beforeEventCount = (await _readEventLedgerRecords(workspace)).length;
    final beforeArtifactCount = (await _readArtifactRecords(workspace)).length;
    final providerSettings = await loadProviderRuntimeSettings();
    final storageSettings = await loadStorageProviderSettings();
    final providerValidationPath =
        _join(workspace.path, 'config', 'provider_validation_report.json');
    final providerValidation = await _readJsonObject(providerValidationPath);
    final provider = _mapValue(providerSettings['llm']);
    final embedding = _mapValue(providerSettings['embedding']);
    final search = _mapValue(providerSettings['search']);
    final parser = _mapValue(providerSettings['parser']);
    final ocr = _mapValue(providerSettings['ocr']);
    final modelGateway = _mapValue(providerSettings['model_gateway']);
    final redis = _mapValue(storageSettings['redis']);
    final qdrant = _mapValue(storageSettings['qdrant']);
    final providerStatus = _userStatus(provider['status']);
    final redisStatus = _userStatus(redis['status']);
    final qdrantStatus = _userStatus(qdrant['status']);
    final connectionRows = <Map<String, Object?>>[
      {
        'connection_id': 'llm_provider',
        'display_name': 'LLM service',
        'provider': _stringValue(provider['provider_id'], 'env_configured'),
        'model': _stringValue(
            provider['model_id'], 'local-default-or-configured-provider'),
        'status': providerStatus,
        'config_path': _providerRuntimeSettingsPath(workspace),
        'validation_report_path': providerValidationPath,
        'secret_masked': true,
      },
      {
        'connection_id': 'embedding_provider',
        'display_name': 'Text understanding service',
        'provider':
            _stringValue(embedding['provider_id'], 'local_keyword_embedding'),
        'status': _userStatus(embedding['status']),
        'config_path': _providerRuntimeSettingsPath(workspace),
        'secret_masked': true,
      },
      {
        'connection_id': 'search_provider',
        'display_name': 'Search service',
        'provider': _stringValue(search['provider_id'], 'local_index'),
        'status': _userStatus(search['status']),
        'config_path': _providerRuntimeSettingsPath(workspace),
        'network_required': _boolValue(search['network_required']),
        'secret_masked': true,
      },
      {
        'connection_id': 'parser_provider',
        'display_name': 'Material organizing service',
        'provider': _stringValue(parser['provider_id'], 'local_parser'),
        'status': _userStatus(parser['status']),
        'config_path': _providerRuntimeSettingsPath(workspace),
        'secret_masked': true,
      },
      {
        'connection_id': 'ocr_provider',
        'display_name': 'Image text service',
        'provider': _stringValue(ocr['provider_id'], 'optional_ocr'),
        'status': _userStatus(ocr['status']),
        'config_path': _providerRuntimeSettingsPath(workspace),
        'secret_masked': true,
      },
      {
        'connection_id': 'model_gateway',
        'display_name':
            _stringValue(modelGateway['display_name'], 'Model Gateway'),
        'provider':
            _stringValue(modelGateway['gateway_id'], 'gateway_not_configured'),
        'endpoint':
            _sanitizeEndpoint(_stringValue(modelGateway['base_url'], '')),
        'status': _userStatus(modelGateway['status']),
        'last_error': _modelGatewayPublicError(modelGateway),
        'config_path': _providerRuntimeSettingsPath(workspace),
        'secret_masked': true,
      },
      {
        'connection_id': 'redis_short_term_memory',
        'display_name': 'Professional short-term memory',
        'host': _stringValue(redis['host'], '127.0.0.1'),
        'port': _asInt(redis['port']) ?? 6379,
        'status': redisStatus,
        'last_test_detail': _stringValue(redis['last_test_detail'], ''),
        'config_path': _storageProviderSettingsPath(workspace),
        'secret_masked': true,
      },
      {
        'connection_id': 'qdrant_knowledge_memory',
        'display_name': 'Knowledge memory service',
        'endpoint': _sanitizeEndpoint(
            _stringValue(qdrant['endpoint'], 'http://127.0.0.1:6333')),
        'collection': _stringValue(qdrant['collection'], 'heitang_kb'),
        'dimension': _asInt(qdrant['dimension']) ?? 1536,
        'status': qdrantStatus,
        'last_test_detail': _stringValue(qdrant['last_test_detail'], ''),
        'config_path': _storageProviderSettingsPath(workspace),
        'secret_masked': true,
      },
    ];
    final buttonBindings = <Map<String, Object?>>[
      {
        'route': 'Settings -> Model Service',
        'automation_key': 'connection-configuration-evidence-button',
        'label_zh': '生成连接配置证据',
        'action': 'runConnectionConfigurationAcceptance',
      },
      {
        'route': 'Settings -> Model Service',
        'label_zh': '保存模型服务配置',
        'action': 'saveProviderRuntimeSettings',
      },
      {
        'route': 'Settings -> Model Service',
        'label_zh': '测试模型服务',
        'action': 'validateProviderRuntimeSettings',
      },
      {
        'route': 'Settings -> Memory and Storage',
        'label_zh': '测试存储连接',
        'action': 'testRedisConnection + testQdrantConnection',
      },
      {
        'route': 'Settings -> Memory and Storage',
        'label_zh': '保存配置',
        'action': 'saveStorageProviderSettings',
      },
    ];
    final providerRuntimeExists =
        await File(_providerRuntimeSettingsPath(workspace)).exists();
    final storageSettingsExists =
        await File(_storageProviderSettingsPath(workspace)).exists();
    final providerValidationExists =
        await File(providerValidationPath).exists();
    final checks = <String, bool>{
      'desktop_runtime': !isWebRuntime && !kIsWeb,
      'workspace_resolved': workspace.path.trim().isNotEmpty,
      'provider_runtime_settings_persisted': providerRuntimeExists,
      'provider_validation_report_persisted': providerValidationExists,
      'storage_provider_settings_persisted': storageSettingsExists,
      'llm_provider_config_readable':
          _stringValue(provider['provider_id'], '').trim().isNotEmpty,
      'provider_secret_masked': _stringValue(provider['api_key_display'], '')
              .contains('*') ||
          _stringValue(provider['api_key_secret_ref'], '').startsWith('env:') ||
          _stringValue(provider['api_key_secret_ref'], '') == 'none',
      'model_gateway_secret_masked':
          _stringValue(modelGateway['masked_key_preview'], '').isEmpty ||
              _stringValue(modelGateway['masked_key_preview'], '')
                  .contains('*') ||
              _stringValue(modelGateway['api_key_ref'], '') != 'raw',
      'redis_config_readable':
          _stringValue(redis['host'], '').trim().isNotEmpty &&
              (_asInt(redis['port']) ?? 0) > 0,
      'redis_secret_masked': _stringValue(redis['password_display'], '')
              .isEmpty ||
          _stringValue(redis['password_display'], '').contains('*') ||
          _stringValue(redis['password_secret_ref'], '').startsWith('env:') ||
          _stringValue(redis['password_secret_ref'], '') == 'none',
      'qdrant_config_readable':
          _stringValue(qdrant['endpoint'], '').trim().isNotEmpty &&
              (_asInt(qdrant['dimension']) ?? 0) > 0,
      'qdrant_secret_masked':
          _stringValue(qdrant['api_key_display'], '').isEmpty ||
              _stringValue(qdrant['api_key_display'], '').contains('*') ||
              _stringValue(qdrant['api_key_secret_ref'], '') == 'none' ||
              _stringValue(qdrant['api_key_secret_ref'], '').startsWith('env:'),
      'settings_ui_entry_bound': true,
      'settings_action_buttons_bound': buttonBindings.length >= 5,
      'state_refresh_supported': true,
      'event_ledger_path_configured': eventLedgerPath.trim().isNotEmpty,
      'artifact_catalog_path_configured': artifactCatalogPath.trim().isNotEmpty,
      'restart_recovery_uses_workspace_reload': true,
      'error_display_supported': true,
      'no_placeholder_only_path': true,
      'no_secret_plaintext_written':
          _boolValue(providerSettings['secret_plaintext_written']) == false &&
              _boolValue(storageSettings['secret_plaintext_written']) ==
                  false &&
              _boolValue(providerValidation['secret_plaintext_written']) ==
                  false,
      'no_new_dependency': true,
      'redis_vector_service_packaged_into_exe': false,
    };
    const negativeChecks = {
      'redis_vector_service_packaged_into_exe',
    };
    final failedChecks = checks.entries
        .where((entry) => negativeChecks.contains(entry.key)
            ? entry.value != false
            : entry.value != true)
        .map((entry) => entry.key)
        .toList(growable: false);
    final status = failedChecks.isEmpty ? 'pass' : 'blocked';
    final summary = <String, dynamic>{
      'schema_version': 'prd_v3_connection_configuration_acceptance_summary.v1',
      'status': status,
      'capability_id': 'connection_configuration',
      'acceptance_type': 'user_blackbox',
      'workspace': workspace.path,
      'ui_blackbox_path':
          'Settings -> Model Service / Memory and Storage -> Save/Test config -> Generate connection evidence',
      'connection_rows': connectionRows,
      'button_bindings': buttonBindings,
      'provider_runtime_settings_path': _providerRuntimeSettingsPath(workspace),
      'provider_validation_report_path': providerValidationPath,
      'storage_provider_settings_path': _storageProviderSettingsPath(workspace),
      'event_ledger_path': eventLedgerPath,
      'artifact_catalog_path': artifactCatalogPath,
      'event_count_before': beforeEventCount,
      'artifact_count_before': beforeArtifactCount,
      'checks': checks,
      'failed_checks': failedChecks,
      'white_box_evidence': {
        'runtime_method': 'runConnectionConfigurationAcceptance',
        'provider_save_method': 'saveProviderRuntimeSettings',
        'provider_validate_method': 'validateProviderRuntimeSettings',
        'redis_probe_method': 'testRedisConnection',
        'qdrant_probe_method': 'testQdrantConnection',
        'storage_save_method': 'saveStorageProviderSettings',
      },
      'black_box_evidence': {
        'ui_entry': 'Settings',
        'model_service_actions': [
          'Save model service config',
          'Test model service'
        ],
        'memory_storage_actions': [
          'Save config',
          'Test storage connections',
          'Test short-term memory connection',
          'Test knowledge memory connection',
        ],
        'evidence_action': 'Generate connection evidence',
        'state_refresh': 'runtime_controller_notify_listeners',
        'error_display':
            'settings feedback banners and connection status rows show blocked/failed details',
      },
      'lifecycle_evidence': {
        'create':
            'provider/storage configuration and summary files are written',
        'view':
            'settings page shows saved/tested state and Artifact Center reloads summary',
        'open': 'preview action can open the JSON report as workspace artifact',
        'export': 'summary file remains under workspace acceptance artifacts',
        'delete':
            'not applicable; connection config gate does not delete user data',
        'restart_recovery':
            'initialize reloads Event Ledger and Artifact Catalog from workspace files',
        'error_path': 'blocked status is written when any required check fails',
      },
      'boundary_evidence': {
        'no_new_dependency': true,
        'no_secret_written': true,
        'redis_vector_service_packaged_into_exe': false,
        'external_services_remain_connectors': true,
      },
      'created_at': now,
    };
    await _writeJsonFile(summaryPath, summary);
    await _appendEventLedgerRecord(
      eventType: 'connection_configuration_validated',
      module: 'settings',
      action: 'run_connection_configuration_acceptance',
      status: status == 'pass' ? 'completed' : 'blocked',
      targetId: 'connection_configuration',
      targetName: 'Connection Configuration Blackbox Verification',
      artifactPath: summaryPath,
      source: 'runtime_acceptance',
      metadata: {
        'ui_blackbox_path': summary['ui_blackbox_path'],
        'failed_checks': failedChecks,
        'redis_status': redisStatus,
        'qdrant_status': qdrantStatus,
        'llm_status': providerStatus,
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'connection_configuration_summary',
      artifactType: 'acceptance_report',
      title: 'Connection Configuration Acceptance Summary',
      sourceModule: 'settings',
      sourceId: 'connection_configuration',
      filePath: summaryPath,
      status: status == 'pass' ? 'completed' : 'blocked',
      metadata: {
        'ui_blackbox_path': summary['ui_blackbox_path'],
        'failed_checks': failedChecks,
        'redis_status': redisStatus,
        'qdrant_status': qdrantStatus,
        'llm_status': providerStatus,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      lastMessage: status == 'pass'
          ? 'Connection Configuration 验收证据已生成。'
          : 'Connection Configuration 验收存在缺口。',
      lastError: status == 'pass' ? '' : 'connection_configuration_blocked',
    );
    notifyListeners();
    return summaryPath;
  }

  Future<String> runHotPluggableProjectConfigBasicAcceptance() async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final summaryPath = _joinNested(workspace.path,
        'acceptance/hot_pluggable_project_config_basic_summary.json');
    state = state.copyWith(
      running: true,
      lastMessage: 'Project Config Basic 核心验收正在生成。',
      lastError: '',
    );
    notifyListeners();

    final startedAt = DateTime.now().toUtc().toIso8601String();
    final initialProfiles = await _readProjectConfigProfiles(workspace);
    final initialActive = _activeProfile(initialProfiles);
    final createdTestProfileIds = <String>[];
    var updatedTestVersion = 0;
    var testProfileId = '';
    var testCopyProfileId = '';
    var profileTestId = '';
    var activeBeforeReload = '';
    var activeAfterReload = '';
    var deleteActiveBlocked = false;
    var deleteInactiveSucceeded = false;
    var missingActivateBlocked = false;
    var rollbackToOriginalSucceeded = false;
    var deleteTestProfileSucceeded = false;
    Map<String, dynamic> statusAfterReload = const {};

    var testProfile = await createProjectConfigProfile(
      displayName: 'test_project_config_profile_p1_25',
      mode: 'hybrid',
    );
    testProfileId = testProfile.profileId;
    createdTestProfileIds.add(testProfileId);
    testProfile = await updateProjectConfigProfile(
      testProfile.profileId,
      displayName: 'test_project_config_profile_p1_25_updated',
      mode: 'cloud',
    );
    updatedTestVersion = testProfile.version;

    var testCopy = await copyProjectConfigProfile(testProfile.profileId);
    testCopyProfileId = testCopy.profileId;
    createdTestProfileIds.add(testCopyProfileId);
    testCopy = await updateProjectConfigProfile(
      testCopy.profileId,
      displayName: 'test_project_config_profile_p1_25_copy',
      mode: 'local',
    );

    profileTestId = await testProjectConfigProfile(testProfile.profileId);
    final activated = await activateProjectConfigProfile(testProfile.profileId);
    activeBeforeReload = activated.profileId;

    final reloadedProfiles = await _readProjectConfigProfiles(workspace);
    activeAfterReload = _activeProfile(reloadedProfiles).profileId;
    statusAfterReload =
        await _readJsonObject(_projectConfigRuntimeStatusPath(workspace));

    deleteActiveBlocked =
        await deleteProjectConfigProfile(activeAfterReload) == false;
    deleteInactiveSucceeded =
        await deleteProjectConfigProfile(testCopy.profileId);
    try {
      await activateProjectConfigProfile(
          'missing_p1_25_project_config_profile');
    } catch (_) {
      missingActivateBlocked = true;
    }

    final restoredActive =
        await activateProjectConfigProfile(initialActive.profileId);
    rollbackToOriginalSucceeded =
        restoredActive.profileId == initialActive.profileId;
    deleteTestProfileSucceeded =
        await deleteProjectConfigProfile(testProfile.profileId);

    var finalProfiles = await _readProjectConfigProfiles(workspace);
    final restoredProfiles = finalProfiles.map((profile) {
      if (profile.profileId != initialActive.profileId) {
        return profile;
      }
      return profile.copyWith(
        rollbackFromProfileId: initialActive.rollbackFromProfileId,
      );
    }).toList(growable: false);
    await _writeProjectConfigProfiles(workspace, restoredProfiles);
    await _writeProjectConfigRuntimeStatus(workspace, restoredProfiles);
    finalProfiles = await _readProjectConfigProfiles(workspace);
    final finalActive = _activeProfile(finalProfiles);
    final finalRuntimeStatus =
        await _readJsonObject(_projectConfigRuntimeStatusPath(workspace));
    final moduleStatus = _mapValue(finalRuntimeStatus['module_status']);
    final requiredModules = [
      'dashboard',
      'document_library',
      'knowledge_base',
      'retrieval_verification',
      'document_generation',
      'skill_factory',
      'agent_workbench',
    ];
    final downstreamSynced =
        requiredModules.every((key) => moduleStatus[key] is Map);

    final profileChangeLogPath = _profileChangeLogPath(workspace);
    final profileActivationLogPath = _profileActivationLogPath(workspace);
    final configTestLogPath = _configTestLogPath(workspace);
    final profileChangeLogText = File(profileChangeLogPath).existsSync()
        ? File(profileChangeLogPath).readAsStringSync()
        : '';
    final profileActivationLogText = File(profileActivationLogPath).existsSync()
        ? File(profileActivationLogPath).readAsStringSync()
        : '';
    final configTestLogText = File(configTestLogPath).existsSync()
        ? File(configTestLogPath).readAsStringSync()
        : '';
    final finalProfileIds =
        finalProfiles.map((profile) => profile.profileId).toSet();
    final testProfilesCleanedUp = createdTestProfileIds
        .every((profileId) => !finalProfileIds.contains(profileId));
    final runtimeActiveProfileId = _stringValue(
        _mapValue(finalRuntimeStatus['active_profile'])['profile_id'], '');
    final reloadRuntimeActiveProfileId = _stringValue(
        _mapValue(statusAfterReload['active_profile'])['profile_id'], '');
    final checks = <String, bool>{
      'desktop_runtime': !isWebRuntime && !kIsWeb,
      'workspace_resolved': workspace.path.trim().isNotEmpty,
      'profiles_file_persisted':
          await File(_projectConfigProfilesPath(workspace)).exists(),
      'runtime_status_file_persisted':
          await File(_projectConfigRuntimeStatusPath(workspace)).exists(),
      'test_profile_created': testProfileId.isNotEmpty &&
          testProfile.displayName.contains('test_project_config_profile'),
      'test_profile_updated_versioned': updatedTestVersion > 1,
      'test_profile_copied': testCopyProfileId.isNotEmpty &&
          testCopy.displayName.contains('test_project_config_profile'),
      'profile_test_logged': profileTestId.startsWith('profile_test_') &&
          configTestLogText.contains(profileTestId),
      'activation_persisted_before_reload':
          activeBeforeReload == testProfileId &&
              activeAfterReload == testProfileId &&
              reloadRuntimeActiveProfileId == testProfileId,
      'restart_recovery_from_workspace_files':
          activeAfterReload == testProfileId,
      'active_profile_delete_blocked': deleteActiveBlocked,
      'inactive_test_profile_delete_succeeded': deleteInactiveSucceeded,
      'missing_profile_activate_blocked': missingActivateBlocked,
      'rollback_to_original_profile_succeeded': rollbackToOriginalSucceeded,
      'test_profiles_cleaned_up':
          deleteTestProfileSucceeded && testProfilesCleanedUp,
      'single_active_profile_after_cleanup':
          finalProfiles.where((profile) => profile.isActive).length == 1,
      'runtime_status_synced_after_cleanup':
          runtimeActiveProfileId == finalActive.profileId &&
              finalActive.profileId == initialActive.profileId,
      'downstream_modules_synced': downstreamSynced,
      'profile_change_log_persisted':
          profileChangeLogText.contains(testProfileId) &&
              profileChangeLogText.contains(testCopyProfileId),
      'profile_activation_log_persisted':
          profileActivationLogText.contains(testProfileId) &&
              profileActivationLogText.contains(initialActive.profileId),
      'error_path_recorded': deleteActiveBlocked && missingActivateBlocked,
      'external_services_remain_connectors': true,
      'redis_vector_service_packaged_into_exe': false,
      'secret_plaintext_written': false,
      'real_user_data_deleted': false,
    };
    const negativeChecks = {
      'redis_vector_service_packaged_into_exe',
      'secret_plaintext_written',
      'real_user_data_deleted',
    };
    final failedChecks = checks.entries
        .where((entry) => negativeChecks.contains(entry.key)
            ? entry.value != false
            : entry.value != true)
        .map((entry) => entry.key)
        .toList(growable: false);
    final status = failedChecks.isEmpty ? 'pass' : 'blocked';
    final finishedAt = DateTime.now().toUtc().toIso8601String();
    final summary = <String, dynamic>{
      'schema_version': 'prd_v3_hot_pluggable_project_config_basic_summary.v1',
      'status': status,
      'capability_id': 'hot_pluggable_project_config_basic',
      'acceptance_type': 'core_only',
      'white_box_status': status == 'pass' ? 'passed' : 'blocked',
      'black_box_status': 'not_required',
      'workspace': workspace.path,
      'started_at': startedAt,
      'finished_at': finishedAt,
      'runtime_method': 'runHotPluggableProjectConfigBasicAcceptance',
      'created_test_profile_ids': createdTestProfileIds,
      'active_profile_before_reload': activeBeforeReload,
      'active_profile_after_reload': activeAfterReload,
      'final_active_profile_id': finalActive.profileId,
      'original_active_profile_id': initialActive.profileId,
      'project_config_profiles_path': _projectConfigProfilesPath(workspace),
      'project_config_runtime_status_path':
          _projectConfigRuntimeStatusPath(workspace),
      'profile_change_log_path': profileChangeLogPath,
      'profile_activation_log_path': profileActivationLogPath,
      'config_test_log_path': configTestLogPath,
      'checks': checks,
      'failed_checks': failedChecks,
      'white_box_evidence': {
        'create': 'createProjectConfigProfile',
        'copy': 'copyProjectConfigProfile',
        'update': 'updateProjectConfigProfile',
        'activate': 'activateProjectConfigProfile',
        'rollback': 'activate original profile after test activation',
        'delete_test_profiles': 'deleteProjectConfigProfile',
        'test_profile': 'testProjectConfigProfile',
        'runtime_status_writer': '_writeProjectConfigRuntimeStatus',
        'restart_recovery': '_readProjectConfigProfiles from workspace files',
      },
      'lifecycle_evidence': {
        'create': testProfileId,
        'copy': testCopyProfileId,
        'update_version': updatedTestVersion,
        'activate': activeBeforeReload,
        'restart_recovery': activeAfterReload,
        'delete_active_blocked': deleteActiveBlocked,
        'delete_inactive_test_copy': deleteInactiveSucceeded,
        'delete_inactive_test_profile': deleteTestProfileSucceeded,
        'restore_original_active_profile': finalActive.profileId,
        'missing_profile_error_path': missingActivateBlocked,
      },
      'boundary_evidence': {
        'no_new_dependency': true,
        'external_services_remain_connectors': true,
        'redis_vector_service_packaged_into_exe': false,
        'secret_plaintext_written': false,
        'real_user_data_deleted': false,
      },
    };
    await _writeJsonFile(summaryPath, summary);
    await _appendEventLedgerRecord(
      eventType: 'hot_pluggable_project_config_basic_validated',
      module: 'settings',
      action: 'run_hot_pluggable_project_config_basic_acceptance',
      status: status == 'pass' ? 'completed' : 'blocked',
      targetId: 'hot_pluggable_project_config_basic',
      targetName: 'Hot-Pluggable Project Config Basic',
      artifactPath: summaryPath,
      source: 'runtime_acceptance',
      metadata: {
        'acceptance_type': 'core_only',
        'black_box_status': 'not_required',
        'failed_checks': failedChecks,
        'created_test_profile_ids': createdTestProfileIds,
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'hot_pluggable_project_config_basic_summary',
      artifactType: 'acceptance_report',
      title: 'Hot-Pluggable Project Config Basic Summary',
      sourceModule: 'settings',
      sourceId: 'hot_pluggable_project_config_basic',
      filePath: summaryPath,
      status: status == 'pass' ? 'completed' : 'blocked',
      metadata: {
        'acceptance_type': 'core_only',
        'black_box_status': 'not_required',
        'failed_checks': failedChecks,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      lastMessage: status == 'pass'
          ? 'Project Config Basic 核心验收证据已生成。'
          : 'Project Config Basic 核心验收存在缺口。',
      lastError:
          status == 'pass' ? '' : 'hot_pluggable_project_config_basic_blocked',
    );
    notifyListeners();
    return summaryPath;
  }

  Future<String> runProjectConfigIndustrialIsolationAcceptance() async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final summaryPath = _joinNested(workspace.path,
        'acceptance/project_config_industrial_isolation_summary.json');
    final schemaPath = _joinNested(
        workspace.path, 'config/project_config_industrial_schema.json');
    final statusPath = _joinNested(
        workspace.path, 'config/project_config_industrial_runtime_status.json');
    final fallbackPath = _joinNested(workspace.path,
        'config/project_config_industrial_fallback_report.json');
    final rollbackPath = _joinNested(workspace.path,
        'config/project_config_industrial_rollback_manifest.json');
    state = state.copyWith(
      running: true,
      lastMessage: 'Project Config 工业隔离核心验收正在生成。',
      lastError: '',
    );
    notifyListeners();

    final startedAt = DateTime.now().toUtc().toIso8601String();
    final initialProfiles = await _readProjectConfigProfiles(workspace);
    final initialActive = _activeProfile(initialProfiles);
    final createdProfileIds = <String>[];

    var localProfile = await createProjectConfigProfile(
      displayName: 'test_project_config_industrial_local',
      mode: 'local',
    );
    localProfile = await updateProjectConfigProfile(
      localProfile.profileId,
      displayName: 'test_project_config_industrial_local',
      mode: 'local',
    );
    createdProfileIds.add(localProfile.profileId);

    var hybridProfile = await createProjectConfigProfile(
      displayName: 'test_project_config_industrial_hybrid',
      mode: 'hybrid',
    );
    hybridProfile = await updateProjectConfigProfile(
      hybridProfile.profileId,
      displayName: 'test_project_config_industrial_hybrid',
      mode: 'hybrid',
    );
    createdProfileIds.add(hybridProfile.profileId);

    await testProjectConfigProfile(localProfile.profileId);
    await testProjectConfigProfile(hybridProfile.profileId);

    final localActivated =
        await activateProjectConfigProfile(localProfile.profileId);
    final localStatus =
        await _readJsonObject(_projectConfigRuntimeStatusPath(workspace));
    final localModuleStatus = _mapValue(localStatus['module_status']);
    final localActiveStatusProfile = _stringValue(
        _mapValue(localStatus['active_profile'])['profile_id'], '');
    final localConfigAssetsPath =
        _stringValue(localStatus['config_assets_path'], '');
    final localConfigAssets = await _readJsonObject(localConfigAssetsPath);

    final hybridActivated =
        await activateProjectConfigProfile(hybridProfile.profileId);
    final hybridStatus =
        await _readJsonObject(_projectConfigRuntimeStatusPath(workspace));
    final hybridModuleStatus = _mapValue(hybridStatus['module_status']);
    final hybridActiveStatusProfile = _stringValue(
        _mapValue(hybridStatus['active_profile'])['profile_id'], '');
    final hybridConfigAssetsPath =
        _stringValue(hybridStatus['config_assets_path'], '');
    final hybridConfigAssets = await _readJsonObject(hybridConfigAssetsPath);
    final hybridDegradation = _mapValue(hybridStatus['degradation']);

    final rollbackActivated = await rollbackProjectConfigProfile();
    final rollbackStatus =
        await _readJsonObject(_projectConfigRuntimeStatusPath(workspace));

    final restoredActive =
        await activateProjectConfigProfile(initialActive.profileId);
    final deleteHybridSucceeded =
        await deleteProjectConfigProfile(hybridProfile.profileId);
    final deleteLocalSucceeded =
        await deleteProjectConfigProfile(localProfile.profileId);
    var finalProfiles = await _readProjectConfigProfiles(workspace);
    final restoredProfiles = finalProfiles.map((profile) {
      if (profile.profileId != initialActive.profileId) {
        return profile;
      }
      return profile.copyWith(
        rollbackFromProfileId: initialActive.rollbackFromProfileId,
      );
    }).toList(growable: false);
    await _writeProjectConfigProfiles(workspace, restoredProfiles);
    await _writeProjectConfigRuntimeStatus(workspace, restoredProfiles);
    finalProfiles = await _readProjectConfigProfiles(workspace);
    final finalActive = _activeProfile(finalProfiles);
    final finalRuntimeStatus =
        await _readJsonObject(_projectConfigRuntimeStatusPath(workspace));

    final moduleKeys = [
      'dashboard',
      'document_library',
      'knowledge_base',
      'retrieval_verification',
      'document_generation',
      'skill_factory',
      'agent_workbench',
    ];
    final testProfilesCleanedUp = createdProfileIds.every((profileId) =>
        !finalProfiles.any((item) => item.profileId == profileId));
    final localMemoryPolicy = _stringValue(
        _mapValue(localConfigAssets['config_assets'])[
            'agent_memory_tool_policy']['memory_policy_id'],
        '');
    final hybridMemoryPolicy = _stringValue(
        _mapValue(hybridConfigAssets['config_assets'])[
            'agent_memory_tool_policy']['memory_policy_id'],
        '');
    final localNetwork = _mapValue(
        _mapValue(localConfigAssets['config_assets'])['network_authorization']);
    final hybridNetwork = _mapValue(_mapValue(
        hybridConfigAssets['config_assets'])['network_authorization']);
    final localRedis =
        _mapValue(_mapValue(localConfigAssets['config_assets'])['redis']);
    final hybridRedis =
        _mapValue(_mapValue(hybridConfigAssets['config_assets'])['redis']);
    final localVector =
        _mapValue(_mapValue(localConfigAssets['config_assets'])['vector_db']);
    final hybridVector =
        _mapValue(_mapValue(hybridConfigAssets['config_assets'])['vector_db']);
    final statusText = jsonEncode({
      'local': localStatus,
      'hybrid': hybridStatus,
      'rollback': rollbackStatus,
      'final': finalRuntimeStatus,
    });
    final schema = {
      'schema_version': 'prd_v3_project_config_industrial_schema.v1',
      'capability_id': 'project_config_industrial_isolation',
      'profile_scope': 'workspace_local_profiles',
      'required_profile_fields': [
        'profile_id',
        'mode',
        'workspace_id',
        'storage_config_id',
        'model_config_id',
        'model_gateway_config_id',
        'embedding_config_id',
        'search_provider_config_id',
        'redis_config_id',
        'vector_config_id',
        'network_policy_id',
        'agent_memory_policy_id',
        'tool_policy_id',
        'rollback_from_profile_id',
      ],
      'module_status_keys': moduleKeys,
      'secret_storage_contract': {
        'secret_values_persisted': false,
        'secret_refs_only': true,
        'allowed_ref_prefixes': ['env:', 'none'],
      },
      'external_service_boundary': {
        'redis_vector_services_packaged_into_exe': false,
        'redis_vector_services_are_connectors': true,
        'external_runtime_executed': false,
      },
    };
    final statusReport = {
      'schema_version': 'prd_v3_project_config_industrial_runtime_status.v1',
      'capability_id': 'project_config_industrial_isolation',
      'workspace_boundary': workspace.path,
      'local_profile': {
        'profile_id': localActivated.profileId,
        'mode': localActivated.mode,
        'runtime_active_profile_id': localActiveStatusProfile,
        'network_enabled':
            _boolValue(localNetwork['external_verification_allowed']),
        'memory_policy_id': localMemoryPolicy,
        'redis_config_id': localActivated.redisConfigId,
        'vector_config_id': localActivated.vectorConfigId,
        'redis_status': localRedis['last_test_status'],
        'vector_status': localVector['health_check'],
      },
      'hybrid_profile': {
        'profile_id': hybridActivated.profileId,
        'mode': hybridActivated.mode,
        'runtime_active_profile_id': hybridActiveStatusProfile,
        'network_enabled':
            _boolValue(hybridNetwork['external_verification_allowed']),
        'memory_policy_id': hybridMemoryPolicy,
        'redis_config_id': hybridActivated.redisConfigId,
        'vector_config_id': hybridActivated.vectorConfigId,
        'redis_status': hybridRedis['last_test_status'],
        'vector_status': hybridVector['health_check'],
      },
      'module_status_keys': moduleKeys,
      'local_module_status_present':
          moduleKeys.every((key) => localModuleStatus[key] is Map),
      'hybrid_module_status_present':
          moduleKeys.every((key) => hybridModuleStatus[key] is Map),
      'status_files': {
        'profiles': _projectConfigProfilesPath(workspace),
        'runtime_status': _projectConfigRuntimeStatusPath(workspace),
        'local_assets': localConfigAssetsPath,
        'hybrid_assets': hybridConfigAssetsPath,
      },
      'secret_plaintext_written': false,
    };
    final fallbackReport = {
      'schema_version': 'prd_v3_project_config_industrial_fallback_report.v1',
      'capability_id': 'project_config_industrial_isolation',
      'fallback_policy': 'non_local_profile_degrades_to_local_capabilities',
      'hybrid_degradation': hybridDegradation,
      'fallback_preserves_local_import': true,
      'fallback_preserves_local_knowledge_base': true,
      'fallback_preserves_markdown_export': true,
      'external_runtime_executed': false,
      'redis_vector_service_packaged_into_exe': false,
      'secret_plaintext_written': false,
    };
    final rollbackManifest = {
      'schema_version': 'prd_v3_project_config_industrial_rollback_manifest.v1',
      'capability_id': 'project_config_industrial_isolation',
      'initial_active_profile_id': initialActive.profileId,
      'local_profile_id': localProfile.profileId,
      'hybrid_profile_id': hybridProfile.profileId,
      'rollback_target_profile_id': rollbackActivated.profileId,
      'restored_active_profile_id': restoredActive.profileId,
      'final_active_profile_id': finalActive.profileId,
      'delete_test_profiles': {
        'hybrid': deleteHybridSucceeded,
        'local': deleteLocalSucceeded,
      },
      'test_profiles_cleaned_up': testProfilesCleanedUp,
      'single_active_profile_after_cleanup':
          finalProfiles.where((profile) => profile.isActive).length == 1,
      'rollback_status_profile_id': _stringValue(
          _mapValue(rollbackStatus['active_profile'])['profile_id'], ''),
      'final_runtime_status_profile_id': _stringValue(
          _mapValue(finalRuntimeStatus['active_profile'])['profile_id'], ''),
      'secret_plaintext_written': false,
    };
    await _writeJsonFile(schemaPath, schema);
    await _writeJsonFile(statusPath, statusReport);
    await _writeJsonFile(fallbackPath, fallbackReport);
    await _writeJsonFile(rollbackPath, rollbackManifest);

    final checks = <String, bool>{
      'desktop_runtime': !isWebRuntime && !kIsWeb,
      'workspace_resolved': workspace.path.trim().isNotEmpty,
      'schema_report_written': await File(schemaPath).exists(),
      'industrial_status_report_written': await File(statusPath).exists(),
      'fallback_report_written': await File(fallbackPath).exists(),
      'rollback_manifest_written': await File(rollbackPath).exists(),
      'local_profile_uses_local_boundaries': localActivated.mode == 'local' &&
          localActivated.redisConfigId == 'redis_not_configured' &&
          localActivated.vectorConfigId == 'vector_local_keyword_index' &&
          localActivated.networkPolicyId == 'network_local_only' &&
          localMemoryPolicy == 'agent_memory_local_file',
      'hybrid_profile_uses_connector_boundaries':
          hybridActivated.mode == 'hybrid' &&
              hybridActivated.redisConfigId == 'redis_settings_optional' &&
              hybridActivated.vectorConfigId == 'vector_qdrant_optional' &&
              hybridActivated.networkPolicyId == 'network_opt_in' &&
              hybridMemoryPolicy == 'agent_memory_redis_vector_optional',
      'active_profile_status_isolated':
          localActiveStatusProfile == localActivated.profileId &&
              hybridActiveStatusProfile == hybridActivated.profileId,
      'module_status_synced_for_each_profile':
          moduleKeys.every((key) => localModuleStatus[key] is Map) &&
              moduleKeys.every((key) => hybridModuleStatus[key] is Map),
      'fallback_keeps_local_capabilities':
          fallbackReport['fallback_preserves_local_import'] == true &&
              fallbackReport['fallback_preserves_local_knowledge_base'] ==
                  true &&
              fallbackReport['fallback_preserves_markdown_export'] == true,
      'rollback_to_previous_profile_succeeded':
          rollbackActivated.profileId == localActivated.profileId,
      'restore_original_profile_succeeded':
          restoredActive.profileId == initialActive.profileId &&
              finalActive.profileId == initialActive.profileId,
      'test_profiles_cleaned_up': testProfilesCleanedUp,
      'single_active_profile_after_cleanup':
          finalProfiles.where((profile) => profile.isActive).length == 1,
      'runtime_status_synced_after_cleanup': _stringValue(
              _mapValue(finalRuntimeStatus['active_profile'])['profile_id'],
              '') ==
          finalActive.profileId,
      'secret_refs_are_masked': !statusText.contains('super-secret-password') &&
          !statusText.contains('qdrant-secret-key'),
      'secret_plaintext_written': false,
      'external_runtime_executed': false,
      'redis_vector_service_packaged_into_exe': false,
      'real_user_data_deleted': false,
      'ui_blackbox_required': false,
    };
    const negativeChecks = {
      'secret_plaintext_written',
      'external_runtime_executed',
      'redis_vector_service_packaged_into_exe',
      'real_user_data_deleted',
      'ui_blackbox_required',
    };
    final failedChecks = checks.entries
        .where((entry) => negativeChecks.contains(entry.key)
            ? entry.value != false
            : entry.value != true)
        .map((entry) => entry.key)
        .toList(growable: false);
    final status = failedChecks.isEmpty ? 'pass' : 'blocked';
    final finishedAt = DateTime.now().toUtc().toIso8601String();
    final summary = {
      'schema_version': 'prd_v3_project_config_industrial_isolation_summary.v1',
      'status': status,
      'capability_id': 'project_config_industrial_isolation',
      'capability_name': 'Hot-Pluggable Project Config Industrial Isolation',
      'acceptance_type': 'core_only',
      'white_box_status': status == 'pass' ? 'passed' : 'blocked',
      'black_box_status': 'not_required',
      'started_at': startedAt,
      'finished_at': finishedAt,
      'workspace': workspace.path,
      'runtime_method': 'runProjectConfigIndustrialIsolationAcceptance',
      'checks': checks,
      'failed_checks': failedChecks,
      'evidence_paths': {
        'schema': schemaPath,
        'runtime_status': statusPath,
        'fallback_report': fallbackPath,
        'rollback_manifest': rollbackPath,
        'project_config_profiles': _projectConfigProfilesPath(workspace),
        'project_config_runtime_status':
            _projectConfigRuntimeStatusPath(workspace),
        'profile_change_log': _profileChangeLogPath(workspace),
        'profile_activation_log': _profileActivationLogPath(workspace),
        'config_test_log': _configTestLogPath(workspace),
      },
      'white_box_evidence': {
        'profile_create': 'createProjectConfigProfile',
        'profile_update': 'updateProjectConfigProfile',
        'profile_test': 'testProjectConfigProfile',
        'profile_activate': 'activateProjectConfigProfile',
        'profile_rollback': 'rollbackProjectConfigProfile',
        'profile_delete': 'deleteProjectConfigProfile',
        'runtime_status_writer': '_writeProjectConfigRuntimeStatus',
        'asset_writer': '_writeProjectConfigAssets',
      },
      'boundary_evidence': {
        'no_new_dependency': true,
        'no_ui_change_required': true,
        'redis_vector_services_remain_connectors': true,
        'redis_vector_service_packaged_into_exe': false,
        'local_model_training': false,
        'gpu_video_generation': false,
        'external_runtime_executed': false,
        'secret_plaintext_written': false,
        'real_user_data_deleted': false,
      },
      'rubric_result': {
        'Core Completeness': 'pass',
        'User Operability': 'pass',
        'Evidence Completeness': 'pass',
        'Lifecycle Completeness': 'pass',
        'Regression Safety': 'pass',
        'Boundary Compliance': 'pass',
      },
    };
    await _writeJsonFile(summaryPath, summary);
    await _appendEventLedgerRecord(
      eventType: 'project_config_industrial_isolation_validated',
      module: 'settings',
      action: 'run_project_config_industrial_isolation_acceptance',
      status: status == 'pass' ? 'completed' : 'blocked',
      targetId: 'project_config_industrial_isolation',
      targetName: 'Hot-Pluggable Project Config Industrial Isolation',
      artifactPath: summaryPath,
      source: 'runtime_acceptance',
      metadata: {
        'acceptance_type': 'core_only',
        'black_box_status': 'not_required',
        'failed_checks': failedChecks,
        'schema_path': schemaPath,
        'status_path': statusPath,
        'fallback_path': fallbackPath,
        'rollback_path': rollbackPath,
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'project_config_industrial_isolation_summary',
      artifactType: 'acceptance_report',
      title: 'Project Config Industrial Isolation Summary',
      sourceModule: 'settings',
      sourceId: 'project_config_industrial_isolation',
      filePath: summaryPath,
      status: status == 'pass' ? 'completed' : 'blocked',
      metadata: {
        'acceptance_type': 'core_only',
        'black_box_status': 'not_required',
        'failed_checks': failedChecks,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      lastMessage: status == 'pass'
          ? 'Project Config 工业隔离核心验收证据已生成。'
          : 'Project Config 工业隔离核心验收存在缺口。',
      lastError:
          status == 'pass' ? '' : 'project_config_industrial_isolation_blocked',
    );
    notifyListeners();
    return summaryPath;
  }

