        'schema_version': 'prd_v3_polly_style_execution_trace.v1',
        'step': 4,
        'subtask_id': 'lead_task_04',
        'owner_role': 'verifier',
        'status': 'completed',
        'output_ref': 'validation_report',
        'review_result': 'pass',
