      'query_answer_route_report_path': queryAnswerPath,
      'delete_report_path': deleteReportPath,
      'tombstone_path': tombstonePath,
      'state_snapshot_path': stateSnapshotPath,
      'boundary_report_path': boundaryReportPath,
