      running: false,
      lastMessage: status == 'pass' ? '知识库版本治理核心验收证据已生成。' : '知识库版本治理核心验收存在缺口。',
      lastError:
          status == 'pass' ? '' : 'versioned_knowledge_governance_blocked',
