      lastMessage: status == 'pass' ? '知识库范围规则核心验收证据已生成。' : '知识库范围规则核心验收存在缺口。',
      lastError: status == 'pass' ? '' : 'jurisdiction_domain_scope_blocked',
    );
    notifyListeners();
    return summaryPath;
  }

