      },
      'boundary_evidence': boundaryReport,
      'rubric_result': {
        'Core Completeness': status == 'pass' ? 'pass' : 'fail',
        'User Operability': 'pass',
        'Evidence Completeness': status == 'pass' ? 'pass' : 'fail',
        'Lifecycle Completeness': status == 'pass' ? 'pass' : 'fail',
