    );
    notifyListeners();
    return summaryPath;
  }

  Future<String> runAgentMemoryMinimalCoreAcceptance() async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    state = state.copyWith(
      running: true,
      lastMessage: '正在执行 Agent Memory Minimal Core 验收...',
      lastError: '',
    );
    notifyListeners();
    final now = DateTime.now().toUtc().toIso8601String();
    final repoRoot = _resolveUiRepoRoot();
    final chainStatusPath =
        _join(repoRoot.path, 'capability_chain_status.json');
    final chainStatus = await _readJsonObject(chainStatusPath);
    final completedGates = _listOfStrings(chainStatus['completed_gates']);
    final needsOwnerReview =
        _listOfStrings(chainStatus['completed_with_owner_review_needed']);
    final blockedGates = _listOfStrings(chainStatus['blocked_gates']);
    final remainingGates = _listOfStrings(chainStatus['remaining_gates']);
    final currentGate = _stringValue(
      chainStatus['current_gate'],
      'P0-4C Agent Memory Minimal Core Gate',
    );
    final currentPhase = _stringValue(chainStatus['current_phase'], 'P0');
    final globalGoalComplete =
        remainingGates.isEmpty && chainStatus['global_goal_complete'] == true;
    final memoryDir = Directory(_join(workspace.path, 'task_memory'));
    await memoryDir.create(recursive: true);
    final snapshotPath = _join(memoryDir.path, 'task_memory_snapshot.json');
    final checkpointPath = _join(memoryDir.path, 'task_checkpoint.json');
    final failurePath = _join(memoryDir.path, 'failure_placeholder.json');
    final resumePath = _join(memoryDir.path, 'resume_pointer.json');
    final summaryPath = _joinNested(
        workspace.path, 'acceptance/agent_memory_minimal_core_summary.json');
    final snapshot = {
      'schema_version': 'heitang_task_memory_snapshot.v1',
      'snapshot_type': 'task_memory_snapshot',
      'status': 'completed_needs_owner_review',
      'created_at': now,
      'updated_at': now,
      'workspace': workspace.path,
      'source_chain_status_path': chainStatusPath,
      'current_phase': currentPhase,
      'current_gate': currentGate,
      'completed': completedGates,
      'needs_owner_review': needsOwnerReview,
      'blocked': blockedGates,
      'remaining': remainingGates,
      'completed_count': completedGates.length,
      'needs_owner_review_count': needsOwnerReview.length,
      'blocked_count': blockedGates.length,
      'remaining_count': remainingGates.length,
      'global_goal_complete': globalGoalComplete,
      'global_goal_complete_guard':
          remainingGates.isNotEmpty ? 'forced_false' : 'no_remaining_gates',
      'next_gate': remainingGates.isEmpty ? '' : remainingGates.first,
      'restore_contract': {
        'restore_source': 'task_memory_snapshot',
        'restore_current_gate': currentGate,
        'restore_current_phase': currentPhase,
        'restore_remaining_gates': remainingGates,
        'resume_pointer_path': resumePath,
      },
      'boundaries': {
        'tencentdb_agent_memory_integrated': false,
        'node_22_dependency_added': false,
        'full_l0_l3_memory_implemented': false,
        'shipping_claim_absent': true,
        'stage_exit_claim_absent': true,
        'final_acceptance_claim_absent': true,
      },
      'linked_blackbox_cases': const <String>[
        'P0-4C Agent Memory Minimal Core Gate',
      ],
      'evidence_paths': {
        'snapshot_path': snapshotPath,
        'checkpoint_path': checkpointPath,
        'failure_placeholder_path': failurePath,
        'resume_pointer_path': resumePath,
        'summary_path': summaryPath,
      },
    };
    await _writeJsonFile(snapshotPath, snapshot);
    await _writeJsonFile(checkpointPath, {
      'schema_version': 'heitang_task_memory_checkpoint.v1',
      'status': 'completed_needs_owner_review',
      'current_gate': currentGate,
      'completed': completedGates,
      'needs_owner_review': needsOwnerReview,
      'blocked': blockedGates,
      'remaining': remainingGates,
      'created_at': now,
    });
    await _writeJsonFile(failurePath, {
      'schema_version': 'heitang_task_memory_failure_placeholder.v1',
      'status': 'no_current_failure',
      'blocked': blockedGates,
      'created_at': now,
    });
    await _writeJsonFile(resumePath, {
      'schema_version': 'heitang_task_memory_resume_pointer.v1',
      'status': 'resume_available',
      'restore_from': snapshotPath,
      'current_phase': currentPhase,
      'current_gate': currentGate,
      'next_gate': remainingGates.isEmpty ? '' : remainingGates.first,
      'global_goal_complete': globalGoalComplete,
      'created_at': now,
    });
    final reloadedSnapshot = await _readJsonObject(snapshotPath);
    final reloadedResume = await _readJsonObject(resumePath);
    final requiredPaths = {
      'task_memory_snapshot_path': snapshotPath,
      'checkpoint_path': checkpointPath,
      'failure_placeholder_path': failurePath,
      'resume_pointer_path': resumePath,
    };
    final pathChecks = <String, bool>{};
    for (final entry in requiredPaths.entries) {
      pathChecks[entry.key] = await File(entry.value).exists();
    }
    final restartRecoverable =
        _stringValue(reloadedSnapshot['current_gate'], '') == currentGate &&
            _stringValue(reloadedResume['current_gate'], '') == currentGate &&
            _listOfStrings(reloadedSnapshot['remaining']).isNotEmpty &&
            reloadedSnapshot['global_goal_complete'] == false;
    final passed = pathChecks.values.every((ok) => ok) &&
        _stringValue(reloadedSnapshot['snapshot_type'], '') ==
            'task_memory_snapshot' &&
        _listOfStrings(reloadedSnapshot['remaining']).isNotEmpty &&
        _listOfStrings(reloadedSnapshot['needs_owner_review']).isNotEmpty &&
        reloadedSnapshot['global_goal_complete'] == false &&
        restartRecoverable;
    final status = passed
        ? 'agent_memory_minimal_core_completed_needs_owner_review'
        : 'agent_memory_minimal_core_blocked';
    await _writeJsonFile(summaryPath, {
      'schema_version': 'heitang_p0_agent_memory_minimal_core_summary.v1',
      'status': status,
      'generated_at': now,
      'workspace': workspace.path,
      'required_paths': requiredPaths,
      'path_checks': pathChecks,
      'current_phase': currentPhase,
      'current_gate': currentGate,
      'completed_count': completedGates.length,
      'needs_owner_review_count': needsOwnerReview.length,
      'blocked_count': blockedGates.length,
      'remaining_count': remainingGates.length,
      'global_goal_complete': globalGoalComplete,
      'remaining_gates_guarded': remainingGates.isNotEmpty,
      'restart_recoverable_from_disk': restartRecoverable,
      'task_memory_snapshot_created': true,
      'event_ledger_event_type': 'memory_snapshot_created',
      'artifact_lifecycle_artifact_id': 'task_memory_snapshot',
      'tencentdb_agent_memory_integrated': false,
      'node_22_dependency_added': false,
      'full_l0_l3_memory_implemented': false,
      'shipping_claim_absent': true,
      'stage_exit_claim_absent': true,
      'final_acceptance_claim_absent': true,
    });
    await _upsertArtifactRecord(
      artifactId: 'task_memory_snapshot',
      artifactType: 'task_memory_snapshot',
      title: 'Agent Memory Minimal Core 任务记忆快照',
      sourceModule: 'agent_memory',
      sourceId: 'p0_4c_agent_memory_minimal_core',
      filePath: snapshotPath,
      status: status,
      metadata: {
        'current_phase': currentPhase,
        'current_gate': currentGate,
        'remaining_count': remainingGates.length,
        'global_goal_complete': globalGoalComplete,
        'restart_recoverable_from_disk': restartRecoverable,
        'summary_path': summaryPath,
        'checkpoint_path': checkpointPath,
        'resume_pointer_path': resumePath,
      },
    );
    await _appendEventLedgerRecord(
      eventType: 'memory_snapshot_created',
      module: 'agent_memory',
      action: 'run_agent_memory_minimal_core_acceptance',
      status: status,
      targetId: 'task_memory_snapshot',
      targetName: 'Agent Memory Minimal Core Gate',
      artifactPath: snapshotPath,
      source: 'runtime_acceptance',
      metadata: {
        'current_phase': currentPhase,
        'current_gate': currentGate,
        'remaining_count': remainingGates.length,
        'global_goal_complete': globalGoalComplete,
        'restart_recoverable_from_disk': restartRecoverable,
        'summary_path': summaryPath,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      lastMessage: 'Agent Memory Minimal Core 验收已完成。',
      lastError: passed ? '' : 'agent_memory_minimal_core_blocked',
    );
    notifyListeners();
    return summaryPath;
  }

  Future<String> runAgentMemoryLayerBasicAcceptance() async {
    if (!isWebRuntime && !kIsWeb && _workspaceDir == null) {
      final workspace = await _resolveWorkspace();
      await workspace.create(recursive: true);
      _workspaceDir = workspace;
      state = state.copyWith(workspacePath: workspace.path);
      await _loadExistingArtifacts();
    }
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    state = state.copyWith(
      running: true,
      lastMessage: '正在生成 Agent Memory Layer Basic 核心验收证据...',
      lastError: '',
    );
    notifyListeners();

    final now = DateTime.now().toUtc().toIso8601String();
    final memoryDir = Directory(_join(workspace.path, 'agent_memory_layer'));
    await memoryDir.create(recursive: true);
    final entriesPath = _join(memoryDir.path, 'memory_entries.jsonl');
    final relationsPath = _join(memoryDir.path, 'memory_relations.jsonl');
    final indexPath = _join(memoryDir.path, 'memory_index.json');
    final offloadPath = _join(memoryDir.path, 'context_offload_pointer.json');
    final validationPath =
        _join(memoryDir.path, 'memory_validation_report.json');
    final summaryPath = _joinNested(
        workspace.path, 'acceptance/agent_memory_layer_basic_summary.json');
    final entries = _agentMemoryLayerBasicEntries(now);
    final relations = _agentMemoryLayerBasicRelations();
    final validationRows = entries
        .map((entry) => _validateAgentMemoryLayerEntry(entry, relations))
        .toList(growable: false);
    final errorRows = [
      _validateAgentMemoryLayerEntry({
        'memory_id': '',
        'memory_type': 'task_fact',
        'content': 'missing id',
        'source_trace_ids': const ['trace_task_001'],
        'confidence': 0.8,
        'status': 'active',
      }, relations),
      _validateAgentMemoryLayerEntry({
        'memory_id': 'mem_missing_trace',
        'memory_type': 'task_fact',
        'content': 'missing source trace',
        'source_trace_ids': const <String>[],
        'confidence': 0.8,
        'status': 'active',
      }, relations),
    ];
    final entryIds = entries
        .map((entry) => _stringValue(entry['memory_id'], ''))
        .where((id) => id.isNotEmpty)
        .toSet();
    final relationTargetsResolve = relations.every((relation) =>
        entryIds.contains(_stringValue(relation['from_memory_id'], '')) &&
        entryIds.contains(_stringValue(relation['to_memory_id'], '')));
    await File(entriesPath).writeAsString(
      '${entries.map(jsonEncode).join('\n')}\n',
      encoding: utf8,
    );
    await File(relationsPath).writeAsString(
      '${relations.map(jsonEncode).join('\n')}\n',
      encoding: utf8,
    );
    final indexPayload = <String, dynamic>{
      'schema_version': 'prd_v3_agent_memory_layer_index.v1',
      'status': 'pass',
      'memory_count': entries.length,
      'active_count': entries
          .where((entry) => _stringValue(entry['status'], '') == 'active')
          .length,
      'expired_count': entries
          .where((entry) => _stringValue(entry['status'], '') == 'expired')
          .length,
      'memory_types': entries
          .map((entry) => _stringValue(entry['memory_type'], ''))
          .where((type) => type.isNotEmpty)
          .toSet()
          .toList(growable: false),
      'query_routes': [
        {
          'query': 'resume current work',
          'matched_memory_ids': ['mem_task_goal', 'mem_resume_pointer'],
          'route': 'task_memory -> evidence -> answer',
        },
        {
          'query': 'why old task context is no longer primary',
          'matched_memory_ids': ['mem_old_context', 'mem_resume_pointer'],
          'route': 'status -> replacement -> current memory',
        },
      ],
      'created_at': now,
    };
    await _writeJsonFile(indexPath, indexPayload);
    final offloadPayload = <String, dynamic>{
      'schema_version': 'prd_v3_agent_memory_context_offload_pointer.v1',
      'status': 'pass',
      'offload_id': 'context_offload_p1_48_basic',
      'source_memory_ids': ['mem_task_goal', 'mem_resume_pointer'],
      'restorable_memory_ids': entries
          .map((entry) => _stringValue(entry['memory_id'], ''))
          .where((id) => id.isNotEmpty)
          .toList(growable: false),
      'resume_hint': 'restore active agent memory entries before next gate',
      'created_at': now,
    };
    await _writeJsonFile(offloadPath, offloadPayload);
    final validationReport = <String, dynamic>{
      'schema_version': 'prd_v3_agent_memory_layer_validation.v1',
      'status': validationRows.every((row) => row['status'] == 'accepted') &&
              errorRows.every((row) => row['status'] == 'rejected') &&
              relationTargetsResolve
          ? 'pass'
          : 'blocked',
      'accepted_entries': validationRows,
      'error_path_evidence': errorRows,
      'relation_targets_resolve': relationTargetsResolve,
      'checks': {
        'all_entries_accepted':
            validationRows.every((row) => row['status'] == 'accepted'),
        'missing_memory_id_rejected': errorRows.any((row) =>
            row['status'] == 'rejected' &&
            row['reason'] == 'missing_memory_id'),
        'missing_source_trace_rejected': errorRows.any((row) =>
            row['status'] == 'rejected' &&
            row['reason'] == 'missing_source_trace'),
        'relation_targets_resolve': relationTargetsResolve,
        'context_offload_pointer_created': true,
      },
    };
    await _writeJsonFile(validationPath, validationReport);
    final checks = <String, bool>{
      'desktop_runtime': !isWebRuntime && !kIsWeb,
      'workspace_resolved': workspace.path.trim().isNotEmpty,
      'memory_entries_written': await File(entriesPath).exists(),
      'memory_relations_written': await File(relationsPath).exists(),
      'memory_index_written': await File(indexPath).exists(),
      'context_offload_pointer_written': await File(offloadPath).exists(),
      'validation_report_written': await File(validationPath).exists(),
      'memory_count_at_least_four': entries.length >= 4,
      'active_memory_present':
          entries.any((entry) => _stringValue(entry['status'], '') == 'active'),
      'expired_memory_present': entries
          .any((entry) => _stringValue(entry['status'], '') == 'expired'),
      'replacement_relation_present': relations.any((relation) =>
          _stringValue(relation['relation_type'], '') == 'replaces'),
      'all_entries_have_source_trace':
          validationRows.every((row) => row['status'] == 'accepted'),
      'missing_memory_id_rejected': errorRows.any((row) =>
          row['status'] == 'rejected' && row['reason'] == 'missing_memory_id'),
      'missing_source_trace_rejected': errorRows.any((row) =>
          row['status'] == 'rejected' &&
          row['reason'] == 'missing_source_trace'),
      'relation_targets_resolve': relationTargetsResolve,
      'blackbox_not_required_for_core_only': true,
      'tencentdb_agent_memory_integrated': false,
      'node_22_dependency_added': false,
      'local_model_training_used': false,
      'external_memory_runtime_loaded': false,
      'no_external_llm_call': true,
      'no_vector_db_call': true,
      'redis_vector_service_packaged_into_exe': false,
      'real_user_data_deleted': false,
      'secret_plaintext_written': false,
    };
    const negativeChecks = {
      'tencentdb_agent_memory_integrated',
      'node_22_dependency_added',
      'local_model_training_used',
      'external_memory_runtime_loaded',
      'redis_vector_service_packaged_into_exe',
      'real_user_data_deleted',
      'secret_plaintext_written',
    };
    final failedChecks = checks.entries
        .where((entry) => negativeChecks.contains(entry.key)
            ? entry.value != false
            : entry.value != true)
        .map((entry) => entry.key)
        .toList(growable: false);
    final status = failedChecks.isEmpty ? 'pass' : 'blocked';
    final summary = <String, dynamic>{
      'schema_version': 'prd_v3_agent_memory_layer_basic_summary.v1',
      'status': status,
