        .toList(growable: false);
    final status = failedChecks.isEmpty ? 'pass' : 'blocked';
    final summary = <String, dynamic>{
      'schema_version': 'prd_v3_context_offload_basic_summary.v1',
      'status': status,
      'capability_id': 'context_offload_basic',
