    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      lastMessage:
          status == 'pass' ? 'Mermaid 符号记忆核心验收证据已生成。' : 'Mermaid 符号记忆核心验收存在缺口。',
      lastError:
          status == 'pass' ? '' : 'mermaid_symbolic_memory_industrial_blocked',
