    final reloadedSourceTrace = await _readJsonl(File(sourceTracePath));
    final reloadedTimeline = await _readJsonl(File(timelinePath));
    final loadedCards = _listOfMaps(reloadedCards['cards']);
    final checks = <String, bool>{
