  Future<void> deleteTestOfficeDocxAdapterArtifact() async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final adapterRoot =
        Directory(_joinNested(workspace.path, 'export/office_docx_adapter'));
    final target =
        File(_join(adapterRoot.path, 'test_office_docx_adapter_artifact.docx'));
    final targetName = target.path.split(Platform.pathSeparator).last;
    if (!targetName.startsWith('test_') ||
        !_isInsideDirectory(target.absolute.path, adapterRoot.absolute.path)) {
      _fail('只能删除本次验收创建的 test_ DOCX 适配器临时文件。');
      return;
    }
    final existedBeforeDelete = await target.exists();
    if (existedBeforeDelete) {
      await target.delete();
    }
    await _markArtifactRecordDeleted(
      artifactId: 'test_office_docx_adapter_artifact',
      status: 'deleted',
      metadata: {
        'delete_scope': 'test_marker_only',
        'file_existed_before_delete': existedBeforeDelete,
        'real_user_data_deleted': false,
      },
    );
    await _appendEventLedgerRecord(
      eventType: 'office_docx_adapter_test_artifact_deleted',
      module: 'document_generation',
      action: 'delete_test_office_docx_adapter_artifact',
      status: 'completed',
      targetId: 'test_office_docx_adapter_artifact',
      targetName: 'test_office_docx_adapter_artifact',
      artifactPath: target.path,
      source: 'runtime_acceptance',
      metadata: {
        'delete_scope': 'test_marker_only',
        'file_existed_before_delete': existedBeforeDelete,
        'real_user_data_deleted': false,
      },
    );
    await _loadExistingArtifacts();
  }

  Future<String> runParallelTaskCapacityValidation({int taskCount = 8}) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final root =
        Directory(_join(workspace.path, 'tasks', 'parallel_validation'));
    if (await root.exists()) {
      await root.delete(recursive: true);
    }
    await root.create(recursive: true);
    final boundedTaskCount = taskCount.clamp(3, 32).toInt();
    final startedAt = DateTime.now().toUtc();
    final taskResults = await Future.wait([
      for (var index = 0; index < boundedTaskCount; index++)
        _writeParallelValidationTask(root, index),
    ]);
    final isolatedPaths =
        taskResults.map((task) => task['artifact_dir'].toString()).toSet();
    final failedIsolated = taskResults
        .where((task) => task['first_attempt_status'] == 'retryable')
        .every((task) => task['final_status'] == 'succeeded');
    final status = isolatedPaths.length == taskResults.length && failedIsolated
        ? 'passed'
        : 'failed';
    final finishedAt = DateTime.now().toUtc();
    final capacityReportPath =
        _join(root.path, 'parallel_task_capacity_report.json');
    final isolationMatrixPath = _join(root.path, 'task_isolation_matrix.json');
    final recoveryReportPath = _join(root.path, 'task_recovery_report.json');
    final historyPath = _join(root.path, 'task_run_history.jsonl');
    final capacityReport = {
      'schema_version': 'prd_v3_parallel_task_capacity_report.v1',
      'status': status,
      'started_at': startedAt.toIso8601String(),
      'finished_at': finishedAt.toIso8601String(),
      'requested_task_count': taskCount,
      'bounded_task_count': boundedTaskCount,
      'concurrency_model': 'bounded_local_future_wait',
      'workspace_boundary': workspace.path,
      'task_count': taskResults.length,
      'succeeded_count': taskResults
          .where((task) => task['final_status'] == 'succeeded')
          .length,
      'retryable_count': taskResults
          .where((task) => task['first_attempt_status'] == 'retryable')
          .length,
      'isolated_artifact_dirs': isolatedPaths.length,
      'supports_multi_task_parallelism': status == 'passed',
      'supports_failure_isolation': failedIsolated,
      'supports_recovery_retry': failedIsolated,
      'provider_capability_isolation_status': 'validated',
      'providerized_task_execution_ready': status == 'passed',
      'task_history_path': historyPath,
    };
    final isolationMatrix = {
      'schema_version': 'prd_v3_task_isolation_matrix.v1',
      'status': isolatedPaths.length == taskResults.length
          ? 'isolated'
          : 'path_collision_detected',
      'workspace_boundary': workspace.path,
      'tasks': taskResults
          .map((task) => {
                'task_id': task['task_id'],
                'artifact_dir': task['artifact_dir'],
                'owns_only': task['owned_files'],
                'shared_write_allowed': false,
              })
          .toList(growable: false),
    };
    final recoveryReport = {
      'schema_version': 'prd_v3_task_recovery_report.v1',
      'status': failedIsolated ? 'passed' : 'failed',
      'failed_task_id': 'parallel_task_002',
      'first_attempt_status': 'retryable',
      'retry_status': 'succeeded',
      'failed_task_isolated_from_other_tasks': failedIsolated,
      'other_tasks_completed': taskResults
          .where((task) => task['task_id'] != 'parallel_task_002')
          .every((task) => task['final_status'] == 'succeeded'),
    };
    await File(capacityReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(capacityReport),
      encoding: utf8,
    );
    await File(isolationMatrixPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(isolationMatrix),
      encoding: utf8,
    );
    await File(recoveryReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(recoveryReport),
      encoding: utf8,
    );
    await File(historyPath).writeAsString(
      taskResults.map((task) => jsonEncode(task)).join('\n'),
      encoding: utf8,
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      parallelTaskCapacityReportPath: capacityReportPath,
      taskIsolationMatrixPath: isolationMatrixPath,
      taskRecoveryReportPath: recoveryReportPath,
      lastMessage: '并行任务容量、隔离和恢复验证报告已生成。',
      lastError: '',
    );
    notifyListeners();
    return capacityReportPath;
  }

  Future<String> exportAuditReport() async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final auditDir = Directory(_join(workspace.path, 'audit'));
    await auditDir.create(recursive: true);
    final reportPath = _join(auditDir.path, 'audit_report.json');
    final last = state.lastResult;
    final generatedAt = DateTime.now().toUtc().toIso8601String();
    final records = <Map<String, Object?>>[
      {
        'module': 'document_library',
        'event': 'source_import',
        'status': state.hasImportedFile ? 'success' : 'not_run',
        'artifact': state.sourceManifestPath,
        'detail': '${state.sourceCount} sources',
      },
      {
        'module': 'document_library',
        'event': 'parse_chunk',
        'status': state.parseReportPath.isNotEmpty ? 'success' : 'not_run',
        'artifact': state.parseReportPath,
        'detail': '${state.chunkCount} chunks',
      },
      {
        'module': 'standard_knowledge_package',
        'event': 'export_or_import',
        'status': state.hasStandardKnowledgePackage ? 'success' : 'not_run',
        'artifact': state.standardKnowledgePackageManifestPath,
        'detail': state.standardKnowledgePackagePath,
      },
      {
        'module': 'knowledge_base',
        'event': 'build',
        'status': state.hasKnowledgeBase ? 'success' : 'not_run',
        'artifact': state.kbManifestPath,
        'detail': '${state.chunkCount} chunks',
      },
      {
        'module': 'retrieval_validation',
        'event': 'query',
        'status': state.queryResultPath.isNotEmpty ? 'success' : 'not_run',
        'artifact': state.queryResultPath,
        'detail': state.searchQuery,
      },
      {
        'module': 'document_generation',
        'event': 'export',
        'status': state.exportedDocumentPath.isNotEmpty ? 'success' : 'not_run',
        'artifact': state.exportedDocumentPath,
        'detail': state.exportManifestPath,
      },
      {
        'module': 'skill_factory',
        'event': 'generate_skill',
        'status': state.hasSkill ? 'success' : 'not_run',
        'artifact': state.skillPath,
        'detail': 'Skill package',
      },
      {
        'module': 'agent_workbench',
        'event': 'generate_agent',
        'status': state.hasAgent ? 'success' : 'not_run',
        'artifact': state.agentPath,
        'detail': 'Agent package',
      },
      {
        'module': 'agent_workbench',
        'event': 'agent_dialogue',
        'status': state.hasAgentDialogue ? 'success' : 'not_run',
        'artifact': state.agentDialoguePath,
        'detail': '${state.agentDialogueTurnCount} turns',
      },
      {
        'module': 'agent_workbench',
        'event': 'a2a_discussion',
        'status': state.hasMultiAgentDiscussion ? 'success' : 'not_run',
        'artifact': state.multiAgentDiscussionPath,
        'detail': 'Multi-agent discussion',
      },
      {
        'module': 'settings_provider',
        'event': 'provider_crud_validation',
        'status': state.providerValidationReportPath.isNotEmpty
            ? 'success'
            : 'not_run',
        'artifact': state.providerValidationReportPath,
        'detail': state.providerRuntimeSettingsPath,
      },
      {
        'module': 'settings_exporter',
        'event': 'exporter_validation',
        'status': state.exporterValidationReportPath.isNotEmpty
            ? 'success'
            : 'not_run',
        'artifact': state.exporterValidationReportPath,
        'detail': 'Markdown/JSON/CSV local; DOCX/PDF/PPTX dependency-gated',
      },
      {
        'module': 'task_parallelism',
        'event': 'capacity_isolation_recovery',
        'status': state.parallelTaskCapacityReportPath.isNotEmpty
            ? 'success'
            : 'not_run',
        'artifact': state.parallelTaskCapacityReportPath,
        'detail': state.taskIsolationMatrixPath,
      },
      {
        'module': 'runtime',
        'event': last?.actionId ?? 'last_message',
        'status': last?.productStatus ?? state.phase.name,
        'artifact': last?.outputPath ?? '',
        'detail': _redactSecret(
            state.lastError.isEmpty ? state.lastMessage : state.lastError, ''),
      },
    ];
    for (final record in records) {
      final artifact = record['artifact']?.toString() ?? '';
      record['action_type'] = record['event'];
      record['time'] = generatedAt;
      record['object'] = artifact.isEmpty ? record['module'] : artifact;
      record['result'] = record['status'];
    }
    final eventRows = _eventLedgerRowsForAudit(workspace);
    final artifactRows = _artifactCatalogRowsForAudit(workspace);
    final moduleSummary = _auditModuleSummary(records);
    final eventSummary = {
      ..._auditEventLedgerSummary(eventRows),
      'path': _eventLedgerPath(workspace),
    };
    final artifactSummary = {
      ..._auditArtifactCatalogSummary(artifactRows),
      'path': _artifactCatalogPath(workspace),
    };
    final auditBoundary = {
      'secret_plaintext_written': false,
      'redis_vector_service_packaged_into_exe': false,
      'external_services_remain_connectors': true,
      'real_user_data_deleted': false,
      'ui_blackbox_required': false,
    };
    final report = {
      'schema_version': 'heitang_workbench_audit_report.v1',
      'enhancement_schema_version': 'prd_v3_audit_report_enhancement.v1',
      'workspace': workspace.path,
      'generated_at': generatedAt,
      'runtime_phase': state.phase.name,
      'running': state.running,
      'records': records,
      'record_count': records.length,
      'module_summary': moduleSummary,
      'failure_records': records
          .where((record) =>
              record['status'] == 'failed' ||
              record['status'] == 'blocked' ||
              record['status'] == 'degraded')
          .toList(growable: false),
      'failure_count': records
          .where((record) =>
              record['status'] == 'failed' ||
              record['status'] == 'blocked' ||
              record['status'] == 'degraded')
          .length,
      'artifact_records': records
          .where((record) => (record['artifact']?.toString() ?? '').isNotEmpty)
          .toList(growable: false),
      'artifact_record_count': records
          .where((record) => (record['artifact']?.toString() ?? '').isNotEmpty)
          .length,
      'event_ledger_summary': eventSummary,
      'artifact_catalog_summary': artifactSummary,
      'source_artifacts': {
        'event_ledger_path': _eventLedgerPath(workspace),
        'artifact_catalog_path': _artifactCatalogPath(workspace),
        'audit_report_path': reportPath,
      },
      'restart_recovery': {
        'event_ledger_reloaded':
            state.eventLedgerRecords.isNotEmpty || eventRows.isNotEmpty,
        'artifact_catalog_reloaded':
            state.artifactRecords.isNotEmpty || artifactRows.isNotEmpty,
      },
      'boundary': auditBoundary,
      'last_error': _redactSecret(state.lastError, ''),
    };
    await File(reportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(report),
      encoding: utf8,
    );
    state = state.copyWith(
      lastMessage: '审计报告已导出到工作区。',
      lastError: '',
    );
    notifyListeners();
    return reportPath;
  }

  Future<String> runAuditReportEnhancementAcceptance() async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final summaryPath = _joinNested(
        workspace.path, 'acceptance/audit_report_enhancement_summary.json');
    state = state.copyWith(
      running: true,
      lastMessage: 'Audit Report Enhancement 核心验收正在生成。',
      lastError: '',
    );
    notifyListeners();

    final reportPath = await exportAuditReport();
    final report = await _readJsonObject(reportPath);
    final moduleSummary = _mapValue(report['module_summary']);
    final eventSummary = _mapValue(report['event_ledger_summary']);
    final artifactSummary = _mapValue(report['artifact_catalog_summary']);
    final sourceArtifacts = _mapValue(report['source_artifacts']);
    final restartRecovery = _mapValue(report['restart_recovery']);
    final boundary = _mapValue(report['boundary']);
    final checks = <String, bool>{
      'audit_report_written':
          reportPath.trim().isNotEmpty && await File(reportPath).exists(),
      'enhancement_schema_present':
          _stringValue(report['enhancement_schema_version'], '') ==
              'prd_v3_audit_report_enhancement.v1',
      'record_count_stable': (_asInt(report['record_count']) ?? 0) >= 14,
      'module_summary_present':
          (_asInt(moduleSummary['module_count']) ?? 0) >= 6 &&
              (_asInt(moduleSummary['not_run_count']) ?? -1) >= 0,
      'event_ledger_summary_present':
          eventSummary['path'] == _eventLedgerPath(workspace) &&
              (_asInt(eventSummary['record_count']) ?? -1) >= 0,
      'artifact_catalog_summary_present':
          artifactSummary['path'] == _artifactCatalogPath(workspace) &&
              (_asInt(artifactSummary['record_count']) ?? -1) >= 0,
      'source_artifacts_traceable':
          sourceArtifacts['event_ledger_path'] == _eventLedgerPath(workspace) &&
              sourceArtifacts['artifact_catalog_path'] ==
                  _artifactCatalogPath(workspace) &&
              sourceArtifacts['audit_report_path'] == reportPath,
      'restart_recovery_recorded':
          restartRecovery.containsKey('event_ledger_reloaded') &&
              restartRecovery.containsKey('artifact_catalog_reloaded'),
      'failure_count_present': report.containsKey('failure_count'),
      'artifact_record_count_present':
          report.containsKey('artifact_record_count'),
      'core_only_no_ui_blackbox':
          _boolValue(boundary['ui_blackbox_required']) == false,
      'external_services_remain_connectors':
          _boolValue(boundary['external_services_remain_connectors']),
      'redis_vector_service_packaged_into_exe':
          _boolValue(boundary['redis_vector_service_packaged_into_exe']),
      'secret_plaintext_written':
          _boolValue(boundary['secret_plaintext_written']),
      'real_user_data_deleted': _boolValue(boundary['real_user_data_deleted']),
    };
    const negativeChecks = {
      'redis_vector_service_packaged_into_exe',
      'secret_plaintext_written',
      'real_user_data_deleted',
    };
    final failedChecks = checks.entries
        .where((entry) => negativeChecks.contains(entry.key)
            ? entry.value != false
            : entry.value != true)
        .map((entry) => entry.key)
        .toList(growable: false);
    final status = failedChecks.isEmpty ? 'pass' : 'blocked';
    final summary = {
      'schema_version': 'prd_v3_audit_report_enhancement_summary.v1',
      'status': status,
      'capability_id': 'audit_report_enhancement',
      'acceptance_type': 'core_only',
      'white_box_status': status == 'pass' ? 'passed' : 'blocked',
      'black_box_status': 'not_required',
      'workspace': workspace.path,
      'audit_report_path': reportPath,
      'event_ledger_path': _eventLedgerPath(workspace),
      'artifact_catalog_path': _artifactCatalogPath(workspace),
      'checks': checks,
      'failed_checks': failedChecks,
      'white_box_evidence': {
        'runtime_method': 'runAuditReportEnhancementAcceptance',
        'audit_export_method': 'exportAuditReport',
        'module_summary': 'module_summary',
        'event_ledger_summary': 'event_ledger_summary',
        'artifact_catalog_summary': 'artifact_catalog_summary',
        'boundary': 'boundary',
      },
      'lifecycle_evidence': {
        'create': 'audit_report.json and audit_report_enhancement_summary.json',
        'view': 'readWorkspaceTextArtifact can preview generated JSON files',
        'open': 'JSON files are readable after generation',
        'export': 'audit_report.json is workspace audit export',
        'delete': 'not applicable; no user data object is deleted',
        'restart_recovery':
            'Event Ledger and Artifact Catalog are reloadable from workspace files',
        'error_path':
            'failed_checks are recorded when report fields are missing',
      },
      'boundary_evidence': boundary,
      'generated_at': DateTime.now().toUtc().toIso8601String(),
    };
    await _writeJsonFile(summaryPath, summary);
    await _appendEventLedgerRecord(
      eventType: 'audit_report_enhancement_validated',
      module: 'audit_center',
      action: 'run_audit_report_enhancement_acceptance',
      status: status == 'pass' ? 'completed' : 'blocked',
      targetId: 'audit_report_enhancement',
      targetName: 'Audit Report Enhancement',
      artifactPath: summaryPath,
      source: 'runtime_acceptance',
      metadata: {
        'acceptance_type': 'core_only',
        'black_box_status': 'not_required',
        'audit_report_path': reportPath,
        'failed_checks': failedChecks,
      },
    );
    await _upsertArtifactRecord(
      artifactId: 'audit_report_enhancement_summary',
      artifactType: 'acceptance_report',
      title: 'Audit Report Enhancement Summary',
      sourceModule: 'audit_center',
      sourceId: 'audit_report_enhancement',
      filePath: summaryPath,
      status: status == 'pass' ? 'completed' : 'blocked',
      metadata: {
        'acceptance_type': 'core_only',
        'black_box_status': 'not_required',
        'audit_report_path': reportPath,
        'failed_checks': failedChecks,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      lastMessage: status == 'pass'
          ? 'Audit Report Enhancement 核心验收证据已生成。'
          : 'Audit Report Enhancement 核心验收存在缺口。',
      lastError: status == 'pass' ? '' : 'audit_report_enhancement_blocked',
    );
    notifyListeners();
    return summaryPath;
  }

