  Future<void> generateSkill({
    Rc6SkillGenerationConfig config = const Rc6SkillGenerationConfig(),
  }) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final kbDir = Directory(_join(workspace.path, 'kb'));
    if (!await kbDir.exists()) {
      await _appendEventLedgerRecord(
        eventType: 'failure_event',
        module: 'skill_factory',
        action: 'generate_skill',
        status: 'failed',
        targetId: 'generate_skill',
        targetName: config.skillName,
        artifactPath: _join(workspace.path, 'skill'),
        errorMessage: '请先构建知识库，再生成 Skill。',
        source: 'skill_generation_gate',
        metadata: {
          'failure_code': 'missing_knowledge_base',
          'required_artifact': _join(workspace.path, 'kb', 'manifest.json'),
          'skill_type': config.skillType,
          'target_platform': config.targetPlatform,
        },
      );
      await _appendSkillOperationHistoryRecord(
        action: 'generate_skill',
        artifact:
            _joinNested(workspace.path, 'skill/skill_generation_manifest.json'),
        status: 'failed',
        details: {
          'reason': 'missing_knowledge_base',
          'required_artifact': _join(workspace.path, 'kb', 'manifest.json'),
        },
      );
      _fail('请先构建知识库，再生成 Skill。');
      return;
    }
    await _clearWorkspacePath(_join(workspace.path, 'skill'));
    await _runCoreAction(
      actionId: 'package_to_skill',
      arguments: [
        'generate-skill',
        '--package',
        kbDir.path,
        '--output',
        _join(workspace.path, 'skill', 'knowledge_qa_skill'),
        '--skill-name',
        config.skillName,
      ],
      outputPath: _join(workspace.path, 'skill', 'knowledge_qa_skill'),
      nextPhase: Rc6RuntimePhase.skillGenerated,
      successMessage: 'Skill 草稿已生成。',
    );
    if (state.lastResult?.passed == true) {
      await _writeAdditionalSkillPackages(config: config);
      await _appendSkillVersionRecord(
        event: 'generate_skill',
        config: config.toJson(),
      );
      await _appendSkillOperationHistoryRecord(
        action: 'generate_skill',
        artifact:
            _joinNested(workspace.path, 'skill/skill_generation_manifest.json'),
        status: 'completed',
        details: config.toJson(),
      );
      await _appendOrchestrationPlanRecord(
        layer: 'skill',
        action: 'generate_skill',
        artifact:
            _joinNested(workspace.path, 'skill/skill_generation_manifest.json'),
        status: 'completed',
        resources: {
          'kb_package': kbDir.path,
          'skill_name': config.skillName,
          'skill_type': config.skillType,
          'target_platform': config.targetPlatform,
        },
      );
      await _writeSkillProductOperations(agentBound: state.hasAgent);
    }
    await _loadExistingArtifacts();
    notifyListeners();
  }

  Future<void> pickAndImportExternalSkill() async {
    if (!_canRunDesktop()) {
      return;
    }
    final file = await openFile(
      acceptedTypeGroups: const [
        XTypeGroup(
          label: 'External Skill',
          extensions: ['md', 'txt', 'json', 'yaml', 'yml'],
        ),
      ],
    );
    if (file != null) {
      await importExternalSkillPath(file.path);
      return;
    }
    final directoryPath = await getDirectoryPath();
    if (directoryPath == null) {
      state = state.copyWith(
        lastMessage: '未选择外部 Skill；本地化未执行。',
        phase: Rc6RuntimePhase.ready,
      );
      notifyListeners();
      return;
    }
    await importExternalSkillPath(directoryPath);
  }

  Future<void> importExternalSkillPath(String path) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final kbDir = Directory(_join(workspace.path, 'kb'));
    if (!await kbDir.exists()) {
      _fail('请先构建知识库，再导入并本地化外部 Skill。');
      return;
    }
    final sourceFile = await _resolveExternalSkillFile(path);
    if (sourceFile == null) {
      await _appendSkillOperationHistoryRecord(
        action: 'import_external_skill',
        artifact: path,
        status: 'failed',
        details: {
          'reason': 'path_not_found_or_no_supported_skill_file',
        },
      );
      _fail('未找到可导入的外部 Skill 文件；请选择 SKILL.md、Markdown、JSON 或 YAML 文件。');
      return;
    }
    final validation = await _validateExternalSkillSource(sourceFile);
    if (!validation.passed) {
      await _appendSkillOperationHistoryRecord(
        action: 'import_external_skill',
        artifact: sourceFile.path,
        status: 'failed',
        details: {
          'reason': validation.status,
          'missing_fields': validation.missingFields,
        },
      );
      _fail(validation.message);
      return;
    }
    state = state.copyWith(
      running: true,
      lastMessage: '正在导入并本地化外部 Skill...',
      lastError: '',
    );
    notifyListeners();
    await _writeAdditionalSkillPackages(externalSkillSource: sourceFile);
    await _appendSkillVersionRecord(
      event: 'localize_external_skill',
      config: {
        'source': sourceFile.path,
      },
    );
    await _appendSkillOperationHistoryRecord(
      action: 'import_external_skill',
      artifact: _joinNested(workspace.path,
          'skill/localized_writing_skill/S2/localized_skill_manifest.json'),
      status: 'completed',
      details: {
        'source': sourceFile.path,
        'schema_status': validation.status,
      },
    );
    await _writeSkillProductOperations(agentBound: state.hasAgent);
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      phase: Rc6RuntimePhase.skillGenerated,
      lastMessage: '外部 Skill 已导入并结合当前知识库生成本地化 Skill。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<_ExternalSkillValidationResult> _validateExternalSkillSource(
      File sourceFile) async {
    final text = await sourceFile.readAsString(encoding: utf8);
    final lower = text.toLowerCase();
    bool hasAny(List<String> needles) =>
        needles.any((needle) => lower.contains(needle.toLowerCase()));
    final checks = <String, bool>{
      'name': hasAny(['name:', '# ', '"name"', "'name'"]),
      'version': hasAny(['version:', '"version"', "'version'"]),
      'description': hasAny(['description:', '## 能力说明', '## description']),
      'inputs': hasAny(['inputs', 'input:', '输入', '输入格式']),
      'outputs': hasAny(['outputs', 'output:', '输出', '输出格式']),
      'instructions':
          hasAny(['instructions', 'instruction', '使用说明', '方法论', '行为规则']),
      'acceptance': hasAny(['acceptance', 'validation', '验收', '校验', '检查']),
    };
    final missing = checks.entries
        .where((entry) => !entry.value)
        .map((entry) => entry.key)
        .toList(growable: false);
    final dangerous = hasAny([
      'overwrite system',
      'delete system',
      'c:\\windows',
      'program files',
      'rm -rf',
      'format c:',
      '覆盖系统',
      '删除系统',
    ]);
    if (dangerous) {
      return const _ExternalSkillValidationResult(
        passed: false,
        status: 'dangerous_override_rejected',
        message: '外部 Skill 试图覆盖系统关键配置或执行危险操作，已拒绝导入。',
        missingFields: [],
      );
    }
    if (missing.isNotEmpty) {
      return _ExternalSkillValidationResult(
        passed: false,
        status: 'missing_required_fields',
        message: '外部 Skill 缺少必要字段：${missing.join(' / ')}。',
        missingFields: missing,
      );
    }
    return const _ExternalSkillValidationResult(
      passed: true,
      status: 'validated',
      message: '外部 Skill 字段校验通过。',
      missingFields: [],
    );
  }

  Future<void> generateAgent({
    Rc6AgentGenerationConfig config = const Rc6AgentGenerationConfig(),
  }) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final kbDir = Directory(_join(workspace.path, 'kb'));
    final skillDir = Directory(_join(workspace.path, 'skill'));
    if (!await kbDir.exists() || !await skillDir.exists()) {
      _fail('请先构建知识库并生成 Skill，再创建 Agent。');
      return;
    }
    await _clearWorkspacePath(_join(workspace.path, 'agent'));
    await _runCoreAction(
      actionId: 'kb_bound_agent_generation',
      arguments: [
        'generate-agent',
        '--mode',
        config.coreMode,
        '--package',
        kbDir.path,
        '--skill',
        _primarySkillPath(skillDir.path),
        '--output',
        _join(workspace.path, 'agent', 'knowledge_qa_agent'),
        '--agent-name',
        config.agentName,
      ],
      outputPath: _join(workspace.path, 'agent', 'knowledge_qa_agent'),
      nextPhase: Rc6RuntimePhase.agentGenerated,
      successMessage: 'Agent 草稿已生成并绑定知识库/Skill。',
    );
    if (state.lastResult?.passed == true) {
      await _writeAdditionalAgentPackages(config: config);
      await _writeAgentProductOperations(config: config);
      await _appendSkillOperationHistoryRecord(
        action: 'bind_agent',
        artifact: _joinNested(
            workspace.path, 'skill/operations/agent_binding_manifest.json'),
        status: 'bound',
        details: {
          'agent_name': config.agentName,
          'creation_mode': config.creationMode,
        },
      );
      await _appendOrchestrationPlanRecord(
        layer: 'agent',
        action: 'generate_agent',
        artifact:
            _joinNested(workspace.path, 'agent/agent_generation_manifest.json'),
        status: 'completed',
        resources: {
          'kb_package': kbDir.path,
          'skill_package': skillDir.path,
          'agent_name': config.agentName,
          'creation_mode': config.creationMode,
          'agent_type': config.agentType,
          'model_config_id': config.modelConfigId,
        },
      );
      await _writeSkillProductOperations(agentBound: true);
      await _writeMultiAgentDiscussion();
    }
    await _loadExistingArtifacts();
    notifyListeners();
  }

  Future<String> runMultiAgentDiscussion({
    String topic = '',
    List<String> participantAgentIds = const [],
    bool writeOfficeCollaborationSummaryIfReady = true,
    String officeCollaborationUiBlackboxPath =
        'Agent -> Work Group -> Start Work Group',
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    if (!state.hasAgent && !state.hasAgentProfiles) {
      _fail('请先在 Agent 工厂生成 Agent。');
      return '';
    }
    if (!state.hasSkill &&
        !state.hasSkillOperationManifest &&
        !state.hasSkillVersionManifest) {
      _fail('请先在 Skill 工厂生成 Skill，再启动 A2A 协作。');
      return '';
    }
    await _writeMultiAgentDiscussion(
      topic: topic,
      participantAgentIds: participantAgentIds,
    );
    final workspace = _requireWorkspace();
    final a2aRouteEvidence = _modelRouteEvidenceForScopes(
      await _currentModelRouteModuleBinding('a2a'),
      [
        'a2a_task_dispatch',
        'a2a_review',
        'a2a_conflict_detection',
        'a2a_consensus',
        'a2a_report',
      ],
    );
    await _appendAgentRunHistoryRecord(
      action: 'run_a2a_discussion',
      artifact:
          _join(workspace.path, 'multi_agent', 'multi_agent_discussion.md'),
      status: 'completed',
      details: {
        'topic': topic.trim(),
        'participant_agent_ids': participantAgentIds,
        'model_route_evidence': a2aRouteEvidence,
      },
    );
    await _appendOrchestrationPlanRecord(
      layer: 'a2a',
      action: 'run_a2a_discussion',
      artifact:
          _join(workspace.path, 'multi_agent', 'multi_agent_discussion.md'),
      status: 'completed',
      resources: {
        'topic': topic.trim(),
        'participant_agent_ids': participantAgentIds,
        'parent_workspace_id': 'W_M',
        'model_route_evidence': a2aRouteEvidence,
      },
    );
    final summaryPath = await _writeWorkgroupBasicRuntimeSummary(
      topic: topic,
      participantAgentIds: participantAgentIds,
      modelRouteEvidence: a2aRouteEvidence,
    );
    if (writeOfficeCollaborationSummaryIfReady) {
      await _writeOfficeCollaborationWorkgroupSummaryIfReady(
        workgroupSummaryPath: summaryPath,
        uiBlackboxPath: officeCollaborationUiBlackboxPath,
      );
    }
    if (_isResearchAnalysisAcceptanceTopic(topic)) {
      await _writeResearchAnalysisWorkgroupSummary(
        topic: topic,
        workgroupSummaryPath: summaryPath,
        participantAgentIds: participantAgentIds,
      );
    }
    if (_isRoleBasedWorkgroupAcceptanceTopic(topic)) {
      await _writeRoleBasedWorkgroupSummary(
        topic: topic,
        workgroupSummaryPath: summaryPath,
        participantAgentIds: participantAgentIds,
      );
    }
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '多 Agent 联合讨论纪要已生成。',
      lastError: '',
    );
    notifyListeners();
    return summaryPath;
  }

