  Future<String> runA2aTenAgentTemplateAcceptance({
    String topic = 'P2-4 常用助手模板十助手工作组验收',
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final templates = _p2FourAssistantTemplates();
    final creation = await _writeP2FourTemplateAssistants(
      workspace,
      templates: templates,
    );
    final participantIds = _listOfStrings(creation['assistant_ids']);
    await _loadExistingArtifacts();
    if (participantIds.length != 10) {
      _fail('常用助手模板创建未达到 10 个，不能启动十助手工作组。');
      return '';
    }
    final summaryPath = await runMultiAgentDiscussion(
      topic: topic,
      participantAgentIds: participantIds,
      writeOfficeCollaborationSummaryIfReady: false,
    );
    if (summaryPath.isEmpty) {
      return '';
    }
    final tombstone = await _tombstoneP2FourTemplateAssistants(
      workspace,
      createdAssistantIds: participantIds,
    );
    final acceptancePath = await _writeA2aTenAgentTemplateSummary(
      topic: topic,
      templates: templates,
      creation: creation,
      tombstone: tombstone,
      workgroupSummaryPath: summaryPath,
      participantAgentIds: participantIds,
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '常用助手模板十助手工作组验收已生成。',
      lastError: '',
    );
    notifyListeners();
    return acceptancePath;
  }

  Future<String> runMultiAgentRagDeepeningAcceptance({
    String topic = 'P2-5 多助手检索深化验收',
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final queryReport = await _readLatestQueryReport(workspace);
    final queryRows = queryReport['selected'] ??
        queryReport['results'] ??
        queryReport['records'];
    final selected = queryRows is List
        ? queryRows.whereType<Map>().take(5).toList()
        : const <Map>[];
    if (selected.isEmpty) {
      _fail('当前没有可追踪检索证据，不能生成多助手检索深化验收。');
      return '';
    }
    final acceptancePath = await _writeMultiAgentRagDeepeningSummary(
      topic: topic,
      queryReport: queryReport,
      selected: selected,
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '多助手检索深化验收已生成。',
      lastError: '',
    );
    notifyListeners();
    return acceptancePath;
  }

  bool _isResearchAnalysisAcceptanceTopic(String topic) {
    final normalized = topic.toLowerCase();
    return topic.contains('P2-3') ||
        topic.contains('研究分析') ||
        normalized.contains('research analysis');
  }

  bool _isRoleBasedWorkgroupAcceptanceTopic(String topic) {
    final normalized = topic.toLowerCase();
    return topic.contains('P2-10') ||
        topic.contains('角色分工') ||
        normalized.contains('role-based') ||
        normalized.contains('role based');
  }

