      'checks': validationChecks,
      'created_at': now,
    });
    await File(roleReviewPath).parent.create(recursive: true);
    await File(roleReviewPath).writeAsString(
      [
        '# 角色分工工作组复核',
        '',
        '## 任务',
        topic.trim().isEmpty ? 'P2-10 角色分工工作组验收' : topic.trim(),
