  Future<void> runAgentDialogue({String prompt = '请基于当前知识库总结核心要点。'}) async {
    if (!_canRunDesktop()) {
      return;
    }
    if (!state.hasAgent) {
      _fail('请先在 Agent 工厂生成 Agent。');
      return;
    }
    if (!state.hasSkill) {
      _fail('请先在 Skill 工厂生成 Skill，再运行 Agent 对话。');
      return;
    }
    final workspace = _requireWorkspace();
    final agentStatus =
        await _readJsonObject(_joinNested(workspace.path, 'agent/status.json'));
    if (_stringValue(agentStatus['status'], '') == 'dependency_missing') {
      _fail(_stringValue(agentStatus['last_error_zh'], 'Agent 依赖缺失，不能继续对话。'));
      return;
    }
    final outDir = Directory(_join(workspace.path, 'agent', 'dialogue'));
    await outDir.create(recursive: true);
    final queryReport = await _readLatestQueryReport(workspace);
    final queryRows = queryReport['selected'] ??
        queryReport['results'] ??
        queryReport['records'];
    final selected = queryRows is List
        ? queryRows.whereType<Map>().take(4).toList()
        : const <Map>[];
    final chunks = selected.isNotEmpty
        ? const <Map<String, dynamic>>[]
        : (await _readJsonl(File(_join(workspace.path, 'kb', 'chunks.jsonl'))))
            .take(4)
            .toList(growable: false);
    final evidence = selected.isNotEmpty ? selected : chunks;
    final dialoguePath = _join(outDir.path, 'agent_dialogue.md');
    final historyPath = _join(outDir.path, 'chat_history.jsonl');
    final previousTurns = await _readJsonl(File(historyPath));
    final agentConfig = await _readJsonObject(_joinNested(
        workspace.path, 'agent/knowledge_qa_agent/agent_manifest.json'));
    final modelConfigId = _stringValue(
        agentConfig['model_config_id'], 'local-default-or-configured-provider');
    final providerSettings = await loadProviderRuntimeSettings();
    final modelGateway = _mapValue(providerSettings['model_gateway']);
    final modelGatewayStatus = _userStatus(modelGateway['status']);
    final activeModelGatewayId =
        _stringValue(modelGateway['gateway_id'], 'gateway_not_configured');
    final modelGatewayRoute = _modelGatewayRouteSummary(
        modelGateway, _mapValue(providerSettings['llm']));
    final agentModelRouteBinding =
        await _currentModelRouteModuleBinding('agent_workbench');
    final agentChatRoute = _modelRouteEvidenceForScopes(
      agentModelRouteBinding,
      ['agent_chat', 'agent_reasoning', 'agent_summarization'],
    );
    final configuredKbIds = _listOfStrings(agentConfig['kb_ids']);
    final kbIds = configuredKbIds.isEmpty ? const ['K1'] : configuredKbIds;
    final configuredSkillIds = _listOfStrings(agentConfig['skill_ids']);
    final skillIds = configuredSkillIds.isEmpty
        ? const ['S1', 'reading_summary_skill']
        : configuredSkillIds;
    final outputFormat = _stringValue(agentConfig['output_format'], 'markdown');
    final roleGoal =
        _stringValue(agentConfig['role_goal'], '只基于绑定知识库和 Skill 回答，输出必须带引用。');
    final redisConfigId =
        _stringValue(agentConfig['redis_config_id'], 'settings_redis_optional');
    final vectorConfigId =
        _stringValue(agentConfig['vector_config_id'], 'local_file_index');
    final turn = {
      'turn_id':
          'turn_${(previousTurns.length + 1).toString().padLeft(3, '0')}',
      'prompt': prompt,
      'answer': '当前回答基于本地知识库和已生成 Skill，不调用外网、不执行系统命令。',
      'role_goal': roleGoal,
      'model_config_id': modelConfigId,
      'model_gateway_config_id': activeModelGatewayId,
      'model_gateway_status': modelGatewayStatus,
      'model_gateway_route': modelGatewayRoute,
      'model_route_binding': agentModelRouteBinding,
      'model_route_evidence': agentChatRoute,
      'kb_ids': kbIds,
      'skill_ids': skillIds,
      'output_format': outputFormat,
      'evidence_count': evidence.length,
      'evidence': evidence
          .map((item) => {
                'text': _compact(
                    item['text'] ?? item['summary'] ?? item['content'] ?? ''),
                'citation': (item['citation'] ??
                        item['source_path'] ??
                        item['chunk_id'] ??
                        '-')
                    .toString(),
              })
          .toList(growable: false),
      'memory_write': {
        'short_term': 'local_session',
        'history_path': historyPath,
        'redis_config_id': redisConfigId,
        'vector_config_id': vectorConfigId,
        'vector_memory': 'separate_from_kb_index',
      },
      'boundary': {
        'local_kb_only': true,
        'computer_use': false,
        'arbitrary_shell': false,
        'secret_plaintext_access': false,
      },
    };
    await File(historyPath).writeAsString(
      '${const JsonEncoder().convert(turn)}\n',
      encoding: utf8,
      mode: FileMode.append,
    );
    final turns = [...previousTurns, turn];
    final buffer = StringBuffer()
      ..writeln('# Agent 最小对话')
      ..writeln()
      ..writeln('## 本轮配置')
      ..writeln('- 模型：$modelConfigId')
      ..writeln('- Model Gateway：$activeModelGatewayId（$modelGatewayStatus）')
      ..writeln('- 角色说明：$roleGoal')
      ..writeln('- 知识库：${kbIds.join(' / ')}')
      ..writeln('- Skill：${skillIds.join(' / ')}')
      ..writeln('- 输出格式：$outputFormat')
      ..writeln('- 记忆写入：local_session -> chat_history.jsonl')
      ..writeln('- Redis 短期记忆配置：$redisConfigId')
      ..writeln('- 向量长期记忆配置：$vectorConfigId')
      ..writeln()
      ..writeln('## 会话历史');
    for (final item in turns) {
      buffer
        ..writeln()
        ..writeln('### ${item['turn_id']}')
        ..writeln()
        ..writeln('**用户问题**')
        ..writeln(item['prompt'])
        ..writeln()
        ..writeln('**Agent 回答**')
        ..writeln(item['answer'])
        ..writeln()
        ..writeln('**证据**');
      final itemEvidence = item['evidence'];
      if (itemEvidence is List && itemEvidence.isNotEmpty) {
        for (final evidenceItem in itemEvidence.whereType<Map>()) {
          buffer.writeln(
              '- ${evidenceItem['text'] ?? ''} (${evidenceItem['citation'] ?? '-'})');
        }
      } else {
        buffer.writeln('- 当前知识库没有可用证据，请先运行检索或重新构建知识库。');
      }
    }
    buffer
      ..writeln()
      ..writeln('## 边界')
      ..writeln('- 仅使用本地 KB/Skill 产物。')
      ..writeln('- 不开放 Computer Use。')
      ..writeln('- 不开放 arbitrary shell。')
      ..writeln('- 不展示明文 secret。');
    await File(dialoguePath).writeAsString(buffer.toString(), encoding: utf8);
    final citationTracePath = _join(outDir.path, 'citation_trace.jsonl');
    final citationLines = evidence
        .map((item) => jsonEncode({
              'schema_version': 'prd_v3_agent_citation_trace_record.v1',
              'turn_id': turn['turn_id'],
              'kb_ids': kbIds,
              'skill_ids': skillIds,
              'citation': _stringValue(
                  item['citation'] ?? item['source_path'] ?? item['chunk_id'],
                  ''),
              'chunk_id': _stringValue(item['chunk_id'], ''),
              'source_path': _stringValue(item['source_path'], ''),
              'text_preview':
                  _compact(item['text'] ?? item['summary'] ?? item['content']),
              'trace_status': 'linked',
              'created_at': DateTime.now().toUtc().toIso8601String(),
            }))
        .join('\n');
    await File(citationTracePath).writeAsString(
      citationLines.isEmpty ? '' : '$citationLines\n',
      encoding: utf8,
      mode: FileMode.append,
    );
    final skillRuleTracePath = _join(outDir.path, 'skill_rule_trace.jsonl');
    await File(skillRuleTracePath).writeAsString(
      '${jsonEncode({
            'schema_version': 'prd_v3_agent_skill_rule_trace_record.v1',
            'turn_id': turn['turn_id'],
            'skill_ids': skillIds,
            'rules_applied': [
              'local_kb_only',
              'citation_required',
              'no_arbitrary_shell',
              'no_computer_use',
            ],
            'status': 'applied',
            'created_at': DateTime.now().toUtc().toIso8601String(),
          })}\n',
      encoding: utf8,
      mode: FileMode.append,
    );
    final manifestPath = _join(outDir.path, 'agent_dialogue_manifest.json');
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert({
        'schema_version': 'rc10_agent_dialogue.v1',
        'status': evidence.isEmpty ? 'needs_evidence' : 'pass',
        'latest_prompt': prompt,
        'output': dialoguePath,
        'history_path': historyPath,
        'citation_trace_path': citationTracePath,
        'skill_rule_trace_path': skillRuleTracePath,
        'turn_count': turns.length,
        'evidence_count': evidence.length,
        'model_config_id': modelConfigId,
        'model_gateway_config_id': activeModelGatewayId,
        'model_gateway_status': modelGatewayStatus,
        'model_gateway_route': modelGatewayRoute,
        'model_route_binding': agentModelRouteBinding,
        'model_route_evidence': agentChatRoute,
        'role_goal': roleGoal,
        'used_kb_ids': kbIds,
        'used_skill_ids': skillIds,
        'output_format': outputFormat,
        'redis_config_id': redisConfigId,
        'vector_config_id': vectorConfigId,
        'citation_required': true,
        'memory_write_status': 'local_session_written',
        'error_message': '',
      }),
      encoding: utf8,
    );
    await _appendAgentRunHistoryRecord(
      action: 'run_agent_dialogue',
      artifact: dialoguePath,
      status: evidence.isEmpty ? 'needs_evidence' : 'completed',
      details: {
        'prompt': prompt,
        'history_path': historyPath,
        'turn_count': turns.length,
        'evidence_count': evidence.length,
        'model_config_id': modelConfigId,
        'model_gateway_config_id': activeModelGatewayId,
        'model_gateway_status': modelGatewayStatus,
        'model_route_evidence': agentChatRoute,
        'used_kb_ids': kbIds,
        'used_skill_ids': skillIds,
      },
    );
    await _appendOrchestrationPlanRecord(
      layer: 'agent',
      action: 'run_agent_dialogue',
      artifact: dialoguePath,
      status: evidence.isEmpty ? 'needs_evidence' : 'completed',
      resources: {
        'prompt': prompt,
        'model_config_id': modelConfigId,
        'model_gateway_config_id': activeModelGatewayId,
        'model_gateway_status': modelGatewayStatus,
        'model_route_evidence': agentChatRoute,
        'kb_ids': kbIds,
        'skill_ids': skillIds,
        'output_format': outputFormat,
        'evidence_count': evidence.length,
      },
    );
    state = state.copyWith(
      agentDialoguePath: dialoguePath,
      agentDialogueManifestPath: manifestPath,
      agentDialogueHistoryPath: historyPath,
      agentDialogueTurnCount: turns.length,
      agentDialogueModelConfigId: modelConfigId,
      agentDialogueUsedKbIds: kbIds,
      agentDialogueUsedSkillIds: skillIds,
      agentDialogueOutputFormat: outputFormat,
      agentDialogueEvidenceCount: evidence.length,
      agentDialogueMemoryWriteStatus: 'local_session_written',
      agentDialogueErrorMessage: '',
      lastMessage: 'Agent 最小对话已追加到会话历史。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<List<Rc6AgentProfile>> loadAgentProfiles() async {
    if (!_canRunDesktop()) {
      return const <Rc6AgentProfile>[];
    }
    final workspace = _requireWorkspace();
    return _readAgentProfiles(workspace);
  }

  Future<Rc6AgentConversation> loadAgentConversation(String agentId) async {
    if (!_canRunDesktop()) {
      return Rc6AgentConversation.empty(agentId);
    }
    return _readAgentConversation(_requireWorkspace(), agentId);
  }

  Future<Rc6AgentProfile?> createAgentProfile({
    required String name,
    String description = '',
    String role = '',
    List<String> boundKnowledgeBaseIds = const [],
    List<String> boundSkillIds = const [],
    Map<String, String> settings = const {},
  }) async {
    if (!_canRunDesktop()) {
      return null;
    }
    final trimmedName = name.trim();
    if (trimmedName.isEmpty) {
      _fail('请输入助手名称。');
      return null;
    }
    final workspace = _requireWorkspace();
    final now = DateTime.now().toUtc().toIso8601String();
    final profiles = await _readAgentProfiles(workspace);
    final cleanedKbIds = _cleanStringList(boundKnowledgeBaseIds);
    final scope = _agentProfileScopeDefaults(
      workspace: workspace,
      boundKnowledgeBaseIds: cleanedKbIds,
      settings: settings,
    );
    final separatedSettings = await _agentBackendSeparationSettings(
      workspace,
      settings: settings,
    );
    final profile = Rc6AgentProfile(
      id: _newAgentProfileId(trimmedName, profiles.length),
      name: trimmedName,
      description: description.trim(),
      role: role.trim().isEmpty ? '处理当前工作区任务' : role.trim(),
      status: 'available',
      createdAt: now,
      updatedAt: now,
      workspaceId:
          _stringValue(scope['workspace_id'], state.currentWorkbookName),
      primaryKnowledgeBaseId:
          _stringValue(scope['primary_knowledge_base_id'], ''),
      allowedReferenceKbIds: _listOfStrings(scope['allowed_reference_kb_ids']),
      kbScopeMode: _stringValue(scope['kb_scope_mode'], 'none'),
      answerPolicyId:
          _stringValue(scope['answer_policy_id'], 'strict_evidence'),
      aiProfileId:
          _stringValue(scope['ai_profile_id'], 'ai_profile_default_local'),
      boundKnowledgeBaseIds: cleanedKbIds,
      boundSkillIds: _cleanStringList(boundSkillIds),
      settings: separatedSettings,
    );
    await _writeAgentProfiles(workspace, [...profiles, profile]);
    await _writeAgentConversation(
      workspace,
      Rc6AgentConversation(
        conversationId: 'conv_${profile.id}',
        agentId: profile.id,
        messages: const <Rc6AgentMessage>[],
        createdAt: now,
        updatedAt: now,
      ),
    );
    await _appendAgentActivityRecord(
      action: 'create_agent',
      agentId: profile.id,
      status: 'completed',
      artifact: _agentCatalogPath(workspace),
      details: {'name': profile.name},
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '助手已创建并保存：${profile.name}。',
      lastError: '',
    );
    notifyListeners();
    return profile;
  }

  Future<Rc6AgentProfile?> updateAgentProfile({
    required String agentId,
    required String name,
    String description = '',
    String role = '',
    List<String> boundKnowledgeBaseIds = const [],
    List<String> boundSkillIds = const [],
    Map<String, String> settings = const {},
  }) async {
    if (!_canRunDesktop()) {
      return null;
    }
    final workspace = _requireWorkspace();
    final trimmedName = name.trim();
    if (agentId.trim().isEmpty || trimmedName.isEmpty) {
      _fail('请先选择助手并填写助手名称。');
      return null;
    }
    final profiles = await _readAgentProfiles(workspace);
    final index = profiles.indexWhere((profile) => profile.id == agentId);
    if (index < 0) {
      _fail('未找到要保存的助手配置。');
      return null;
    }
    final current = profiles[index];
    final cleanedKbIds = _cleanStringList(boundKnowledgeBaseIds);
    final scope = _agentProfileScopeDefaults(
      workspace: workspace,
      boundKnowledgeBaseIds: cleanedKbIds,
      settings: settings,
      current: current,
    );
    final separatedSettings = await _agentBackendSeparationSettings(
      workspace,
      settings: settings,
      current: current,
    );
    final updated = current.copyWith(
      name: trimmedName,
      description: description.trim(),
      role: role.trim().isEmpty ? current.role : role.trim(),
      updatedAt: DateTime.now().toUtc().toIso8601String(),
      workspaceId: _stringValue(scope['workspace_id'], current.workspaceId),
      primaryKnowledgeBaseId: _stringValue(
        scope['primary_knowledge_base_id'],
        current.primaryKnowledgeBaseId,
      ),
      allowedReferenceKbIds: _listOfStrings(scope['allowed_reference_kb_ids']),
      kbScopeMode: _stringValue(scope['kb_scope_mode'], current.kbScopeMode),
      answerPolicyId:
          _stringValue(scope['answer_policy_id'], current.answerPolicyId),
      aiProfileId: _stringValue(scope['ai_profile_id'], current.aiProfileId),
      boundKnowledgeBaseIds: cleanedKbIds,
      boundSkillIds: _cleanStringList(boundSkillIds),
      settings: separatedSettings,
    );
    final nextProfiles = [...profiles]..[index] = updated;
    await _writeAgentProfiles(workspace, nextProfiles);
    await _appendAgentActivityRecord(
      action: 'update_agent',
      agentId: updated.id,
      status: 'completed',
      artifact: _agentCatalogPath(workspace),
      details: {
        'name': updated.name,
        'bound_knowledge_base_ids': updated.boundKnowledgeBaseIds,
        'bound_skill_ids': updated.boundSkillIds,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '助手配置已保存：${updated.name}。',
      lastError: '',
    );
    notifyListeners();
    return updated;
  }

  Future<void> deleteAgentProfile(String agentId) async {
    if (!_canRunDesktop()) {
      return;
    }
    final workspace = _requireWorkspace();
    final profiles = await _readAgentProfiles(workspace);
    final target = profiles
        .where((profile) => profile.id == agentId)
        .cast<Rc6AgentProfile?>()
        .firstOrNull;
    if (target == null) {
      _fail('未找到要删除的助手。');
      return;
    }
    await _writeAgentProfiles(
      workspace,
      profiles.where((profile) => profile.id != agentId).toList(),
    );
    final conversationDir = _agentConversationDir(workspace, agentId);
    await _clearWorkspacePath(conversationDir);
    await _appendAgentActivityRecord(
      action: 'delete_agent',
      agentId: agentId,
      status: 'completed',
      artifact: _agentCatalogPath(workspace),
      details: {'name': target.name},
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '助手已删除：${target.name}。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<Rc6AgentConversation> sendAgentMessage({
    required String agentId,
    required String content,
  }) async {
    if (!_canRunDesktop()) {
      return Rc6AgentConversation.empty(agentId);
    }
    final prompt = content.trim();
    if (agentId.trim().isEmpty || prompt.isEmpty) {
      _fail('请选择助手并输入消息。');
      return Rc6AgentConversation.empty(agentId);
    }
    final workspace = _requireWorkspace();
    final profiles = await _readAgentProfiles(workspace);
    final profile = profiles
        .where((item) => item.id == agentId)
        .cast<Rc6AgentProfile?>()
        .firstOrNull;
    if (profile == null) {
      _fail('请先创建助手。');
      return Rc6AgentConversation.empty(agentId);
    }
    final previous = await _readAgentConversation(workspace, agentId);
    final now = DateTime.now().toUtc().toIso8601String();
    final userMessage = Rc6AgentMessage(
      id: _newAgentMessageId('user', previous.messages.length),
      role: 'user',
      content: prompt,
      createdAt: now,
      status: 'saved',
    );
    final reply = await _buildAgentReply(
      profile: profile,
      prompt: prompt,
      hasKnowledgeBase: state.hasKnowledgeBase,
      hasSkill: state.hasSkill,
    );
    final assistantMessage = Rc6AgentMessage(
      id: _newAgentMessageId('assistant', previous.messages.length + 1),
      role: 'assistant',
      content: reply.content,
      createdAt: now,
      status: reply.status,
      error: reply.error,
    );
    final conversation = Rc6AgentConversation(
      conversationId: previous.conversationId.isEmpty
          ? 'conv_$agentId'
          : previous.conversationId,
      agentId: agentId,
      messages: [
        ...previous.messages,
        userMessage,
        assistantMessage,
      ],
      createdAt: previous.createdAt.isEmpty ? now : previous.createdAt,
      updatedAt: now,
    );
    await _writeAgentConversation(workspace, conversation);
    await _appendAgentActivityRecord(
      action: 'send_agent_message',
      agentId: agentId,
      status: reply.status,
      artifact: _agentConversationPath(workspace, agentId),
      details: {
        'message_id': userMessage.id,
        'reply_id': assistantMessage.id,
        'reply_status': reply.status,
        'provider_kind': reply.providerKind,
        'knowledge_base_bound': profile.boundKnowledgeBaseIds.isNotEmpty,
        'skill_bound': profile.boundSkillIds.isNotEmpty,
        if (reply.error.isNotEmpty) 'error': reply.error,
      },
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: reply.status == 'llm_completed'
          ? '助手已调用真实模型并保存回复。'
          : '助手已保存本地占位回复；需要检查连接配置后才能使用真实模型回复。',
      lastError: '',
    );
    notifyListeners();
    return conversation;
  }

  Future<String> saveAgentReplyToArtifact({
    required String agentId,
    required String messageId,
  }) async {
    if (!_canRunDesktop()) {
      return '';
    }
    final workspace = _requireWorkspace();
    final conversation = await _readAgentConversation(workspace, agentId);
    final message = conversation.messages
        .where((item) => item.id == messageId && item.role == 'assistant')
        .cast<Rc6AgentMessage?>()
        .firstOrNull;
    if (message == null) {
      _fail('未找到可保存的助手回复。');
      return '';
    }
    final profile = (await _readAgentProfiles(workspace))
        .where((item) => item.id == agentId)
        .cast<Rc6AgentProfile?>()
        .firstOrNull;
    final artifactDir = Directory(_join(workspace.path, 'agent', 'artifacts'));
    await artifactDir.create(recursive: true);
    final safeId = _safeId(message.id);
    final artifactPath = _join(artifactDir.path, '$agentId-$safeId.md');
    final now = DateTime.now().toUtc().toIso8601String();
    final isRealModelReply = message.status == 'llm_completed';
    final savedStatus =
        isRealModelReply ? 'llm_completed_saved' : 'local_fallback_saved';
    final catalogStatus = isRealModelReply
        ? 'agent_artifacts_recorded'
        : 'local_fallback_artifacts_recorded';
    final statusLine =
        isRealModelReply ? '- 状态：真实模型回复已保存。' : '- 状态：当前为本地占位回复，不代表真实模型已完成运行。';
    await File(artifactPath).writeAsString(
      [
        '# ${profile?.name ?? '助手'}回复',
        '',
        '- 助手：${profile?.name ?? agentId}',
        '- 消息：${message.id}',
        '- 保存时间：$now',
        statusLine,
        '',
        message.content,
        '',
      ].join('\n'),
      encoding: utf8,
    );
    final catalogPath = _agentArtifactCatalogPath(workspace);
    final catalog = await _readJsonObject(catalogPath);
    final artifacts = _listOfMaps(catalog['artifacts']).toList(growable: true);
    final artifactId = 'agent_reply_${artifacts.length + 1}';
    artifacts.add({
      'artifact_id': artifactId,
      'agent_id': agentId,
      'agent_name': profile?.name ?? '',
      'message_id': message.id,
      'path': artifactPath,
      'status': savedStatus,
      'created_at': now,
    });
    await File(catalogPath).parent.create(recursive: true);
    await File(catalogPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert({
        'schema_version': 'heitang_agent_artifact_catalog.v1',
        'status': catalogStatus,
        'artifacts': artifacts,
        'updated_at': now,
      }),
      encoding: utf8,
    );
    await _upsertArtifactRecord(
      artifactId: artifactId,
      artifactType: 'agent_reply',
      title: profile == null || profile.name.isEmpty
          ? '助手回复成果'
          : '${profile.name}回复成果',
      sourceModule: 'agent',
      sourceId: agentId,
      filePath: artifactPath,
      status: savedStatus,
      metadata: {
        'message_id': message.id,
        'agent_id': agentId,
        'agent_name': profile?.name ?? '',
        'reply_status': message.status,
      },
    );
    await _appendAgentActivityRecord(
      action: 'save_agent_reply_to_artifact',
      agentId: agentId,
      status: savedStatus,
      artifact: artifactPath,
      details: {'message_id': message.id},
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: '助手回复已保存到成果入口：$artifactPath。',
      lastError: '',
    );
    notifyListeners();
    return artifactPath;
  }

  Future<String> exportAgentDialogue() async {
    if (!_canRunDesktop()) {
      return '';
    }
    if (!state.hasAgentDialogue || !state.hasAgentDialogueHistory) {
      _fail('请先运行单 Agent 对话，再导出对话记录。');
      return '';
    }
    final workspace = _requireWorkspace();
    final dialogue = File(state.agentDialoguePath);
    final history = File(state.agentDialogueHistoryPath);
    if (!await dialogue.exists() || !await history.exists()) {
      _fail('对话产物不完整，请重新运行单 Agent 对话。');
      return '';
    }
    final exportDir =
        Directory(_join(workspace.path, 'agent', 'dialogue_export'));
    await exportDir.create(recursive: true);
    final outputPath = _join(exportDir.path, 'agent_dialogue_export.md');
    final manifestPath =
        _join(exportDir.path, 'agent_dialogue_export_manifest.json');
    final historyLines = await history.readAsLines(encoding: utf8);
    final dialogueText = await dialogue.readAsString(encoding: utf8);
    final dialogueManifest = await _readJsonObject(_joinNested(
        workspace.path, 'agent/dialogue/agent_dialogue_manifest.json'));
    final usedKbIds = _listOfStrings(dialogueManifest['used_kb_ids']);
    final usedSkillIds = _listOfStrings(dialogueManifest['used_skill_ids']);
    final modelConfigId = _stringValue(dialogueManifest['model_config_id'],
        'local-default-or-configured-provider');
    final modelRouteEvidence =
        _mapValue(dialogueManifest['model_route_evidence']);
    await File(outputPath).writeAsString(
      [
        '# Agent 对话导出',
        '',
        '## 导出说明',
        '- 来源对话：${dialogue.path}',
        '- 会话历史：${history.path}',
        '- 导出轮数：${historyLines.length}',
        '- 绑定知识库：${usedKbIds.isEmpty ? 'K1' : usedKbIds.join(' / ')}',
        '- 绑定 Skill：${usedSkillIds.isEmpty ? 'S1 / reading_summary_skill' : usedSkillIds.join(' / ')}',
        '- 模型配置：$modelConfigId',
        '- 高风险能力：未开放 Computer Use / arbitrary shell',
        '',
        dialogueText,
      ].join('\n'),
      encoding: utf8,
    );
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert({
        'schema_version': 'prd_v2_agent_dialogue_export.v1',
        'status': 'pass',
        'workspace': workspace.path,
        'source_dialogue': dialogue.path,
        'source_history': history.path,
        'output': outputPath,
        'turn_count': historyLines.length,
        'used_kb_ids': usedKbIds.isEmpty ? ['K1'] : usedKbIds,
        'used_skill_ids': usedSkillIds.isEmpty
            ? ['S1', 'reading_summary_skill']
            : usedSkillIds,
        'model_config_id': modelConfigId,
        'model_route_evidence': modelRouteEvidence,
        'audit_included': true,
        'secret_plaintext_written': false,
      }),
      encoding: utf8,
    );
    await _appendAgentRunHistoryRecord(
      action: 'export_agent_dialogue',
      artifact: outputPath,
      status: 'completed',
      details: {
        'manifest_path': manifestPath,
        'source_history': history.path,
        'turn_count': historyLines.length,
        'used_kb_ids': usedKbIds.isEmpty ? ['K1'] : usedKbIds,
        'used_skill_ids': usedSkillIds.isEmpty
            ? ['S1', 'reading_summary_skill']
            : usedSkillIds,
        'model_route_evidence': modelRouteEvidence,
      },
    );
    await _appendOrchestrationPlanRecord(
      layer: 'agent',
      action: 'export_agent_dialogue',
      artifact: outputPath,
      status: 'completed',
      resources: {
        'manifest_path': manifestPath,
        'source_history': history.path,
        'turn_count': historyLines.length,
      },
    );
    state = state.copyWith(
      agentDialogueExportPath: outputPath,
      lastMessage: 'Agent 对话记录已导出。',
      lastError: '',
    );
    notifyListeners();
    return outputPath;
  }

  Future<void> completeSkillProductOperations() async {
    if (!_canRunDesktop()) {
      return;
    }
    if (!state.hasSkill) {
      await generateSkill();
      if (!state.hasSkill) return;
    }
    final workspace = _requireWorkspace();
    await _appendSkillOperationHistoryRecord(
      action: 'complete_skill_product_operations',
      artifact: _joinNested(
          workspace.path, 'skill/operations/skill_operation_manifest.json'),
      status: 'completed',
      details: {
        'agent_bound': state.hasAgent,
      },
    );
    await _writeSkillProductOperations(agentBound: state.hasAgent);
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: state.hasAgent
          ? 'Skill 查看、复制、融合、导出和 Agent 绑定产物已生成。'
          : 'Skill 查看、复制、融合和导出产物已生成；Agent 绑定将在创建 Agent 后写入。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<void> runSkillOperation(String operation) async {
    if (!_canRunDesktop()) {
      return;
    }
    final normalized = operation.trim();
    const allowed = {
      'copy',
      'fusion',
      'validate',
      'export',
      'bind_agent',
    };
    if (!allowed.contains(normalized)) {
      _fail('未知 Skill 操作：$operation');
      return;
    }
    if (!state.hasSkill) {
      await generateSkill();
      if (!state.hasSkill) return;
    }
    await _appendSkillVersionRecord(
      event: 'skill_operation_$normalized',
      config: {'operation': normalized},
    );
    final workspace = _requireWorkspace();
    await _appendSkillOperationHistoryRecord(
      action: 'skill_operation_$normalized',
      artifact: _joinNested(
          workspace.path, 'skill/operations/skill_operation_manifest.json'),
      status: 'completed',
      details: {
        'operation': normalized,
        'agent_bound': state.hasAgent,
      },
    );
    await _writeSkillProductOperations(
      agentBound: state.hasAgent,
      requestedOperation: normalized,
    );
    await _loadExistingArtifacts();
    state = state.copyWith(
      lastMessage: 'Skill 操作已完成：$normalized。',
      lastError: '',
    );
    notifyListeners();
  }

  Future<String> saveEditedSkill(String skillMarkdown) async {
    if (!_canRunDesktop()) {
      return '';
    }
    if (!state.hasSkill) {
      _fail('请先生成 Skill 草稿，再保存编辑内容。');
      return '';
    }
    final trimmed = skillMarkdown.trim();
    if (trimmed.isEmpty) {
      _fail('Skill 草稿不能为空。');
      return '';
    }
    final workspace = _requireWorkspace();
    final skillRoot = Directory(_join(workspace.path, 'skill'));
    final primaryDir = Directory(_join(skillRoot.path, 'knowledge_qa_skill'));
    final primarySkill = File(_join(primaryDir.path, 'SKILL.md'));
    if (!await primarySkill.exists()) {
      _fail('未找到可编辑的 SKILL.md。');
      return '';
    }
    state = state.copyWith(
      running: true,
      lastMessage: '正在保存 Skill 编辑稿...',
      lastError: '',
    );
    notifyListeners();
    final previous = await primarySkill.readAsString(encoding: utf8);
    final backup = File(_join(primaryDir.path, 'SKILL.original.md'));
    if (!await backup.exists()) {
      await backup.writeAsString(previous, encoding: utf8);
    }
    await primarySkill.writeAsString(skillMarkdown, encoding: utf8);
    final manifestPath = _join(primaryDir.path, 'skill_edit_manifest.json');
    await File(manifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert({
        'schema_version': 'prd_v2_skill_draft_edit.v1',
        'status': 'pass',
        'workspace': workspace.path,
        'edited_skill_path': primarySkill.path,
        'original_backup_path': backup.path,
        'size_bytes': await primarySkill.length(),
        'saved_at': DateTime.now().toUtc().toIso8601String(),
        'source_kb_manifest': _join(workspace.path, 'kb', 'manifest.json'),
        'secret_plaintext_written': false,
      }),
      encoding: utf8,
    );
    await _appendSkillVersionRecord(
      event: 'edit_skill',
      config: {
        'edited_skill_path': primarySkill.path,
      },
    );
    await _appendSkillOperationHistoryRecord(
      action: 'edit_skill',
      artifact: manifestPath,
      status: 'completed',
      details: {
        'edited_skill_path': primarySkill.path,
      },
    );
    await _writeSkillProductOperations(agentBound: state.hasAgent);
    await _loadExistingArtifacts();
    state = state.copyWith(
      running: false,
      phase: Rc6RuntimePhase.skillGenerated,
      lastMessage: 'Skill 编辑稿已保存并更新导出包。',
      lastError: '',
    );
    notifyListeners();
    return primarySkill.path;
  }

  Future<void> completeAgentProductOperations({
    Rc6AgentGenerationConfig config = const Rc6AgentGenerationConfig(),
  }) async {
    if (!_canRunDesktop()) {
