    return rows
        .whereType<Map>()
        .map((row) => Rc6AgentProfile.fromJson(Map<String, dynamic>.from(row)))
        .where((profile) => profile.id.isNotEmpty && profile.name.isNotEmpty)
        .toList(growable: false);
  }

