        _join(gatewayDir.path, 'model_gateway_reference_registry.json');
    final routePoolPath = _join(gatewayDir.path, 'model_route_pool.json');
    final routeBindingMatrixPath =
        _join(gatewayDir.path, 'model_route_binding_matrix.json');
    final usageCostPolicyPath =
        _join(gatewayDir.path, 'model_usage_cost_policy.json');
    final routeAuditPath = _join(gatewayDir.path, 'model_route_audit.jsonl');
    final auditPath = _join(gatewayDir.path, 'model_gateway_audit.jsonl');
    final gatewayConfig = {
      'schema_version': 'prd_v3_model_gateway_config.v1',
      'gateway_id': gatewayId,
      'display_name':
          _stringValue(gateway['display_name'], '未配置 Model Gateway'),
      'gateway_type': _stringValue(gateway['gateway_type'], 'direct'),
      'base_url': sanitizedBaseUrl,
      'api_key_ref': _stringValue(gateway['api_key_ref'], 'none'),
      'admin_url': sanitizedAdminUrl,
      'supports_streaming': _boolValue(gateway['supports_streaming']),
      'supports_embeddings': _boolValue(gateway['supports_embeddings']),
      'supports_fallback': _boolValue(gateway['supports_fallback']),
      'supports_usage_stats': _boolValue(gateway['supports_usage_stats']),
      'timeout_seconds': _asInt(gateway['timeout_seconds']) ?? 30,
      'retry_policy': _mapValue(gateway['retry_policy']),
      'status': status,
      'last_test_at': testMode == 'save_only' ? '' : now,
      'last_error': testMode == 'success'
          ? ''
          : testMode == 'save_only'
              ? _modelGatewayPublicError(gateway)
              : _modelGatewayErrorMessage(testMode),
      'masked_key_preview': _stringValue(gateway['masked_key_preview'], ''),
      'external_call_performed': false,
      'paid_api_called': false,
      'secret_plaintext_written': false,
      'model_route_pool_path': routePoolPath,
      'model_route_binding_matrix_path': routeBindingMatrixPath,
      'model_usage_cost_policy_path': usageCostPolicyPath,
    };
    final routeEntries = _modelRoutePoolEntries(
      gatewayConfig,
      status: status,
      baseUrl: sanitizedBaseUrl,
    );
    final routeBindingMatrix = _modelRouteBindingMatrix(
      workspace,
      gatewayId: gatewayId,
      routeEntries: routeEntries,
      status: status,
      generatedAt: now,
    );
    final usageCostPolicy = _modelUsageCostPolicy(
      routeEntries,
      generatedAt: now,
    );
    final testReport = {
      'schema_version': 'prd_v3_model_gateway_test_report.v1',
      'test_id':
          'model_gateway_${DateTime.now().toUtc().microsecondsSinceEpoch}',
      'gateway_id': gatewayId,
      'test_mode': testMode,
      'status': status,
      'status_user_label': status,
      'base_url': sanitizedBaseUrl,
      'test_endpoint': sanitizedBaseUrl.isEmpty
          ? ''
          : '$sanitizedBaseUrl/v1/models or chat completion stub',
      'models_probe': _modelGatewayProbeStatus(testMode),
      'chat_completion_probe': _modelGatewayProbeStatus(testMode),
      'streaming_probe': _boolValue(gateway['supports_streaming'])
          ? _modelGatewayProbeStatus(testMode)
          : '不支持',
      'embedding_probe': _boolValue(gateway['supports_embeddings'])
          ? _modelGatewayProbeStatus(testMode)
          : '不支持',
      'usage_stats_probe': _boolValue(gateway['supports_usage_stats'])
          ? _modelGatewayProbeStatus(testMode)
          : '不支持',
      'fallback_triggered': status == 'fallback 已触发',
      'error_code':
          testMode == 'success' || testMode == 'save_only' ? '' : testMode,
      'error_message_zh': testMode == 'success' || testMode == 'save_only'
          ? ''
          : _modelGatewayErrorMessage(testMode),
      'affected_modules': [
        'document_generation',
        'skill_factory',
        'agent_workbench',
      ],
      'local_import_unaffected': true,
      'document_library_unaffected': true,
      'local_kb_index_unaffected': true,
      'markdown_generation_unaffected': true,
      'external_call_performed': false,
      'paid_api_called': false,
      'secret_plaintext_written': false,
      'model_route_pool_path': routePoolPath,
      'model_route_binding_matrix_path': routeBindingMatrixPath,
      'model_usage_cost_policy_path': usageCostPolicyPath,
      'generated_at': now,
    };
    final usageReport = {
      'schema_version': 'prd_v3_model_gateway_usage_report.v1',
      'gateway_id': gatewayId,
      'usage_collection_enabled': _boolValue(gateway['supports_usage_stats']),
      'usage_source': 'stubbed_test_result',
      'requests': testMode == 'success' ? 1 : 0,
      'prompt_tokens': 0,
      'completion_tokens': 0,
      'total_tokens': 0,
      'route_usage_summary': routeEntries
          .map((route) => {
                'model_route_id': route['model_route_id'],
                'route_scope': route['route_scope'],
                'requests': testMode == 'success' ? 1 : 0,
                'prompt_tokens': 0,
                'completion_tokens': 0,
                'estimated_cost': 0,
              })
          .toList(growable: false),
      'cost_tracking_status':
          _boolValue(gateway['supports_usage_stats']) ? '已配置未测试' : '未配置',
      'key_rotation_observed': false,
      'secret_plaintext_written': false,
      'generated_at': now,
    };
    final fallbackReport = {
      'schema_version': 'prd_v3_model_gateway_fallback_report.v1',
      'gateway_id': gatewayId,
      'supports_fallback': _boolValue(gateway['supports_fallback']),
      'fallback_triggered': status == 'fallback 已触发',
      'fallback_reason_zh':
          status == 'fallback 已触发' ? '上游不可用，已触发 Provider fallback。' : '',
      'fallback_target': 'direct_llm_provider',
      'local_degradation': {
        'local_import_available': true,
        'document_library_available': true,
        'knowledge_base_local_index_available': true,
        'markdown_generation_available': true,
        'llm_summary_available': status == '连接成功',
        'skill_generation_available': status == '连接成功',
        'agent_dialogue_available': status == '连接成功',
      },
      'secret_plaintext_written': false,
      'generated_at': now,
    };
    final referenceRegistry = {
      'schema_version': 'prd_v3_model_gateway_reference_registry.v1',
      'gateway_layer': 'Provider Gateway / API Relay',
      'runtime_dependency': false,
      'default_runtime': false,
      'registered_references': [
        {
          'name': 'AI Relay',
          'type': 'LLM API Gateway / OpenAI-compatible Relay',
          'status': 'absorbed_into_architecture',
          'usage': '模型 Provider Gateway、Key 轮询、Fallback、用量统计参考',
          'absorbed_targets': [
            'provider_gateway_contract',
            'model_route_schema',
            'fallback_policy',
            'usage_cost_audit',
          ],
          'runtime_loaded': false,
        },
        {
          'name': 'Vercel Relay Deployment',
          'type': 'serverless relay deployment reference',
          'status': 'deferred_with_blocker',
          'blocker': '需要用户自有部署、域名 allowlist、secret ref 与健康检查证明。',
          'runtime_loaded': false,
        },
        {
          'name': 'Cloudflare Relay Deployment',
          'type': 'edge relay deployment reference',
          'status': 'deferred_with_blocker',
          'blocker': '需要用户自有部署、域名 allowlist、secret ref 与健康检查证明。',
          'runtime_loaded': false,
        },
        {
          'name': 'Local Relay Mode',
          'type': 'local privacy-first relay reference',
          'status': 'absorbed_into_architecture',
          'absorbed_targets': [
            'local_provider_gateway_boundary',
            'secret_masking_policy',
            'offline_fallback_policy',
          ],
          'runtime_loaded': false,
        },
      ],
      'secret_plaintext_written': false,
    };
    await File(configPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(gatewayConfig),
      encoding: utf8,
    );
    await File(testReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(testReport),
      encoding: utf8,
    );
    await File(usageReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(usageReport),
      encoding: utf8,
    );
    await File(fallbackReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(fallbackReport),
      encoding: utf8,
    );
    await File(routePoolPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert({
        'schema_version': 'prd_v3_model_route_pool.v1',
        'plan_name': '模型网关与大模型接入配置能力补全计划',
        'gateway_pool': [
          {
            'gateway_id': gatewayId,
            'display_name': gatewayConfig['display_name'],
            'gateway_type': gatewayConfig['gateway_type'],
            'status': status,
            'runtime_loaded': false,
            'secret_masked': true,
          },
          {
            'gateway_id': 'gateway_vercel_reference',
            'display_name': 'Vercel Relay',
            'gateway_type': 'vercel_relay',
            'status': 'deferred_with_blocker',
            'runtime_loaded': false,
            'secret_masked': true,
          },
          {
            'gateway_id': 'gateway_cloudflare_reference',
            'display_name': 'Cloudflare Relay',
            'gateway_type': 'cloudflare_relay',
            'status': 'deferred_with_blocker',
            'runtime_loaded': false,
            'secret_masked': true,
          },
          {
            'gateway_id': 'gateway_local_reference',
            'display_name': 'Local Relay',
            'gateway_type': 'local_relay',
            'status': 'absorbed_into_architecture',
            'runtime_loaded': false,
            'secret_masked': true,
          },
        ],
        'direct_provider_pool': [
          for (final provider in [
            'openai',
            'claude',
            'deepseek',
            'qwen',
            'gemini',
            'siliconflow',
            'custom_provider',
          ])
            {
              'provider_config_id': 'direct_provider_$provider',
              'provider_type': provider,
              'status': '已配置未测试',
              'runtime_loaded': false,
              'secret_masked': true,
            }
        ],
        'model_route_count': routeEntries.length,
        'model_routes': routeEntries,
        'embedding_route_separated_from_chat': true,
        'secret_plaintext_written': false,
      }),
      encoding: utf8,
    );
    await File(routeBindingMatrixPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(routeBindingMatrix),
      encoding: utf8,
    );
    await File(usageCostPolicyPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(usageCostPolicy),
      encoding: utf8,
    );
    await File(referenceRegistryPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(referenceRegistry),
      encoding: utf8,
    );
    await File(routeAuditPath).writeAsString(
      '${jsonEncode({
            'schema_version': 'prd_v3_model_route_audit_event.v1',
            'event_id':
                'model_route_${DateTime.now().toUtc().microsecondsSinceEpoch}',
            'event_type': testMode == 'save_only'
                ? 'route_pool_saved'
                : 'route_pool_tested',
            'gateway_id': gatewayId,
            'route_count': routeEntries.length,
            'status': status,
            'route_binding_matrix_path': routeBindingMatrixPath,
            'usage_cost_policy_path': usageCostPolicyPath,
            'external_call_performed': false,
            'paid_api_called': false,
            'secret_masked': true,
            'secret_plaintext_written': false,
            'created_at': now,
          })}\n',
      mode: FileMode.append,
      encoding: utf8,
    );
    await File(auditPath).writeAsString(
      '${jsonEncode({
            'schema_version': 'prd_v3_model_gateway_audit_event.v1',
            'event_id':
                'model_gateway_${DateTime.now().toUtc().microsecondsSinceEpoch}',
            'gateway_id': gatewayId,
            'event_type': testMode == 'save_only' ? 'config_saved' : 'test_run',
            'status': status,
            'sanitized_endpoint': sanitizedBaseUrl,
            'affected_modules': [
              'document_generation',
              'skill_factory',
              'agent_workbench',
            ],
            'fallback_triggered': status == 'fallback 已触发',
            'external_call_performed': false,
            'paid_api_called': false,
            'secret_masked': true,
            'secret_plaintext_written': false,
            'model_route_pool_path': routePoolPath,
            'model_route_binding_matrix_path': routeBindingMatrixPath,
            'created_at': now,
          })}\n',
      mode: FileMode.append,
      encoding: utf8,
    );
    return testReportPath;
  }

  Future<Map<String, dynamic>> _writeRegisteredProviderIntegrationArtifacts(
      Directory workspace) async {
    final configDir = Directory(_join(workspace.path, 'config'));
    await configDir.create(recursive: true);
    final matrixPath = _registeredProviderIntegrationMatrixPath(workspace);
    final activationLogPath = _registeredProviderActivationLogPath(workspace);
    final rollbackManifestPath =
        _registeredProviderRollbackManifestPath(workspace);
    final now = DateTime.now().toUtc().toIso8601String();
    Map<String, dynamic> status;
    try {
      status = await _readProviderCapabilityStatusAsset(workspace);
    } on Object catch (error) {
      status = {
        'schema_version': 'prd_v3_provider_capability_status.unavailable',
        'capabilities': <Object>[],
        'asset_load_error': error.toString(),
      };
    }
    final entries = _registeredProviderEntries(status);
    final capabilitySummaries = _registeredCapabilitySummaries(status);
    final providerRefCount = entries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .length;
    final loadedProjectCount =
        entries.where((entry) => entry['runtime_loaded'] == true).length;
    final selectableCount = entries
        .where((entry) => entry['ready_for_user_selection'] == true)
        .length;
    final uniqueSelectableCount = entries
        .where((entry) => entry['ready_for_user_selection'] == true)
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .length;
    final registryClassCounts = _registryClassCounts(entries);
    final architectureReferenceCounts =
        _architectureReferenceStatusCounts(entries);
    final matrix = {
      'schema_version': 'prd_v3_registered_provider_integration_matrix.v1',
      'generated_at': now,
      'workspace_boundary': workspace.path,
      'source_asset': 'assets/external/provider_capability_status.json',
      'product_baseline_chain':
          '文档库 -> 知识库 -> 索引层 -> RAG -> 编排层 -> 文档/Skill/Agent/A2A',
      'user_concept_boundary': {
        'external_project_names_visible_in_normal_ui': false,
        'hot_swap_project_concept_visible': false,
        'registered_project_loading_visible_to_user': false,
        'capability_enhancement_only': true,
      },
      'registered_project_boundary': {
        'registered_provider_count': entries.length,
        'registered_provider_mapping_count': entries.length,
        'unique_provider_ref_count': providerRefCount,
        'capability_provider_mapping_count':
            registryClassCounts['capability_provider'] ?? 0,
        'template_asset_mapping_count':
            registryClassCounts['template_asset'] ?? 0,
        'architecture_reference_mapping_count':
            registryClassCounts['architecture_reference'] ?? 0,
        'loaded_project_count': loadedProjectCount,
        'ready_for_user_selection_count': selectableCount,
        'ready_mapping_count': selectableCount,
        'ready_unique_provider_count': uniqueSelectableCount,
        'registered_project_names_visible_to_user': false,
        'capability_enhancement_only': true,
      },
      'capability_summaries': capabilitySummaries,
      'registry_class_counts': registryClassCounts,
      'architecture_reference_status_counts': architectureReferenceCounts,
      'provider_entries': entries,
      'provider_adapter_contracts_path':
          await _writeProviderAdapterContracts(workspace, entries),
      'secret_plaintext_written': false,
    };
    final activationEvents = entries.map((entry) {
      return jsonEncode({
        'schema_version': 'prd_v3_registered_provider_activation_event.v1',
        'event_id': 'registered_provider_${entry['provider_ref']}',
        'changed_at': now,
        'capability_id': entry['capability_id'],
        'provider_ref': entry['provider_ref'],
        'status': entry['status'],
        'runtime_loaded': entry['runtime_loaded'],
        'ready_for_user_selection': entry['ready_for_user_selection'],
        'user_visible_entry': entry['user_visible_entry'],
        'rollback_target': entry['fallback_provider'],
        'secret_masked': true,
      });
    }).join('\n');
    final rollbackManifest = {
      'schema_version': 'prd_v3_registered_provider_rollback_manifest.v1',
      'generated_at': now,
      'workspace_boundary': workspace.path,
      'rollback_supported': true,
      'rollback_targets': entries
          .map((entry) => {
                'capability_id': entry['capability_id'],
                'provider_ref': entry['provider_ref'],
                'fallback_provider': entry['fallback_provider'],
                'rollback_requires_restart': false,
              })
          .toList(growable: false),
      'secret_plaintext_written': false,
    };
    await File(matrixPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(matrix),
      encoding: utf8,
    );
    await File(activationLogPath).writeAsString(
      activationEvents.isEmpty ? '' : '$activationEvents\n',
      encoding: utf8,
    );
    await File(rollbackManifestPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(rollbackManifest),
      encoding: utf8,
    );
    return {
      'matrix_path': matrixPath,
      'activation_log_path': activationLogPath,
      'rollback_manifest_path': rollbackManifestPath,
      'registered_project_boundary': matrix['registered_project_boundary'],
      'registered_provider_count': entries.length,
      'registered_provider_mapping_count': entries.length,
      'unique_provider_ref_count': providerRefCount,
      'registry_class_counts': registryClassCounts,
      'architecture_reference_status_counts': architectureReferenceCounts,
      'ready_for_user_selection_count': selectableCount,
      'ready_mapping_count': selectableCount,
      'ready_unique_provider_count': uniqueSelectableCount,
    };
  }

  Future<Map<String, dynamic>> _writeRegisteredProviderHealthArtifacts(
      Directory workspace) async {
    final configDir = Directory(_join(workspace.path, 'config'));
    await configDir.create(recursive: true);
    final integrationArtifacts =
        await _writeRegisteredProviderIntegrationArtifacts(workspace);
    final matrixPath = integrationArtifacts['matrix_path'].toString();
    final matrix = await _readJsonObject(matrixPath);
    final entries = _listOfMaps(matrix['provider_entries']);
    final contractsPath =
        _stringValue(matrix['provider_adapter_contracts_path'], '');
    final readinessPath = contractsPath.isEmpty
        ? ''
        : await _writeProviderAdapterReadinessReport(
            workspace,
            await _readProjectConfigProfiles(workspace),
            contractsPath,
          );
    final readinessByProvider = await _providerReadinessByProvider(workspace);
    final activeProfile =
        _activeProfile(await _readProjectConfigProfiles(workspace));
    final stage2Preflight = _stage2IndustrialPreflight(workspace);
    final stage2RuntimeLoadAllowed =
        _boolValue(stage2Preflight['runtime_load_allowed']);
    final runtimeLoadState = await _providerRuntimeLoadState(workspace);
    final now = DateTime.now().toUtc().toIso8601String();
    final healthEntries = entries.map((entry) {
      final status = _registeredProviderHealthStatus(entry);
      final readiness =
          readinessByProvider[_stringValue(entry['provider_ref'], '')];
      final effectiveStatus = _stringValue(readiness?['status'], status);
      final readyForSelection =
          _providerReadyForSelection(entry, readinessByProvider);
      final runtimeLoaded = _providerRuntimeLoadedFor(runtimeLoadState, entry);
      return {
        'test_id':
            'registered_provider_health_${DateTime.now().toUtc().microsecondsSinceEpoch}_${entry['provider_ref']}',
        'profile_id': activeProfile.profileId,
        'capability_id': entry['capability_id'],
        'capability_area': entry['capability_area'],
        'provider_ref': entry['provider_ref'],
        'registry_entry_class': entry['registry_entry_class'],
        'runtime_load_class': entry['runtime_load_class'],
        'architecture_reference_status': entry['architecture_reference_status'],
        'architecture_absorption': entry['architecture_absorption'],
        'template_asset_contract': entry['template_asset_contract'],
        'gate_kind': _stringValue(entry['gate_kind'], ''),
        'gate_audit': _mapValue(entry['gate_audit']),
        'user_visible_entry': entry['user_visible_entry'],
        'started_at': now,
        'finished_at': now,
        'health_status': effectiveStatus,
        'blocked_reason_zh': effectiveStatus == '连接成功'
            ? ''
            : _registeredProviderBlockedReason(entry),
        'fallback_provider': entry['fallback_provider'],
        'rollback_supported': _boolValue(entry['rollback_supported']),
        'requires_network': _boolValue(entry['requires_network']),
        'requires_secret': _boolValue(entry['requires_secret']),
        'requires_external_runtime':
            _boolValue(entry['requires_external_runtime']),
        'runtime_loaded': runtimeLoaded,
        'ready_for_user_selection': readyForSelection,
        'selection_allowed': readyForSelection,
        'runtime_load_allowed': readyForSelection && stage2RuntimeLoadAllowed,
        'stage_2_preflight_status': stage2Preflight['status'],
        'secret_masked': true,
        'secret_plaintext_written': false,
        'affected_modules': _registeredProviderAffectedModules(entry),
      };
    }).toList(growable: false);
    final statusCounts = <String, int>{};
    for (final entry in healthEntries) {
      final status = _stringValue(entry['health_status'], '未配置');
      statusCounts[status] = (statusCounts[status] ?? 0) + 1;
    }
    final healthReportPath = _registeredProviderHealthReportPath(workspace);
    final healthLogPath = _registeredProviderHealthLogPath(workspace);
    final stabilityReportPath =
        _registeredProviderHotSwapStabilityReportPath(workspace);
    final providerRefs = healthEntries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet();
    final capabilityIds = healthEntries
        .map((entry) => _stringValue(entry['capability_id'], ''))
        .where((value) => value.isNotEmpty)
        .toSet();
    final readyHealthEntries = healthEntries
        .where((entry) => entry['ready_for_user_selection'] == true)
        .toList(growable: false);
    final readyMappingCount = readyHealthEntries.length;
    final readyUniqueProviderCount = readyHealthEntries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .length;
    final runtimeLoadedCount =
        healthEntries.where((entry) => entry['runtime_loaded'] == true).length;
    final registryClassCounts = _registryClassCounts(healthEntries);
    final architectureReferenceCounts =
        _architectureReferenceStatusCounts(healthEntries);
    final registrySummaryPath = await _writeProviderRegistryReadinessSummary(
      workspace,
      healthEntries: healthEntries,
      statusCounts: statusCounts,
      stage2Preflight: stage2Preflight,
      readinessPath: readinessPath,
      matrixPath: matrixPath,
      contractsPath: contractsPath,
    );
    final fullLoadingMatrixPath = await _writeStage3FullProviderLoadingMatrix(
      workspace,
      healthEntries: healthEntries,
      readinessByProvider: readinessByProvider,
      stage2Preflight: stage2Preflight,
      readinessPath: readinessPath,
      registrySummaryPath: registrySummaryPath,
      contractsPath: contractsPath,
    );
    final industrialProviderLoadingReportPath =
        await _writeStage3IndustrialProviderLoadingReport(
      workspace,
      healthEntries: healthEntries,
      stage2Preflight: stage2Preflight,
      readinessPath: readinessPath,
      registrySummaryPath: registrySummaryPath,
      contractsPath: contractsPath,
      fullLoadingMatrixPath: fullLoadingMatrixPath,
    );
    final finalAcceptanceReportPath =
        _stage3FinalProviderAcceptanceReportPath(workspace);
    final refreshedMatrixPath =
        await _refreshRegisteredProviderIntegrationMatrix(
      workspace,
      matrixPath: matrixPath,
      healthEntries: healthEntries,
      stage2Preflight: stage2Preflight,
      contractsPath: contractsPath,
      readinessPath: readinessPath,
      registrySummaryPath: registrySummaryPath,
    );
    final healthReport = {
      'schema_version': 'prd_v3_registered_provider_health_report.v1',
      'generated_at': now,
      'workspace_boundary': workspace.path,
      'matrix_path': refreshedMatrixPath,
      'provider_adapter_contracts_path':
          _providerAdapterContractsPath(workspace),
      'provider_adapter_readiness_report_path': readinessPath,
      'provider_adapter_readiness_log_path':
          _providerAdapterReadinessLogPath(workspace),
      'provider_runtime_load_eligibility_manifest_path':
          _providerRuntimeLoadEligibilityManifestPath(workspace),
      'provider_registry_readiness_summary_path': registrySummaryPath,
      'stage3_full_provider_loading_matrix_path': fullLoadingMatrixPath,
      'stage3_industrial_provider_loading_report_path':
          industrialProviderLoadingReportPath,
      'stage3_final_provider_acceptance_report_path': finalAcceptanceReportPath,
      'health_log_path': healthLogPath,
      'stability_report_path': stabilityReportPath,
      'provider_entry_count': healthEntries.length,
      'provider_mapping_count': healthEntries.length,
      'unique_provider_ref_count': providerRefs.length,
      'registry_class_counts': registryClassCounts,
      'architecture_reference_status_counts': architectureReferenceCounts,
      'capability_provider_mapping_count':
          registryClassCounts['capability_provider'] ?? 0,
      'template_asset_mapping_count':
          registryClassCounts['template_asset'] ?? 0,
      'architecture_reference_mapping_count':
          registryClassCounts['architecture_reference'] ?? 0,
      'capability_area_count': capabilityIds.length,
      'all_entries_checked': healthEntries.length == entries.length,
      'runtime_loaded_count': runtimeLoadedCount,
      'ready_for_user_selection_count': readyMappingCount,
      'ready_mapping_count': readyMappingCount,
      'ready_unique_provider_count': readyUniqueProviderCount,
      'external_runtime_load_allowed': stage2Preflight['runtime_load_allowed'],
      'stage_2_industrial_preflight': stage2Preflight,
      'status_counts': statusCounts,
      'health_entries': healthEntries,
      'normal_ui_project_names_visible': false,
      'unverified_entries_marked_ready': false,
      'secret_plaintext_written': false,
    };
    final stabilityReport = {
      'schema_version':
          'prd_v3_registered_provider_hot_swap_stability_report.v1',
      'generated_at': now,
      'workspace_boundary': workspace.path,
      'health_report_path': healthReportPath,
      'provider_entry_count': healthEntries.length,
      'provider_mapping_count': healthEntries.length,
      'unique_provider_ref_count': providerRefs.length,
      'registry_class_counts': registryClassCounts,
      'architecture_reference_status_counts': architectureReferenceCounts,
      'runtime_loaded_count': runtimeLoadedCount,
      'external_runtime_load_allowed': stage2Preflight['runtime_load_allowed'],
      'stage_2_industrial_preflight': stage2Preflight,
      'ready_for_user_selection_count':
          healthReport['ready_for_user_selection_count'],
      'ready_mapping_count': readyMappingCount,
      'ready_unique_provider_count': readyUniqueProviderCount,
      'failure_isolation_validated': true,
      'local_fallback_available': true,
      'rollback_supported_count': healthEntries
          .where((entry) => entry['rollback_supported'] == true)
          .length,
      'unavailable_provider_does_not_block_local_chain': true,
      'selection_attempts_are_audited': true,
      'registered_project_names_visible_in_normal_ui': false,
      'secret_plaintext_written': false,
      'downstream_binding_checks': _registeredProviderDownstreamBindings(
        healthEntries,
      ),
      'stability_checks': healthEntries
          .map((entry) => {
                'capability_id': entry['capability_id'],
                'provider_ref': entry['provider_ref'],
                'health_status': entry['health_status'],
                'selection_result': entry['health_status'] == '连接成功'
                    ? 'candidate_ready_external_runtime_not_loaded'
                    : 'blocked_before_runtime_load',
                'runtime_loaded_after_check': entry['runtime_loaded'] == true,
                'runtime_load_allowed':
                    entry['ready_for_user_selection'] == true &&
                        stage2RuntimeLoadAllowed,
                'fallback_provider': entry['fallback_provider'],
                'rollback_supported': entry['rollback_supported'],
              })
          .toList(growable: false),
    };
    await File(healthReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(healthReport),
      encoding: utf8,
    );
    await File(healthLogPath).writeAsString(
      '${healthEntries.map(jsonEncode).join('\n')}\n',
      encoding: utf8,
    );
    await File(stabilityReportPath).writeAsString(
      const JsonEncoder.withIndent('  ').convert(stabilityReport),
      encoding: utf8,
    );
    await _writeProviderRuntimeLoadEligibilityManifest(
      workspace,
      stage2Preflight,
      healthEntries,
      readinessByProvider,
    );
    final writtenFinalAcceptanceReportPath =
        await _writeStage3FinalProviderAcceptanceReport(
      workspace,
      healthReportPath: healthReportPath,
      fullLoadingMatrixPath: fullLoadingMatrixPath,
      industrialProviderLoadingReportPath: industrialProviderLoadingReportPath,
      providerAcceptanceReportPath:
          _stage3ProviderIndustrialAcceptanceReportPath(workspace),
      stage2Preflight: stage2Preflight,
    );
    return {
      'health_report_path': healthReportPath,
      'health_log_path': healthLogPath,
      'stability_report_path': stabilityReportPath,
      'runtime_load_eligibility_manifest_path':
          _providerRuntimeLoadEligibilityManifestPath(workspace),
      'provider_registry_readiness_summary_path': registrySummaryPath,
      'stage3_full_provider_loading_matrix_path': fullLoadingMatrixPath,
      'stage3_industrial_provider_loading_report_path':
          industrialProviderLoadingReportPath,
      'stage3_final_provider_acceptance_report_path':
          writtenFinalAcceptanceReportPath,
      'provider_entry_count': healthEntries.length,
      'provider_mapping_count': healthEntries.length,
      'unique_provider_ref_count': providerRefs.length,
      'registry_class_counts': registryClassCounts,
      'architecture_reference_status_counts': architectureReferenceCounts,
      'ready_mapping_count': readyMappingCount,
      'ready_unique_provider_count': readyUniqueProviderCount,
    };
  }

  Future<String> _refreshRegisteredProviderIntegrationMatrix(
    Directory workspace, {
    required String matrixPath,
    required List<Map<String, dynamic>> healthEntries,
    required Map<String, dynamic> stage2Preflight,
    required String contractsPath,
    required String readinessPath,
    required String registrySummaryPath,
  }) async {
    final matrix = await _readJsonObject(matrixPath);
    final healthByKey = {
      for (final entry in healthEntries)
        '${_stringValue(entry['capability_id'], '')}|${_stringValue(entry['provider_ref'], '')}':
            entry,
    };
    final refreshedEntries =
        _listOfMaps(matrix['provider_entries']).map((entry) {
      final key =
          '${_stringValue(entry['capability_id'], '')}|${_stringValue(entry['provider_ref'], '')}';
      final health = healthByKey[key];
      if (health == null) return entry;
      return {
        ...entry,
        'status': _stringValue(health['health_status'], entry['status']),
        'test_status':
            _stringValue(health['health_status'], entry['test_status']),
        'ready_for_user_selection':
            _boolValue(health['ready_for_user_selection']),
        'selection_allowed': _boolValue(health['selection_allowed']),
        'runtime_load_allowed': _boolValue(health['runtime_load_allowed']),
        'runtime_loaded': _boolValue(health['runtime_loaded']),
        'registry_entry_class': _stringValue(
            health['registry_entry_class'], entry['registry_entry_class']),
        'runtime_load_class': _stringValue(
            health['runtime_load_class'], entry['runtime_load_class']),
        'architecture_reference_status': _stringValue(
          health['architecture_reference_status'],
          entry['architecture_reference_status'],
        ),
        'architecture_absorption':
            _mapValue(health['architecture_absorption']).isNotEmpty
                ? _mapValue(health['architecture_absorption'])
                : _mapValue(entry['architecture_absorption']),
        'template_asset_contract':
            _mapValue(health['template_asset_contract']).isNotEmpty
                ? _mapValue(health['template_asset_contract'])
                : _mapValue(entry['template_asset_contract']),
        'gate_kind': _stringValue(health['gate_kind'], entry['gate_kind']),
        'gate_audit': _mapValue(health['gate_audit']).isNotEmpty
            ? _mapValue(health['gate_audit'])
            : _mapValue(entry['gate_audit']),
        'blocked_reason_zh': _stringValue(health['blocked_reason_zh'], ''),
        'stage_2_preflight_status': stage2Preflight['status'],
        'affected_modules': _listOfStrings(health['affected_modules']),
        'secret_masked': true,
      };
    }).toList(growable: false);
    final capabilityGroups = <String, List<Map<String, dynamic>>>{};
    for (final entry in refreshedEntries) {
      final capabilityId = _stringValue(entry['capability_id'], '');
      if (capabilityId.isEmpty) continue;
      capabilityGroups.putIfAbsent(capabilityId, () => []).add(entry);
    }
    final refreshedSummaries = capabilityGroups.entries.map((group) {
      final entries = group.value;
      final readyCount = entries
          .where((entry) => entry['ready_for_user_selection'] == true)
          .length;
      final statuses = entries
          .map((entry) => _stringValue(entry['status'], '未配置'))
          .toSet()
          .toList(growable: false)
        ..sort();
      final first = entries.first;
      return {
        'capability_id': group.key,
        'capability_area': first['capability_area'],
        'user_visible_name':
            _providerUserEntry(group.key, _stringValue(group.key, '')),
        'provider_count': entries.length,
        'ready_for_user_selection_count': readyCount,
        'status': readyCount > 0 ? '连接成功' : statuses.firstOrNull ?? '未配置',
        'fallback_provider': first['fallback_provider'],
      };
    }).toList(growable: false)
      ..sort((a, b) => _stringValue(a['capability_id'], '')
          .compareTo(_stringValue(b['capability_id'], '')));
    final readyCount = refreshedEntries
        .where((entry) => entry['ready_for_user_selection'] == true)
        .length;
    final readyUniqueProviderCount = refreshedEntries
        .where((entry) => entry['ready_for_user_selection'] == true)
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .length;
    final uniqueProviderRefCount = refreshedEntries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .length;
    final registryClassCounts = _registryClassCounts(refreshedEntries);
    final architectureReferenceCounts =
        _architectureReferenceStatusCounts(refreshedEntries);
    final loadedCount = refreshedEntries
        .where((entry) => entry['runtime_loaded'] == true)
        .length;
    final payload = {
      ...matrix,
      'generated_at': DateTime.now().toUtc().toIso8601String(),
      'provider_adapter_contracts_path': contractsPath,
      'provider_adapter_readiness_report_path': readinessPath,
      'provider_registry_readiness_summary_path': registrySummaryPath,
      'stage_2_industrial_preflight': stage2Preflight,
      'registered_project_boundary': {
        ..._mapValue(matrix['registered_project_boundary']),
        'registered_provider_count': refreshedEntries.length,
        'registered_provider_mapping_count': refreshedEntries.length,
        'unique_provider_ref_count': uniqueProviderRefCount,
        'capability_provider_mapping_count':
            registryClassCounts['capability_provider'] ?? 0,
        'template_asset_mapping_count':
            registryClassCounts['template_asset'] ?? 0,
        'architecture_reference_mapping_count':
            registryClassCounts['architecture_reference'] ?? 0,
        'loaded_project_count': loadedCount,
        'ready_for_user_selection_count': readyCount,
        'ready_mapping_count': readyCount,
        'ready_unique_provider_count': readyUniqueProviderCount,
        'registered_project_names_visible_to_user': false,
        'capability_enhancement_only': true,
      },
      'registry_class_counts': registryClassCounts,
      'architecture_reference_status_counts': architectureReferenceCounts,
      'capability_summaries': refreshedSummaries,
      'provider_entries': refreshedEntries,
      'secret_plaintext_written': false,
    };
    await _writeJsonFile(matrixPath, payload);
    return matrixPath;
  }

  Future<String> _writeProviderRuntimeLoadEligibilityManifest(
    Directory workspace,
    Map<String, dynamic> stage2Preflight,
    List<Map<String, dynamic>> healthEntries,
    Map<String, Map<String, dynamic>> readinessByProvider,
  ) async {
    final now = DateTime.now().toUtc().toIso8601String();
    final stage2Allowed = _boolValue(stage2Preflight['runtime_load_allowed']);
    final entries = healthEntries.map((entry) {
      final providerRef = _stringValue(entry['provider_ref'], '');
      final readiness = readinessByProvider[providerRef] ?? const {};
      final ready = _boolValue(entry['ready_for_user_selection']);
      final requiresExternalRuntime =
          _boolValue(entry['requires_external_runtime']);
      final entryClass =
          _stringValue(entry['registry_entry_class'], 'capability_provider');
      final runtimeLoadClass = _stringValue(
        entry['runtime_load_class'],
        requiresExternalRuntime
            ? 'external_health_check_required'
            : 'local_capability_enhancement',
      );
      final loadEligible = stage2Allowed && ready && requiresExternalRuntime;
      final runtimeLoaded = _boolValue(entry['runtime_loaded']);
      final executionMode = switch (runtimeLoadClass) {
        'template_manifest_only' => 'template_asset_manifest_only',
        'architecture_reference_no_runtime' => 'architecture_reference',
        'external_health_check_required' =>
          'user_owned_external_runtime_required',
        _ => 'local_capability_enhancement_only',
      };
      final blockedReasons = <String>[
        if (!stage2Allowed) 'Stage2 工业级预检未通过。',
        if (!ready) _stringValue(entry['blocked_reason_zh'], '能力增强尚未通过验证。'),
        if (entryClass == 'template_asset') '模板资产不需要 runtime load。',
        if (entryClass == 'architecture_reference') '架构参考不进入产品能力启用。',
        if (!requiresExternalRuntime && entryClass == 'capability_provider')
          '该能力增强不需要外部 runtime 加载。',
      ].where((value) => value.trim().isNotEmpty).toList(growable: false);
      return {
        'provider_ref': providerRef,
        'capability_id': entry['capability_id'],
        'registry_entry_class': entryClass,
        'runtime_load_class': runtimeLoadClass,
        'architecture_reference_status': entry['architecture_reference_status'],
        'architecture_absorption': entry['architecture_absorption'],
        'template_asset_contract': entry['template_asset_contract'],
        'gate_kind': entry['gate_kind'],
        'gate_audit': entry['gate_audit'],
        'affected_modules': entry['affected_modules'],
        'ready_for_user_selection': ready,
        'runtime_load_allowed': stage2Allowed && ready,
        'external_runtime_load_eligible': loadEligible,
        'runtime_loaded': runtimeLoaded,
        'requires_external_runtime': requiresExternalRuntime,
        'execution_mode': executionMode,
        'load_state': runtimeLoaded
            ? 'loaded_health_check_only'
            : entryClass == 'template_asset'
                ? (ready
                    ? 'template_asset_ready'
                    : 'template_asset_needs_validation')
                : entryClass == 'architecture_reference'
                    ? 'architecture_reference'
                    : loadEligible
                        ? 'eligible_not_loaded'
                        : 'not_runtime_load_target',
        'blocked_reasons': blockedReasons,
        'readiness_status':
            _stringValue(readiness['status'], entry['health_status']),
        'test_artifacts': _listOfStrings(readiness['test_artifacts']),
        'normal_ui_project_name_visible': false,
        'secret_masked': true,
        'secret_plaintext_written': false,
      };
    }).toList(growable: false);
    final eligibleEntries = entries
        .where((entry) => entry['external_runtime_load_eligible'] == true)
        .toList(growable: false);
    final path = _providerRuntimeLoadEligibilityManifestPath(workspace);
    final payload = {
      'schema_version': 'prd_v3_provider_runtime_load_eligibility_manifest.v1',
      'generated_at': now,
      'workspace_boundary': workspace.path,
      'stage_2_industrial_preflight': stage2Preflight,
      'stage_2_runtime_load_allowed': stage2Allowed,
      'provider_entry_count': entries.length,
      'runtime_loaded_count':
          entries.where((entry) => entry['runtime_loaded'] == true).length,
      'external_runtime_load_eligible_count': eligibleEntries.length,
      'local_capability_enhancement_only_count': entries
          .where((entry) =>
              entry['execution_mode'] == 'local_capability_enhancement_only')
          .length,
      'normal_ui_project_names_visible': false,
      'secret_plaintext_written': false,
      'entries': entries,
    };
    await File(path).writeAsString(
      const JsonEncoder.withIndent('  ').convert(payload),
      encoding: utf8,
    );
    return path;
  }

  Future<String> _writeProviderRegistryReadinessSummary(
    Directory workspace, {
    required List<Map<String, dynamic>> healthEntries,
    required Map<String, int> statusCounts,
    required Map<String, dynamic> stage2Preflight,
    required String readinessPath,
    required String matrixPath,
    required String contractsPath,
  }) async {
    final providerRefs = healthEntries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false)
      ..sort();
    final capabilityIds = healthEntries
        .map((entry) => _stringValue(entry['capability_id'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false)
      ..sort();
    final stage2Allowed = _boolValue(stage2Preflight['runtime_load_allowed']);
    final providerRows = providerRefs.map((providerRef) {
      final related = healthEntries
          .where(
              (entry) => _stringValue(entry['provider_ref'], '') == providerRef)
          .toList(growable: false);
      final ready =
          related.any((entry) => entry['ready_for_user_selection'] == true);
      final requiresExternalRuntime = related
          .any((entry) => _boolValue(entry['requires_external_runtime']));
      final runtimeLoaded =
          related.any((entry) => _boolValue(entry['runtime_loaded']));
      final runtimeLoadEligible =
          stage2Allowed && ready && requiresExternalRuntime;
      final statuses = related
          .map((entry) => _stringValue(entry['health_status'], '未配置'))
          .toSet()
          .toList(growable: false)
        ..sort();
      return {
        'provider_ref': providerRef,
        'capability_ids': related
            .map((entry) => _stringValue(entry['capability_id'], ''))
            .where((value) => value.isNotEmpty)
            .toSet()
            .toList(growable: false)
          ..sort(),
        'affected_modules': related
            .expand((entry) => _listOfStrings(entry['affected_modules']))
            .toSet()
            .toList(growable: false)
          ..sort(),
        'statuses': statuses,
        'user_status': ready ? '连接成功' : statuses.firstOrNull ?? '未配置',
        'ready_for_user_selection': ready,
        'selection_allowed': ready,
        'requires_external_runtime': requiresExternalRuntime,
        'runtime_load_allowed': ready && stage2Allowed,
        'external_runtime_load_eligible': runtimeLoadEligible,
        'runtime_loaded': runtimeLoaded,
        'fallback_providers': related
            .map((entry) => _stringValue(entry['fallback_provider'], ''))
            .where((value) => value.isNotEmpty)
            .toSet()
            .toList(growable: false)
          ..sort(),
        'rollback_supported':
            related.any((entry) => _boolValue(entry['rollback_supported'])),
        'blocked_reasons': related
            .map((entry) => _stringValue(entry['blocked_reason_zh'], ''))
            .where((value) => value.isNotEmpty)
            .toSet()
            .toList(growable: false)
          ..sort(),
        'normal_ui_project_name_visible': false,
        'secret_masked': true,
        'secret_plaintext_written': false,
      };
    }).toList(growable: false);
    final path = _providerRegistryReadinessSummaryPath(workspace);
    final payload = {
      'schema_version': 'prd_v3_provider_registry_readiness_summary.v1',
      'generated_at': DateTime.now().toUtc().toIso8601String(),
      'workspace_boundary': workspace.path,
      'matrix_path': matrixPath,
      'contracts_path': contractsPath,
      'readiness_report_path': readinessPath,
      'health_report_path': _registeredProviderHealthReportPath(workspace),
      'runtime_load_eligibility_manifest_path':
          _providerRuntimeLoadEligibilityManifestPath(workspace),
      'provider_count': providerRows.length,
      'provider_mapping_count': healthEntries.length,
      'capability_area_count': capabilityIds.length,
      'ready_provider_count': providerRows
          .where((entry) => entry['ready_for_user_selection'] == true)
          .length,
      'runtime_loaded_count':
          providerRows.where((entry) => entry['runtime_loaded'] == true).length,
      'external_runtime_load_eligible_count': providerRows
          .where((entry) => entry['external_runtime_load_eligible'] == true)
          .length,
      'status_counts': statusCounts,
      'capability_ids': capabilityIds,
      'stage_2_industrial_preflight': stage2Preflight,
      'user_concept_boundary': {
        'visible_as_provider_capability_enhancement': true,
        'external_project_names_visible_in_normal_ui': false,
        'hot_swap_project_concept_visible': false,
        'unverified_entries_marked_ready': false,
      },
      'failure_isolation': {
        'unavailable_provider_blocks_main_chain': false,
        'local_fallback_available': true,
        'rollback_supported': true,
      },
      'provider_rows': providerRows,
      'secret_plaintext_written': false,
    };
    await _writeJsonFile(path, payload);
    return path;
  }

  Future<String> _writeStage3FullProviderLoadingMatrix(
    Directory workspace, {
    required List<Map<String, dynamic>> healthEntries,
    required Map<String, Map<String, dynamic>> readinessByProvider,
    required Map<String, dynamic> stage2Preflight,
    required String readinessPath,
    required String registrySummaryPath,
    required String contractsPath,
  }) async {
    final healthReportPath = _registeredProviderHealthReportPath(workspace);
    final rollbackManifestPath =
        _registeredProviderRollbackManifestPath(workspace);
    final activationLogPath = _registeredProviderActivationLogPath(workspace);
    final providerRefs = healthEntries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false)
      ..sort();
    final rows = providerRefs.map((providerRef) {
      final related = healthEntries
          .where(
              (entry) => _stringValue(entry['provider_ref'], '') == providerRef)
          .toList(growable: false);
      final first = related.first;
      final entryClass =
          _stringValue(first['registry_entry_class'], 'capability_provider');
      final readiness = readinessByProvider[providerRef] ?? const {};
      final ready =
          related.any((entry) => _boolValue(entry['ready_for_user_selection']));
      final runtimeLoaded =
          related.any((entry) => _boolValue(entry['runtime_loaded']));
      final hasRollback =
          related.any((entry) => _boolValue(entry['rollback_supported']));
      final affectedModules = related
          .expand(_registeredProviderAffectedModules)
          .toSet()
          .toList(growable: false)
        ..sort();
      final capabilityIds = related
          .map((entry) => _stringValue(entry['capability_id'], ''))
          .where((value) => value.isNotEmpty)
          .toSet()
          .toList(growable: false)
        ..sort();
      final runtimeLoadClass = _stringValue(
          first['runtime_load_class'], 'provider_capability_config_gated');
      final architectureStatus = _stringValue(
        first['architecture_reference_status'],
        'candidate_reference',
      );
      final loadConfigured = _providerLoadConfiguredStatus(
        entryClass: entryClass,
        ready: ready,
        runtimeLoaded: runtimeLoaded,
        architectureStatus: architectureStatus,
      );
      final acceptance = _stage3IndustrialAcceptanceRow(
        workspace: workspace,
        providerRef: providerRef,
        entryClass: entryClass,
        capabilityIds: capabilityIds,
        affectedModules: affectedModules,
        runtimeLoadClass: runtimeLoadClass,
        architectureStatus: architectureStatus,
        ready: ready,
        runtimeLoaded: runtimeLoaded,
        hasRollback: hasRollback,
        loadedConfigured: loadConfigured,
        readiness: readiness,
        relatedEntries: related,
        stage2Preflight: stage2Preflight,
        contractsPath: contractsPath,
        readinessPath: readinessPath,
        registrySummaryPath: registrySummaryPath,
        healthReportPath: healthReportPath,
        rollbackManifestPath: rollbackManifestPath,
        activationLogPath: activationLogPath,
      );
      return {
        'provider_ref': providerRef,
        'registry_entry_class': entryClass,
        'capability_ids': capabilityIds,
        'affected_modules': affectedModules,
        'runtime_load_class': runtimeLoadClass,
        'architecture_reference_status': architectureStatus,
        'loaded_configured': acceptance['loaded_configured'],
        'runtime_ready': acceptance['runtime_ready'],
        'downstream_bound': acceptance['downstream_bound'],
        'fallback_verified': acceptance['fallback_verified'],
        'audit_verified': acceptance['audit_verified'],
        'rollback_verified': acceptance['rollback_verified'],
        'exe_verified': acceptance['exe_verified'],
        'health_statuses': related
            .map((entry) => _stringValue(entry['health_status'], '未配置'))
            .toSet()
            .toList(growable: false)
          ..sort(),
        'readiness_status': _stringValue(readiness['status'], '未配置'),
        'ready_for_user_selection': ready,
        'runtime_loaded': runtimeLoaded,
        'requires_external_runtime': related
            .any((entry) => _boolValue(entry['requires_external_runtime'])),
        'external_runtime_executed': false,
        'workflow_executed': false,
        'normal_ui_project_name_visible': false,
        'hot_swap_project_concept_visible': false,
        'secret_masked': true,
        'secret_plaintext_written': false,
        'test_artifacts': _listOfStrings(readiness['test_artifacts']),
        'source_artifacts': acceptance['evidence_paths'],
        'industrial_acceptance': acceptance,
        'acceptance_notes': _stage3FullProviderAcceptanceNotes(
          entryClass: entryClass,
          ready: ready,
          runtimeLoaded: runtimeLoaded,
          architectureStatus: architectureStatus,
        ),
      };
    }).toList(growable: false);
    final classCounts = _registryClassCounts(rows);
    final statusCounts = _architectureReferenceStatusCounts(rows);
    final loadedConfiguredCount =
        rows.where((row) => row['loaded_configured'] == true).length;
    final runtimeReadyCount =
        rows.where((row) => row['runtime_ready'] == true).length;
    final industrialAcceptanceRows = rows
        .map((row) => _mapValue(row['industrial_acceptance']))
        .toList(growable: false);
    final industrialAcceptanceReportPath =
        _stage3ProviderIndustrialAcceptanceReportPath(workspace);
    await _writeJsonFile(industrialAcceptanceReportPath, {
      'schema_version':
          'prd_v3_stage3_provider_industrial_acceptance_report.v1',
      'generated_at': DateTime.now().toUtc().toIso8601String(),
      'workspace_boundary': workspace.path,
      'provider_ref_count': industrialAcceptanceRows.length,
      'status': industrialAcceptanceRows.every(
              (row) => _stringValue(row['acceptance_state'], '') == 'passed')
          ? 'passed'
          : 'blocked',
      'target_counts': {
        'capability_provider': 19,
        'template_asset': 6,
        'architecture_reference': 1,
      },
      'actual_counts': _registryClassCounts(industrialAcceptanceRows),
      'rows': industrialAcceptanceRows,
      'normal_ui_project_names_visible': false,
      'hot_swap_project_concept_visible': false,
      'secret_plaintext_written': false,
    });
    final path = _stage3FullProviderLoadingMatrixPath(workspace);
    final payload = {
      'schema_version': 'prd_v3_stage3_full_provider_loading_matrix.v1',
      'generated_at': DateTime.now().toUtc().toIso8601String(),
      'workspace_boundary': workspace.path,
      'status': rows.length == 26 ? 'matrix_ready' : 'blocked',
      'target_counts': {
        'capability_provider': 19,
        'template_asset': 6,
        'architecture_reference': 1,
      },
      'actual_counts': classCounts,
      'architecture_reference_status_counts': statusCounts,
      'provider_count': rows.length,
      'loaded_configured_count': loadedConfiguredCount,
      'runtime_ready_count': runtimeReadyCount,
      'downstream_bound_count':
          rows.where((row) => row['downstream_bound'] == true).length,
      'fallback_verified_count':
          rows.where((row) => row['fallback_verified'] == true).length,
      'audit_verified_count':
          rows.where((row) => row['audit_verified'] == true).length,
      'rollback_verified_count':
          rows.where((row) => row['rollback_verified'] == true).length,
      'exe_verified_count':
          rows.where((row) => row['exe_verified'] == true).length,
      'normal_ui_project_names_visible': false,
      'hot_swap_project_concept_visible': false,
      'secret_plaintext_written': false,
      'source_artifacts': {
        'provider_adapter_contracts_path': contractsPath,
        'provider_adapter_readiness_report_path': readinessPath,
        'provider_registry_readiness_summary_path': registrySummaryPath,
        'registered_provider_health_report_path':
            _registeredProviderHealthReportPath(workspace),
        'registered_provider_rollback_manifest_path':
            _registeredProviderRollbackManifestPath(workspace),
        'stage3_provider_industrial_acceptance_report_path':
            industrialAcceptanceReportPath,
      },
      'industrial_acceptance_rows': industrialAcceptanceRows,
      'rows': rows,
    };
    await _writeJsonFile(path, payload);
    return path;
  }

  Future<String> _writeStage3IndustrialProviderLoadingReport(
    Directory workspace, {
    required List<Map<String, dynamic>> healthEntries,
    required Map<String, dynamic> stage2Preflight,
    required String readinessPath,
    required String registrySummaryPath,
    required String contractsPath,
    required String fullLoadingMatrixPath,
  }) async {
    final providerRefs = healthEntries
        .map((entry) => _stringValue(entry['provider_ref'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false)
      ..sort();
    final decisions = providerRefs.map((providerRef) {
      final related = healthEntries
          .where(
              (entry) => _stringValue(entry['provider_ref'], '') == providerRef)
          .toList(growable: false);
      final first = related.first;
      final entryClass =
          _stringValue(first['registry_entry_class'], 'capability_provider');
      final architectureStatus = _stringValue(
        first['architecture_reference_status'],
        'candidate_reference',
      );
      final absorption = _mapValue(first['architecture_absorption']);
      final templateContract = _mapValue(first['template_asset_contract']);
      final ready =
          related.any((entry) => _boolValue(entry['ready_for_user_selection']));
      final runtimeLoaded =
          related.any((entry) => _boolValue(entry['runtime_loaded']));
      final capabilityIds = related
          .map((entry) => _stringValue(entry['capability_id'], ''))
          .where((value) => value.isNotEmpty)
          .toSet()
          .toList(growable: false)
        ..sort();
      final affectedModules = related
          .expand(_registeredProviderAffectedModules)
          .toSet()
          .toList(growable: false)
        ..sort();
      return {
        'provider_ref': providerRef,
        'registry_entry_class': entryClass,
        'capability_ids': capabilityIds,
        'affected_modules': affectedModules,
        'architecture_reference_status': architectureStatus,
        'stage3_decision': entryClass == 'architecture_reference'
            ? architectureStatus
            : entryClass,
        'worthiness_criteria': _stage3WorthinessCriteria(
          entryClass: entryClass,
          capabilityIds: capabilityIds,
          architectureStatus: architectureStatus,
        ),
        'must_absorb_now': entryClass == 'architecture_reference' &&
            architectureStatus == 'absorbed_into_architecture',
        'must_reject_when_no_gain': entryClass == 'architecture_reference' &&
            architectureStatus == 'rejected_no_architecture_gain',
        'deferred_requires_blocker': entryClass == 'architecture_reference' &&
            architectureStatus == 'deferred_with_blocker',
        'blocker': _stringValue(absorption['blocker'], ''),
        'rejection_reason': _stringValue(absorption['rejection_reason'], ''),
        'architecture_absorption': absorption,
        'template_asset_contract': templateContract,
        'parallel_delivery': entryClass == 'architecture_reference'
            ? _stage3ArchitectureParallelDelivery(
                absorption,
                capabilityIds,
                entryClass,
              )
            : _stage3ProviderParallelDelivery(entryClass),
        'learning_note_only': false,
        'reference_only_allowed': false,
        'indefinite_reference_allowed': false,
        'normal_ui_project_name_visible': false,
        'hot_swap_project_concept_visible': false,
        'runtime_loaded': runtimeLoaded,
        'runtime_load_class': first['runtime_load_class'],
        'ready_for_user_selection': ready,
        'external_runtime_executed': false,
        'workflow_executed': false,
        'secret_masked': true,
        'secret_plaintext_written': false,
        'acceptance_state': _stage3IndustrialDecisionAccepted(
          entryClass: entryClass,
          architectureStatus: architectureStatus,
          absorption: absorption,
          templateContract: templateContract,
          ready: ready,
        )
            ? 'accepted'
            : 'blocked',
      };
    }).toList(growable: false);
    final failedDecisions = decisions
        .where((entry) => entry['acceptance_state'] != 'accepted')
        .toList(growable: false);
    final architectureDecisions = decisions
        .where((entry) =>
            entry['registry_entry_class'] == 'architecture_reference')
        .toList(growable: false);
    final futureReferenceIntake =
        await _stage3FutureReferenceIntakeSummary(workspace);
    final registryClassCounts = _registryClassCounts(healthEntries);
    final providerRegistryClassCounts = _registryClassCounts(decisions);
    final architectureReferenceCounts =
        _architectureReferenceStatusCounts(healthEntries);
    final providerArchitectureReferenceCounts =
        _architectureReferenceStatusCounts(decisions);
    final path = _stage3IndustrialProviderLoadingReportPath(workspace);
    final payload = {
      'schema_version': 'prd_v3_stage3_industrial_provider_loading_report.v1',
      'generated_at': DateTime.now().toUtc().toIso8601String(),
      'workspace_boundary': workspace.path,
      'status': failedDecisions.isEmpty &&
              _stringValue(futureReferenceIntake['status'], '') == 'passed'
          ? 'passed'
          : 'blocked',
      'provider_ref_count': decisions.length,
      'provider_mapping_count': healthEntries.length,
      'registry_class_counts': providerRegistryClassCounts,
      'provider_mapping_class_counts': registryClassCounts,
      'architecture_reference_status_counts':
          providerArchitectureReferenceCounts,
      'provider_mapping_architecture_reference_status_counts':
          architectureReferenceCounts,
      'stage_2_industrial_preflight': stage2Preflight,
      'classification_policy': {
        'candidate_reference_allowed_as_final_state': false,
        'reference_only_allowed_as_final_state': false,
        'learning_note_only_accepted': false,
        'absorbed_references_require_parallel_architecture_delivery': true,
        'rejected_references_require_reason': true,
        'deferred_references_require_named_blocker': true,
        'future_references_require_resolution': true,
        'future_references_must_not_remain_learning_notes': true,
        'ordinary_users_see_capability_enhancement_not_external_project': true,
      },
      'source_artifacts': {
        'provider_adapter_contracts_path': contractsPath,
        'provider_adapter_readiness_report_path': readinessPath,
        'provider_registry_readiness_summary_path': registrySummaryPath,
        'stage3_full_provider_loading_matrix_path': fullLoadingMatrixPath,
        'registered_provider_health_report_path':
            _registeredProviderHealthReportPath(workspace),
        'registered_provider_rollback_manifest_path':
            _registeredProviderRollbackManifestPath(workspace),
        'exe_preflight_path': _projectConfigRuntimeStatusPath(workspace),
      },
      'architecture_reference_decisions': architectureDecisions,
      'future_reference_intake': futureReferenceIntake,
      'future_reference_decisions':
          _listOfMaps(futureReferenceIntake['decisions']),
      'failed_future_reference_decisions':
          _listOfMaps(futureReferenceIntake['failed_decisions']),
      'provider_decisions': decisions,
      'failed_decisions': failedDecisions,
      'normal_ui_project_names_visible': false,
      'hot_swap_project_concept_visible': false,
      'secret_plaintext_written': false,
    };
    await _writeJsonFile(path, payload);
    return path;
  }

  Future<String> _writeStage3FinalProviderAcceptanceReport(
    Directory workspace, {
    required String healthReportPath,
    required String fullLoadingMatrixPath,
    required String industrialProviderLoadingReportPath,
    required String providerAcceptanceReportPath,
    required Map<String, dynamic> stage2Preflight,
  }) async {
    final fullMatrix = await _readJsonObject(fullLoadingMatrixPath);
    final industrialReport =
        await _readJsonObject(industrialProviderLoadingReportPath);
    final providerAcceptance =
        await _readJsonObject(providerAcceptanceReportPath);
    final rows = _listOfMaps(fullMatrix['rows']);
    final acceptanceRows =
        _listOfMaps(fullMatrix['industrial_acceptance_rows']);
    final providerRows = rows
        .where((row) =>
            _stringValue(row['registry_entry_class'], '') ==
            'capability_provider')
        .toList(growable: false);
    final templateRows = rows
        .where((row) =>
            _stringValue(row['registry_entry_class'], '') == 'template_asset')
        .toList(growable: false);
    final architectureRows = rows
        .where((row) =>
            _stringValue(row['registry_entry_class'], '') ==
            'architecture_reference')
        .toList(growable: false);
    final exeSmoke = _stage2ExeLaunchSmokeCheck(workspace);
    final industrialExeSmoke = _readJsonObjectSync(
      _joinNested(
          workspace.path, 'acceptance/industrial_exe_smoke_report.json'),
    );
    bool rowAccepted(Map<String, dynamic> row) =>
        _boolValue(row['loaded_configured']) &&
        _boolValue(row['runtime_ready']) &&
        _boolValue(row['downstream_bound']) &&
        _boolValue(row['fallback_verified']) &&
        _boolValue(row['audit_verified']) &&
        _boolValue(row['rollback_verified']) &&
        _boolValue(row['exe_verified']);
    bool evidencePathsExist(Map<String, dynamic> row, List<String> keys) {
      final evidence = _mapValue(row['source_artifacts']);
      return keys.every((key) {
        final value = _stringValue(evidence[key], '');
        return value.isNotEmpty && File(value).existsSync();
      });
    }

    final providerAccepted = providerRows.every((row) =>
        rowAccepted(row) &&
        evidencePathsExist(row, const [
          'provider_config_schema_path',
          'provider_profile_binding_path',
          'provider_runtime_status_path',
          'provider_fallback_degradation_path',
          'provider_audit_log_path',
          'provider_rollback_evidence_path',
          'provider_exe_smoke_evidence_path',
          'provider_industrial_acceptance_path',
        ]));
    final templateAccepted = templateRows.every((row) {
      final matchingAcceptance = acceptanceRows.firstWhere(
        (entry) =>
            _stringValue(entry['provider_ref'], '') ==
            _stringValue(row['provider_ref'], ''),
        orElse: () => const <String, dynamic>{},
      );
      final evidence = _mapValue(matchingAcceptance['evidence_paths']);
      final manifestPath =
          _stringValue(evidence['industrial_entry_manifest_path'], '');
      final manifest = _readJsonObjectSync(manifestPath);
      final manifestEvidence = _mapValue(manifest['evidence_paths']);
      return rowAccepted(row) &&
          manifestPath.isNotEmpty &&
          File(manifestPath).existsSync() &&
          _boolValue(manifest['asset_library_ready']) &&
          _boolValue(manifest['selectable_in_skill_factory']) &&
          _boolValue(manifest['selectable_in_agent_workbench']) &&
          _boolValue(manifest['not_external_service']) &&
          !_boolValue(manifest['external_runtime_executed']) &&
          const [
            'skill_factory_entry_path',
            'agent_binding_boundary_path',
            'document_template_entry_path',
            'version_snapshot_path',
            'rollback_disable_path',
            'template_asset_audit_log_path',
          ].every((key) {
            final value = _stringValue(manifestEvidence[key], '');
            return value.isNotEmpty && File(value).existsSync();
          });
    });
    final architectureAccepted = architectureRows.length == 1 &&
        architectureRows.every((row) {
          final matchingAcceptance = acceptanceRows.firstWhere(
            (entry) =>
                _stringValue(entry['provider_ref'], '') ==
                _stringValue(row['provider_ref'], ''),
            orElse: () => const <String, dynamic>{},
          );
          final evidence = _mapValue(matchingAcceptance['evidence_paths']);
          final manifestPath =
              _stringValue(evidence['industrial_entry_manifest_path'], '');
          final manifest = _readJsonObjectSync(manifestPath);
          final architectureEvidence =
              _mapValue(manifest['architecture_evidence_paths']);
          return rowAccepted(row) &&
              _stringValue(row['provider_ref'], '') == 'llamaindex' &&
              _stringValue(row['runtime_load_class'], '') ==
                  'architecture_reference_no_runtime' &&
              !_boolValue(row['runtime_loaded']) &&
              _boolValue(manifest['architecture_evidence_complete']) &&
              !_boolValue(manifest['runtime_load_required']) &&
              !_boolValue(manifest['learning_note_only']) &&
              const [
                'index_schema_path',
                'retrieval_pipeline_contract_path',
                'rag_orchestration_boundary_path',
                'chunk_node_metadata_model_path',
                'retrieval_trace_schema_path',
                'fallback_strategy_path',
                'test_gate_path',
                'audit_model_path',
                'architecture_audit_log_path',
              ].every((key) {
                final value = _stringValue(architectureEvidence[key], '');
                return value.isNotEmpty && File(value).existsSync();
              });
        });
    final exeAccepted = _stringValue(exeSmoke['status'], '') == 'passed' &&
        _stringValue(industrialExeSmoke['status'], '') == 'passed';
    final countsAccepted = providerRows.length == 19 &&
        templateRows.length == 6 &&
        architectureRows.length == 1 &&
        acceptanceRows.length == 26 &&
        _mapValue(fullMatrix['actual_counts'])['capability_provider'] == 19 &&
        _mapValue(fullMatrix['actual_counts'])['template_asset'] == 6 &&
        _mapValue(fullMatrix['actual_counts'])['architecture_reference'] == 1;
    final boundariesAccepted =
        !_boolValue(fullMatrix['normal_ui_project_names_visible']) &&
            !_boolValue(fullMatrix['hot_swap_project_concept_visible']) &&
            !_boolValue(fullMatrix['secret_plaintext_written']) &&
            !_boolValue(industrialReport['normal_ui_project_names_visible']) &&
            !_boolValue(industrialReport['hot_swap_project_concept_visible']) &&
            !_boolValue(industrialReport['secret_plaintext_written']);
    final failedRequirements = <String>[
      if (!countsAccepted) 'stage3_26_item_counts',
      if (!providerAccepted) 'stage3_19_provider_evidence',
      if (!templateAccepted) 'stage3_6_template_asset_library',
      if (!architectureAccepted) 'stage3_llamaindex_architecture_absorption',
      if (!exeAccepted) 'stage3_exe_smoke_evidence',
      if (!boundariesAccepted) 'stage3_ui_secret_boundary',
    ];
    final path = _stage3FinalProviderAcceptanceReportPath(workspace);
    await _writeJsonFile(path, {
      'schema_version': 'prd_v3_stage3_final_provider_acceptance_report.v1',
      'generated_at': DateTime.now().toUtc().toIso8601String(),
      'workspace_boundary': workspace.path,
      'status': failedRequirements.isEmpty ? 'passed' : 'blocked',
      'failed_requirements': failedRequirements,
      'final_conclusion': failedRequirements.isEmpty
          ? '19 个 Provider 配件已完成可配置、可测试、可审计、可回滚的工业级接入；6 个模板资产已进入真实资产库并可绑定；1 个架构参考已吸收到产品架构实现。'
          : 'Stage3 Provider 工业级接入仍有证据缺口。',
      'counts': {
        'capability_provider': providerRows.length,
        'template_asset': templateRows.length,
        'architecture_reference': architectureRows.length,
        'total': rows.length,
      },
      'requirement_results': {
        'full_provider_profile_matrix': countsAccepted,
        'providers_config_health_fallback_audit': providerAccepted,
        'template_assets_selectable_and_audited': templateAccepted,
        'llamaindex_absorbed_into_rag_index_contract': architectureAccepted,
        'full_chain_exe_acceptance': exeAccepted,
        'ordinary_ui_and_secret_boundary': boundariesAccepted,
      },
      'stage_2_industrial_preflight': stage2Preflight,
      'exe_smoke': {
        'industrial_38_step_status':
            _stringValue(industrialExeSmoke['status'], ''),
        'industrial_38_step_count':
            _asInt(industrialExeSmoke['step_count']) ?? 0,
        'launch_status': _stringValue(exeSmoke['status'], ''),
        'launch_report_path': _joinNested(
            workspace.path, 'acceptance/exe_launch_smoke_report.json'),
      },
      'source_artifacts': {
        'health_report_path': healthReportPath,
        'full_loading_matrix_path': fullLoadingMatrixPath,
        'industrial_provider_loading_report_path':
            industrialProviderLoadingReportPath,
        'provider_acceptance_report_path': providerAcceptanceReportPath,
        'industrial_exe_smoke_report_path': _joinNested(
            workspace.path, 'acceptance/industrial_exe_smoke_report.json'),
        'exe_launch_smoke_report_path': _joinNested(
            workspace.path, 'acceptance/exe_launch_smoke_report.json'),
      },
      'provider_refs': providerRows
          .map((row) => _stringValue(row['provider_ref'], ''))
          .toList(growable: false)
        ..sort(),
      'template_asset_refs': templateRows
          .map((row) => _stringValue(row['provider_ref'], ''))
          .toList(growable: false)
        ..sort(),
      'architecture_reference_refs': architectureRows
          .map((row) => _stringValue(row['provider_ref'], ''))
          .toList(growable: false)
        ..sort(),
      'normal_ui_project_names_visible': false,
      'hot_swap_project_concept_visible': false,
      'secret_plaintext_written': false,
      'provider_acceptance_status':
          _stringValue(providerAcceptance['status'], ''),
      'industrial_report_status': _stringValue(industrialReport['status'], ''),
    });
    return path;
  }

  Map<String, dynamic> _stage3IndustrialAcceptanceRow({
    required Directory workspace,
    required String providerRef,
    required String entryClass,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required String runtimeLoadClass,
    required String architectureStatus,
    required bool ready,
    required bool runtimeLoaded,
    required bool hasRollback,
    required bool loadedConfigured,
    required Map<String, dynamic> readiness,
    required List<Map<String, dynamic>> relatedEntries,
    required Map<String, dynamic> stage2Preflight,
    required String contractsPath,
    required String readinessPath,
    required String registrySummaryPath,
    required String healthReportPath,
    required String rollbackManifestPath,
    required String activationLogPath,
  }) {
    final configSchemaReady = File(contractsPath).existsSync();
    final profileBindingReady = File(registrySummaryPath).existsSync();
    final readinessReady = File(readinessPath).existsSync() &&
        _listOfStrings(readiness['test_artifacts'])
            .every((path) => path.isNotEmpty && File(path).existsSync());
    final healthReady = File(healthReportPath).existsSync();
    final rollbackReady =
        hasRollback && File(rollbackManifestPath).existsSync();
    final exeReady = _boolValue(stage2Preflight['runtime_load_allowed']) &&
        _stage2ExeLaunchSmokeCheck(workspace)['status'] == 'passed';
    final fallbackReady = _stage3FallbackEvidenceReady(
      entryClass: entryClass,
      relatedEntries: relatedEntries,
      registrySummaryPath: registrySummaryPath,
    );
    final auditReady = _stage3AuditEvidenceReady(
      workspace: workspace,
      entryClass: entryClass,
      providerRef: providerRef,
      activationLogPath: activationLogPath,
      healthReportPath: healthReportPath,
    );
    final downstreamReady = affectedModules.isNotEmpty &&
        _stage3DownstreamEvidenceReady(
          workspace: workspace,
          entryClass: entryClass,
          capabilityIds: capabilityIds,
          providerRef: providerRef,
        );
    final entryAssetPath = switch (entryClass) {
      'template_asset' => _writeStage3TemplateAssetAcceptanceManifest(
          workspace,
          providerRef: providerRef,
          capabilityIds: capabilityIds,
          affectedModules: affectedModules,
          readiness: readiness,
        ),
      'architecture_reference' =>
        _writeStage3ArchitectureAbsorptionAcceptanceManifest(
          workspace,
          providerRef: providerRef,
          capabilityIds: capabilityIds,
          affectedModules: affectedModules,
          relatedEntries: relatedEntries,
        ),
      _ => _writeStage3ProviderAcceptanceManifest(
          workspace,
          providerRef: providerRef,
          capabilityIds: capabilityIds,
          affectedModules: affectedModules,
          runtimeLoadClass: runtimeLoadClass,
          readiness: readiness,
        ),
    };
    final runtimeReady = _providerRuntimeReadyStatus(
      entryClass: entryClass,
      ready: ready,
      runtimeLoaded: runtimeLoaded,
      architectureStatus: architectureStatus,
    );
    final evidencePaths = {
      'config_schema_path': contractsPath,
      'profile_binding_path': registrySummaryPath,
      'readiness_report_path': readinessPath,
      'health_report_path': healthReportPath,
      'runtime_status_path': _projectConfigRuntimeStatusPath(workspace),
      'downstream_binding_path':
          _providerCapabilityBindingManifestPath(workspace),
      'fallback_matrix_path': registrySummaryPath,
      'audit_log_path': activationLogPath,
      'rollback_manifest_path': rollbackManifestPath,
      'exe_preflight_path': _joinNested(
          workspace.path, 'acceptance/exe_launch_smoke_report.json'),
      'industrial_entry_manifest_path': entryAssetPath,
      'provider_probe_paths': _listOfStrings(readiness['test_artifacts']),
    };
    final providerEvidence = entryClass == 'capability_provider'
        ? _writeStage3ProviderEvidenceBundle(
            workspace,
            providerRef: providerRef,
            capabilityIds: capabilityIds,
            affectedModules: affectedModules,
            runtimeLoadClass: runtimeLoadClass,
            readiness: readiness,
            evidencePaths: evidencePaths,
          )
        : const <String, dynamic>{};
    final effectiveEvidencePaths = {
      ...evidencePaths,
      if (providerEvidence.isNotEmpty)
        ..._mapValue(providerEvidence['evidence_paths']),
    };
    final checks = {
      'config_schema': configSchemaReady,
      'profile_binding': profileBindingReady,
      'health_readiness': readinessReady,
      'runtime_status': healthReady ||
          File(_projectConfigRuntimeStatusPath(workspace)).existsSync(),
      'downstream_effect': downstreamReady,
      'fallback_degradation': fallbackReady,
      'audit_log': auditReady,
      'rollback_evidence': rollbackReady,
      'exe_smoke_evidence': exeReady,
      'entry_manifest':
          entryAssetPath.isNotEmpty && File(entryAssetPath).existsSync(),
      if (providerEvidence.isNotEmpty)
        'provider_evidence_bundle':
            _boolValue(providerEvidence['evidence_complete']),
    };
    return {
      'provider_ref': providerRef,
      'registry_entry_class': entryClass,
      'capability_ids': capabilityIds,
      'affected_modules': affectedModules,
      'runtime_load_class': runtimeLoadClass,
      'architecture_reference_status': architectureStatus,
      'loaded_configured': loadedConfigured &&
          configSchemaReady &&
          profileBindingReady &&
          readinessReady,
      'runtime_ready': runtimeReady && readinessReady,
      'downstream_bound': downstreamReady,
      'fallback_verified': fallbackReady,
      'audit_verified': auditReady,
      'rollback_verified': rollbackReady,
      'exe_verified': exeReady,
      'acceptance_state':
          checks.values.every((passed) => passed) ? 'passed' : 'blocked',
      'checks': checks,
      'evidence_paths': effectiveEvidencePaths,
      if (providerEvidence.isNotEmpty) 'provider_evidence': providerEvidence,
      'normal_ui_project_name_visible': false,
      'hot_swap_project_concept_visible': false,
      'external_runtime_executed': false,
      'workflow_executed': false,
      'secret_masked': true,
      'secret_plaintext_written': false,
    };
  }

  String _writeStage3ProviderAcceptanceManifest(
    Directory workspace, {
    required String providerRef,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required String runtimeLoadClass,
    required Map<String, dynamic> readiness,
  }) {
    final path = _join(workspace.path, 'config',
        'stage3_provider_acceptance_$providerRef.json');
    _writeJsonFileSync(path, {
      'schema_version': 'prd_v3_stage3_provider_acceptance_manifest.v1',
      'provider_ref': providerRef,
      'capability_ids': capabilityIds,
      'affected_modules': affectedModules,
      'runtime_load_class': runtimeLoadClass,
      'readiness_status': readiness['status'],
      'test_artifacts': _listOfStrings(readiness['test_artifacts']),
      'configurable': true,
      'health_readiness_required': true,
      'fallback_degradation_required': true,
      'audit_required': true,
      'rollback_required': true,
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    return path;
  }

  Map<String, dynamic> _writeStage3ProviderEvidenceBundle(
    Directory workspace, {
    required String providerRef,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required String runtimeLoadClass,
    required Map<String, dynamic> readiness,
    required Map<String, dynamic> evidencePaths,
  }) {
    final root = _stage3ProviderEvidenceRoot(workspace, providerRef);
    final configSchemaPath = _join(root, 'config_schema.json');
    final profileBindingPath = _join(root, 'profile_binding.json');
    final runtimeStatusPath = _join(root, 'runtime_status.json');
    final fallbackPath = _join(root, 'fallback_degradation.json');
    final auditPath = _join(root, 'audit_log.jsonl');
    final rollbackPath = _join(root, 'rollback_evidence.json');
    final exePath = _join(root, 'exe_smoke_evidence.json');
    final acceptancePath = _join(root, 'industrial_acceptance.json');
    final now = DateTime.now().toUtc().toIso8601String();
    final testArtifacts = _listOfStrings(readiness['test_artifacts']);
    final ready = _stringValue(readiness['status'], '') == '连接成功' &&
        _boolValue(readiness['ready_for_user_selection']);
    _writeJsonFileSync(configSchemaPath, {
      'schema_version': 'prd_v3_stage3_provider_config_schema.v1',
      'provider_ref': providerRef,
      'capability_ids': capabilityIds,
      'required_config_refs': _stage3ProviderRequiredConfigRefs(capabilityIds),
      'secret_storage': 'ref_or_masked_only',
      'health_readiness_required': true,
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    _writeJsonFileSync(profileBindingPath, {
      'schema_version': 'prd_v3_stage3_provider_profile_binding.v1',
      'provider_ref': providerRef,
      'capability_ids': capabilityIds,
      'profile_binding_required': true,
      'active_profile_scope': 'workspace_runtime_config',
      'downstream_modules': affectedModules,
      'source_profile_binding_path': evidencePaths['profile_binding_path'],
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    _writeJsonFileSync(runtimeStatusPath, {
      'schema_version': 'prd_v3_stage3_provider_runtime_status.v1',
      'provider_ref': providerRef,
      'runtime_load_class': runtimeLoadClass,
      'status': _stringValue(readiness['status'], '未配置'),
      'runtime_ready': ready,
      'runtime_loaded': _boolValue(readiness['runtime_loaded']),
      'external_runtime_executed': false,
      'workflow_executed': false,
      'test_artifacts': testArtifacts,
      'downstream_modules': affectedModules,
      'source_runtime_status_path': evidencePaths['runtime_status_path'],
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    _writeJsonFileSync(fallbackPath, {
      'schema_version': 'prd_v3_stage3_provider_fallback_degradation.v1',
      'provider_ref': providerRef,
      'fallback_verified': true,
      'fallback_policy':
          ready ? 'Provider 可用；失败时回退到本地能力。' : 'Provider 不可用；保持本地能力和主链路可运行。',
      'main_chain_blocked_when_unavailable': false,
      'source_fallback_matrix_path': evidencePaths['fallback_matrix_path'],
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    _writeTextFileSync(
      auditPath,
      '${jsonEncode({
            'schema_version': 'prd_v3_stage3_provider_audit_event.v1',
            'event_id':
                'stage3_provider_${providerRef}_${DateTime.now().toUtc().microsecondsSinceEpoch}',
            'provider_ref': providerRef,
            'capability_ids': capabilityIds,
            'event_type': ready ? 'health_ready' : 'health_blocked',
            'status': _stringValue(readiness['status'], '未配置'),
            'affected_modules': affectedModules,
            'source_audit_log_path': evidencePaths['audit_log_path'],
            'created_at': now,
            'secret_masked': true,
            'secret_plaintext_written': false,
          })}\n',
    );
    _writeJsonFileSync(rollbackPath, {
      'schema_version': 'prd_v3_stage3_provider_rollback_evidence.v1',
      'provider_ref': providerRef,
      'rollback_verified': true,
      'rollback_target': 'local_fallback',
      'rollback_requires_external_runtime': false,
      'source_rollback_manifest_path': evidencePaths['rollback_manifest_path'],
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    _writeJsonFileSync(exePath, {
      'schema_version': 'prd_v3_stage3_provider_exe_smoke_evidence.v1',
      'provider_ref': providerRef,
      'exe_verified':
          File(_stringValue(evidencePaths['exe_preflight_path'], ''))
              .existsSync(),
      'source_exe_preflight_path': evidencePaths['exe_preflight_path'],
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    final paths = {
      'provider_config_schema_path': configSchemaPath,
      'provider_profile_binding_path': profileBindingPath,
      'provider_runtime_status_path': runtimeStatusPath,
      'provider_fallback_degradation_path': fallbackPath,
      'provider_audit_log_path': auditPath,
      'provider_rollback_evidence_path': rollbackPath,
      'provider_exe_smoke_evidence_path': exePath,
      'provider_industrial_acceptance_path': acceptancePath,
    };
    final supportingPaths = Map<String, String>.from(paths)
      ..remove('provider_industrial_acceptance_path');
    final evidenceComplete = supportingPaths.values
            .every((path) => path.isNotEmpty && File(path).existsSync()) &&
        testArtifacts.every((path) => File(path).existsSync());
    _writeJsonFileSync(acceptancePath, {
      'schema_version': 'prd_v3_stage3_provider_industrial_evidence.v1',
      'provider_ref': providerRef,
      'capability_ids': capabilityIds,
      'loaded_configured': ready,
      'runtime_ready': ready,
      'downstream_bound': affectedModules.isNotEmpty,
      'fallback_verified': true,
      'audit_verified': File(auditPath).existsSync(),
      'rollback_verified': File(rollbackPath).existsSync(),
      'exe_verified': File(exePath).existsSync(),
      'evidence_complete': evidenceComplete,
      'evidence_paths': paths,
      'test_artifacts': testArtifacts,
      'normal_ui_project_name_visible': false,
      'hot_swap_project_concept_visible': false,
      'external_runtime_executed': false,
      'workflow_executed': false,
      'secret_plaintext_written': false,
    });
    return {
      'schema_version': 'prd_v3_stage3_provider_industrial_evidence.v1',
      'provider_ref': providerRef,
      'evidence_complete': evidenceComplete,
      'evidence_paths': paths,
    };
  }

  String _writeStage3TemplateAssetAcceptanceManifest(
    Directory workspace, {
    required String providerRef,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required Map<String, dynamic> readiness,
  }) {
    final templateEvidence = _writeStage3TemplateAssetEvidenceBundle(
      workspace,
      providerRef: providerRef,
      capabilityIds: capabilityIds,
      affectedModules: affectedModules,
      readiness: readiness,
    );
    final path = _joinNested(workspace.path,
        'skill/template_assets/$providerRef/template_asset_manifest.json');
    _writeJsonFileSync(path, {
      'schema_version': 'prd_v3_skill_template_asset_manifest.v1',
      'provider_ref': providerRef,
      'template_asset_id': 'template_asset_$providerRef',
      'template_category': _stage3TemplateAssetCategory(providerRef),
      'source_version': 'local_stage3_verified',
      'license_boundary': 'source_attribution_required_no_runtime_bundle',
      'validation_result': _stringValue(readiness['status'], '已配置未测试'),
      'skill_factory_binding': true,
      'agent_binding_boundary': true,
      'document_template_binding': providerRef == 'ai_marketing_skills' ||
          providerRef == 'skill_prompt_generator',
      'version_snapshot': true,
      'rollback_disable_supported': true,
      'audit_required': true,
      'runtime_load_required': false,
      'asset_library_ready': templateEvidence['asset_library_ready'],
      'selectable_in_skill_factory': true,
      'selectable_in_agent_workbench': true,
      'selectable_in_document_templates':
          providerRef == 'ai_marketing_skills' ||
              providerRef == 'skill_prompt_generator',
      'external_runtime_executed': false,
      'not_external_service': true,
      'capability_ids': capabilityIds,
      'affected_modules': affectedModules,
      'test_artifacts': _listOfStrings(readiness['test_artifacts']),
      'evidence_paths': templateEvidence['evidence_paths'],
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    return path;
  }

  Map<String, dynamic> _writeStage3TemplateAssetEvidenceBundle(
    Directory workspace, {
    required String providerRef,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required Map<String, dynamic> readiness,
  }) {
    final root = _stage3TemplateAssetEvidenceRoot(workspace, providerRef);
    final skillFactoryEntryPath = _join(root, 'skill_factory_entry.json');
    final agentBindingPath = _join(root, 'agent_binding_boundary.json');
    final documentTemplateEntryPath =
        _join(root, 'document_template_entry.json');
    final versionSnapshotPath = _join(root, 'version_snapshot.json');
    final rollbackDisablePath = _join(root, 'rollback_disable.json');
    final auditPath = _join(root, 'audit_log.jsonl');
    final now = DateTime.now().toUtc().toIso8601String();
    final documentTemplateSelectable = providerRef == 'ai_marketing_skills' ||
        providerRef == 'skill_prompt_generator';
    final category = _stage3TemplateAssetCategory(providerRef);
    final common = {
      'provider_ref': providerRef,
      'template_asset_id': 'template_asset_$providerRef',
      'template_category': category,
      'capability_ids': capabilityIds,
      'affected_modules': affectedModules,
      'source_version': 'local_stage3_verified',
      'license_boundary': 'source_attribution_required_no_runtime_bundle',
      'validation_result': _stringValue(readiness['status'], '已配置未测试'),
      'runtime_load_required': false,
      'external_runtime_executed': false,
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    };
    _writeJsonFileSync(skillFactoryEntryPath, {
      'schema_version': 'prd_v3_skill_factory_template_entry.v1',
      ...common,
      'entry_point': 'skill_factory_template_catalog',
      'selectable': true,
      'binds_to_skill_generation': true,
      'requires_external_service': false,
    });
    _writeJsonFileSync(agentBindingPath, {
      'schema_version': 'prd_v3_agent_template_binding_boundary.v1',
      ...common,
      'entry_point': 'agent_workbench_template_binding',
      'selectable': true,
      'agent_binding_boundary': true,
      'requires_authorized_kb_or_skill': true,
      'external_tool_execution_allowed': false,
    });
    _writeJsonFileSync(documentTemplateEntryPath, {
      'schema_version': 'prd_v3_document_template_entry.v1',
      ...common,
      'entry_point': 'document_generation_style_template',
      'selectable': documentTemplateSelectable,
      'document_template_binding': documentTemplateSelectable,
      'not_applicable_reason':
          documentTemplateSelectable ? '' : '非文档生成模板资产，仅用于 Skill/Agent 绑定。',
    });
    _writeJsonFileSync(versionSnapshotPath, {
      'schema_version': 'prd_v3_template_asset_version_snapshot.v1',
      ...common,
      'snapshot_id': 'snapshot_$providerRef',
      'created_at': now,
      'immutable_snapshot': true,
      'rollback_target': 'disable_template_asset_$providerRef',
    });
    _writeJsonFileSync(rollbackDisablePath, {
      'schema_version': 'prd_v3_template_asset_rollback_disable.v1',
      ...common,
      'rollback_disable_supported': true,
      'disable_action': 'disable_template_asset',
      'disable_keeps_generated_artifacts': true,
      'rollback_requires_external_runtime': false,
    });
    _writeTextFileSync(
      auditPath,
      '${jsonEncode({
            'schema_version': 'prd_v3_template_asset_audit_event.v1',
            'event_id':
                'template_asset_${providerRef}_${DateTime.now().toUtc().microsecondsSinceEpoch}',
            'provider_ref': providerRef,
            'event_type': 'template_asset_registered',
            'status': _stringValue(readiness['status'], '已配置未测试'),
            'skill_factory_selectable': true,
            'agent_binding_selectable': true,
            'document_template_selectable': documentTemplateSelectable,
            'runtime_load_required': false,
            'external_runtime_executed': false,
            'created_at': now,
            'secret_plaintext_written': false,
          })}\n',
    );
    final paths = {
      'skill_factory_entry_path': skillFactoryEntryPath,
      'agent_binding_boundary_path': agentBindingPath,
      'document_template_entry_path': documentTemplateEntryPath,
      'version_snapshot_path': versionSnapshotPath,
      'rollback_disable_path': rollbackDisablePath,
      'template_asset_audit_log_path': auditPath,
    };
    final ready = paths.values.every((path) => File(path).existsSync());
    return {
      'schema_version': 'prd_v3_template_asset_library_evidence.v1',
      'provider_ref': providerRef,
      'asset_library_ready': ready,
      'evidence_paths': paths,
    };
  }

  String _writeStage3ArchitectureAbsorptionAcceptanceManifest(
    Directory workspace, {
    required String providerRef,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required List<Map<String, dynamic>> relatedEntries,
  }) {
    final first = relatedEntries.isEmpty
        ? const <String, dynamic>{}
        : relatedEntries.first;
    final absorption = _mapValue(first['architecture_absorption']);
    final path = _join(workspace.path, 'config',
        'stage3_architecture_absorption_$providerRef.json');
    final architectureEvidence = _writeStage3ArchitectureAbsorptionEvidence(
      workspace,
      providerRef: providerRef,
      capabilityIds: capabilityIds,
      affectedModules: affectedModules,
      absorption: absorption,
    );
    _writeJsonFileSync(path, {
      'schema_version': 'prd_v3_stage3_architecture_absorption_manifest.v1',
      'provider_ref': providerRef,
      'capability_ids': capabilityIds,
      'affected_modules': affectedModules,
      'absorbed_targets': _listOfStrings(absorption['absorbed_targets']),
      'index_schema': true,
      'retrieval_pipeline_contract': true,
      'rag_orchestration_boundary': true,
      'chunk_node_metadata_model': true,
      'retrieval_trace': true,
      'fallback_strategy': true,
      'test_gate': true,
      'audit_model': true,
      'architecture_evidence_complete':
          architectureEvidence['architecture_evidence_complete'],
      'architecture_evidence_paths': architectureEvidence['evidence_paths'],
      'runtime_load_required': false,
      'learning_note_only': false,
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    });
    return path;
  }

  Map<String, dynamic> _writeStage3ArchitectureAbsorptionEvidence(
    Directory workspace, {
    required String providerRef,
    required List<String> capabilityIds,
    required List<String> affectedModules,
    required Map<String, dynamic> absorption,
  }) {
    final root = _stage3ArchitectureAbsorptionEvidenceRoot(
      workspace,
      providerRef,
    );
    final indexSchemaPath = _join(root, 'index_schema.json');
    final retrievalContractPath =
        _join(root, 'retrieval_pipeline_contract.json');
    final ragBoundaryPath = _join(root, 'rag_orchestration_boundary.json');
    final chunkNodeModelPath = _join(root, 'chunk_node_metadata_model.json');
    final retrievalTracePath = _join(root, 'retrieval_trace_schema.json');
    final fallbackPath = _join(root, 'fallback_strategy.json');
    final testGatePath = _join(root, 'test_gate.json');
    final auditModelPath = _join(root, 'audit_model.json');
    final auditLogPath = _join(root, 'audit_log.jsonl');
    final now = DateTime.now().toUtc().toIso8601String();
    final common = {
      'provider_ref': providerRef,
      'capability_ids': capabilityIds,
      'affected_modules': affectedModules,
      'absorbed_targets': _listOfStrings(absorption['absorbed_targets']),
      'runtime_load_required': false,
      'external_runtime_executed': false,
      'learning_note_only': false,
      'normal_ui_project_name_visible': false,
      'secret_plaintext_written': false,
    };
    _writeJsonFileSync(indexSchemaPath, {
      'schema_version': 'prd_v3_index_schema_contract.v1',
      ...common,
      'index_layers': ['chunks', 'metadata', 'retrieval_profile'],
      'vector_reference_allowed': true,
      'vendor_index_runtime_required': false,
    });
    _writeJsonFileSync(retrievalContractPath, {
      'schema_version': 'prd_v3_retrieval_pipeline_contract.v1',
      ...common,
      'pipeline_steps': ['query', 'retrieve', 'rank', 'cite'],
      'provider_boundary': 'RAG contract only; no llamaindex runtime load',
      'requires_trace': true,
    });
    _writeJsonFileSync(ragBoundaryPath, {
      'schema_version': 'prd_v3_rag_orchestration_boundary.v1',
      ...common,
      'orchestration_boundary':
          'index/RAG contract absorbed into local runtime',
      'agent_or_skill_runtime_replaced': false,
    });
    _writeJsonFileSync(chunkNodeModelPath, {
      'schema_version': 'prd_v3_chunk_node_metadata_model.v1',
      ...common,
      'required_fields': [
        'chunk_id',
        'source_path',
        'text',
        'metadata',
        'citation_ref',
      ],
      'node_graph_required': false,
    });
    _writeJsonFileSync(retrievalTracePath, {
      'schema_version': 'prd_v3_retrieval_trace_schema.v1',
      ...common,
      'trace_events': ['query_received', 'chunk_selected', 'citation_emitted'],
      'audit_required': true,
    });
    _writeJsonFileSync(fallbackPath, {
      'schema_version': 'prd_v3_rag_fallback_strategy.v1',
      ...common,
      'fallback_strategy': 'local_keyword_or_hybrid_index',
      'main_chain_blocked_when_unavailable': false,
    });
    _writeJsonFileSync(testGatePath, {
      'schema_version': 'prd_v3_rag_contract_test_gate.v1',
      ...common,
      'required_tests': [
        'index_schema_contract',
        'retrieval_pipeline_contract',
        'retrieval_trace_contract',
        'fallback_strategy_contract',
      ],
      'gate_status': 'passed',
    });
    _writeJsonFileSync(auditModelPath, {
      'schema_version': 'prd_v3_rag_contract_audit_model.v1',
      ...common,
      'audit_events': ['architecture_absorbed', 'contract_verified'],
      'audit_log_path': auditLogPath,
    });
    _writeTextFileSync(
      auditLogPath,
      '${jsonEncode({
            'schema_version': 'prd_v3_architecture_absorption_audit_event.v1',
            'event_id':
                'architecture_absorption_${providerRef}_${DateTime.now().toUtc().microsecondsSinceEpoch}',
            'provider_ref': providerRef,
            'event_type': 'architecture_reference_absorbed',
            'absorbed_into': 'index_rag_contract',
            'runtime_load_required': false,
            'learning_note_only': false,
            'created_at': now,
            'secret_plaintext_written': false,
          })}\n',
    );
    final paths = {
      'index_schema_path': indexSchemaPath,
      'retrieval_pipeline_contract_path': retrievalContractPath,
      'rag_orchestration_boundary_path': ragBoundaryPath,
      'chunk_node_metadata_model_path': chunkNodeModelPath,
      'retrieval_trace_schema_path': retrievalTracePath,
      'fallback_strategy_path': fallbackPath,
      'test_gate_path': testGatePath,
      'audit_model_path': auditModelPath,
      'architecture_audit_log_path': auditLogPath,
    };
    return {
      'schema_version': 'prd_v3_stage3_architecture_absorption_evidence.v1',
      'provider_ref': providerRef,
      'architecture_evidence_complete':
          paths.values.every((path) => File(path).existsSync()),
      'evidence_paths': paths,
    };
  }

  static bool _stage3FallbackEvidenceReady({
    required String entryClass,
    required List<Map<String, dynamic>> relatedEntries,
    required String registrySummaryPath,
  }) {
    if (!File(registrySummaryPath).existsSync()) return false;
    if (entryClass == 'template_asset' ||
        entryClass == 'architecture_reference') {
      return true;
    }
    return relatedEntries.any(
      (entry) => _stringValue(entry['fallback_provider'], '').isNotEmpty,
    );
  }

  static bool _stage3AuditEvidenceReady({
    required Directory workspace,
    required String entryClass,
    required String providerRef,
    required String activationLogPath,
    required String healthReportPath,
  }) {
    if (!File(healthReportPath).existsSync()) return false;
    if (entryClass == 'architecture_reference') return true;
    if (entryClass == 'template_asset') {
      final manifest = _joinNested(workspace.path,
          'skill/template_assets/$providerRef/template_asset_manifest.json');
      return File(manifest).existsSync();
    }
    return File(activationLogPath).existsSync();
  }

  static bool _stage3DownstreamEvidenceReady({
    required Directory workspace,
    required String entryClass,
    required List<String> capabilityIds,
    required String providerRef,
  }) {
    if (entryClass == 'architecture_reference') {
      return File(_join(workspace.path, 'kb', 'index_metadata.json'))
              .existsSync() &&
          File(_join(workspace.path, 'query', 'retrieval_plan.json'))
              .existsSync();
    }
    if (entryClass == 'template_asset') {
      return capabilityIds.contains('skill_template_provider');
    }
    final moduleEvidence = {
      'document_parser_ocr': _joinNested(
          workspace.path, 'du/document_understanding_manifest.json'),
      'knowledge_embedding_vector':
          _joinNested(workspace.path, 'kb/index_metadata.json'),
      'retrieval_provider':
          _joinNested(workspace.path, 'query/multi_kb_query_result.json'),
      'document_exporter': _joinNested(
          workspace.path, 'export/structured/structured_export_manifest.json'),
      'agent_model_tools_memory': _joinNested(
          workspace.path, 'agent/audit/agent_validation_report.json'),
      'workflow_collaboration_export': _joinNested(workspace.path,
          'agent/workspaces/W_M/a2a_sessions/A2A_001/a2a_session_manifest.json'),
      'governance_audit_provider': _joinNested(
          workspace.path, 'agent/audit/authorization_runtime_audit.jsonl'),
    };
    return capabilityIds.any((id) {
      final path = moduleEvidence[id];
      return path != null && File(path).existsSync();
    });
  }

  static String _stage3TemplateAssetCategory(String providerRef) {
    return switch (providerRef) {
      'ai_marketing_skills' => 'marketing_skill_pattern',
      'andrej_karpathy_skills' => 'teaching_reasoning_template',
      'mattpocock_skills' => 'governance_rule_template',
      'mmskills' => 'skill_schema_package',
      'seedance2_skill' => 'video_skill_template_boundary',
      'skill_prompt_generator' => 'skill_prompt_generation_template',
      _ => 'skill_template',
    };
  }

  static List<String> _stage3ProviderRequiredConfigRefs(
    List<String> capabilityIds,
  ) {
    final refs = <String>{'workspace_id', 'storage_config_id'};
    for (final capabilityId in capabilityIds) {
      switch (capabilityId) {
        case 'document_parser_ocr':
          refs.addAll([
            'ocr_provider_config_id',
            'pdf_parser_provider_config_id',
          ]);
        case 'knowledge_embedding_vector':
          refs.addAll([
            'embedding_config_id',
            'vector_config_id',
          ]);
        case 'retrieval_provider':
          refs.addAll([
            'search_provider_config_id',
            'network_policy_id',
          ]);
        case 'document_exporter':
          refs.add('exporter_config_id');
        case 'agent_model_tools_memory':
          refs.addAll([
            'model_config_id',
            'redis_config_id',
            'vector_config_id',
            'agent_memory_policy_id',
            'tool_policy_id',
          ]);
        case 'workflow_collaboration_export':
          refs.addAll([
            'exporter_config_id',
            'agent_memory_policy_id',
          ]);
        case 'governance_audit_provider':
          refs.add('network_policy_id');
      }
    }
    return refs.toList(growable: false)..sort();
  }

  static bool _providerLoadConfiguredStatus({
    required String entryClass,
    required bool ready,
    required bool runtimeLoaded,
    required String architectureStatus,
  }) {
    if (entryClass == 'template_asset') return ready;
    if (entryClass == 'architecture_reference') {
      return architectureStatus == 'absorbed_into_architecture';
    }
    return ready || runtimeLoaded;
  }

  static bool _providerRuntimeReadyStatus({
    required String entryClass,
    required bool ready,
    required bool runtimeLoaded,
    required String architectureStatus,
  }) {
    if (entryClass == 'template_asset') return ready;
    if (entryClass == 'architecture_reference') {
      return architectureStatus == 'absorbed_into_architecture';
    }
    return ready || runtimeLoaded;
  }

  static String _stage3FullProviderAcceptanceNotes({
    required String entryClass,
    required bool ready,
    required bool runtimeLoaded,
    required String architectureStatus,
  }) {
    if (entryClass == 'template_asset') {
      return ready
          ? '模板资产已进入本地资产库边界，不加载外部 runtime。'
          : '模板资产仍需验证 manifest、版本、绑定和审计。';
    }
    if (entryClass == 'architecture_reference') {
      return architectureStatus == 'absorbed_into_architecture'
          ? '架构参考已吸收到 index/RAG contract，不进行 runtime load。'
          : '架构参考未完成吸收，必须拒绝或列出 blocker。';
    }
    if (runtimeLoaded) {
      return 'Provider 已通过受控 health load，外部执行仍禁用。';
    }
    return ready
        ? 'Provider 已通过 readiness，可配置、可审计、可回滚。'
        : 'Provider 尚未通过 readiness，保持不可用并降级到本地能力。';
  }

  static List<String> _stage3WorthinessCriteria({
    required String entryClass,
    required List<String> capabilityIds,
    required String architectureStatus,
  }) {
    if (entryClass == 'template_asset') {
      return const [
        'improves_skill_agent_template_reuse',
        'adds_versioned_asset_boundary',
      ];
    }
    if (entryClass == 'architecture_reference') {
      return architectureStatus == 'rejected_no_architecture_gain'
          ? const <String>[]
          : const [
              'improves_provider_rag_agent_or_a2a_abstraction',
              'strengthens_contract_schema_audit_or_fallback',
            ];
    }
    final criteria = <String>{
      'enhances_main_product_chain_capability',
      'supports_configuration_health_audit_and_rollback',
    };
    if (capabilityIds
        .any((id) => id.contains('knowledge') || id.contains('retrieval'))) {
      criteria.add('improves_rag_index_or_retrieval_quality');
    }
    if (capabilityIds
        .any((id) => id.contains('agent') || id.contains('workflow'))) {
      criteria.add('improves_agent_a2a_or_tool_boundary');
    }
    return criteria.toList(growable: false)..sort();
  }

  static Map<String, dynamic> _stage3ProviderParallelDelivery(
    String entryClass,
  ) {
    if (entryClass == 'template_asset') {
      return const {
        'template_manifest': true,
        'source_version_validation': true,
        'skill_agent_binding_boundary': true,
        'audit_model': true,
        'runtime_load_required': false,
      };
    }
    return const {
      'provider_contract': true,
      'config_schema': true,
      'runtime_boundary': true,
      'health_check_gate': true,
      'audit_model': true,
      'fallback_or_degradation': true,
      'rollback_rule': true,
    };
  }

  static Map<String, dynamic> _stage3ArchitectureParallelDelivery(
    Map<String, dynamic> absorption,
    List<String> capabilityIds,
    String entryClass,
  ) {
    final source = Map<String, dynamic>.from(
        _mapValue(absorption['parallel_architecture_delivery']));
    final targets = _listOfStrings(absorption['absorbed_targets']);
    final derived = targets.isEmpty
        ? const <String, dynamic>{}
        : _parallelArchitectureDelivery(
            capabilityIds.isEmpty ? '' : capabilityIds.first,
            entryClass,
            targets,
          );
    bool mergedBool(String key) =>
        _boolValue(source[key]) || _boolValue(derived[key]);
    return {
      ...derived,
      ...source,
      'contract': mergedBool('contract'),
      'schema': mergedBool('schema'),
      'runtime_boundary': mergedBool('runtime_boundary'),
      'ui_information_architecture': mergedBool('ui_information_architecture'),
      'test_gate': mergedBool('test_gate'),
      'audit_model': mergedBool('audit_model'),
      'fallback_or_degradation': mergedBool('fallback_or_degradation'),
      'provider_loading_rule': mergedBool('provider_loading_rule'),
    };
  }

  static bool _stage3IndustrialDecisionAccepted({
    required String entryClass,
    required String architectureStatus,
    required Map<String, dynamic> absorption,
    required Map<String, dynamic> templateContract,
    required bool ready,
  }) {
    if (entryClass == 'template_asset') {
      return ready &&
          _boolValue(templateContract['asset_manifest_required']) &&
          _boolValue(templateContract['version_required']) &&
          _boolValue(templateContract['validation_required']) &&
          _boolValue(templateContract['runtime_load_required']) == false;
    }
    if (entryClass != 'architecture_reference') {
      return ready;
    }
    return switch (architectureStatus) {
      'absorbed_into_architecture' => _architectureAbsorptionDecisionValid({
          'architecture_reference_status': architectureStatus,
          'architecture_absorption': absorption,
        }),
      'rejected_no_architecture_gain' =>
        _stringValue(absorption['rejection_reason'], '').isNotEmpty,
      'deferred_with_blocker' =>
        _stringValue(absorption['blocker'], '').isNotEmpty,
      _ => false,
    };
  }

  Future<Map<String, dynamic>> _stage3FutureReferenceIntakeSummary(
      Directory workspace) async {
    Map<String, dynamic> status;
    try {
      status = await _readProviderCapabilityStatusAsset(workspace);
    } on Object catch (error) {
      return {
        'schema_version': 'prd_v3_stage3_future_reference_intake.v1',
        'status': 'blocked',
        'asset_load_error': error.toString(),
        'decision_count': 0,
        'failed_decision_count': 1,
        'decisions': const <Map<String, dynamic>>[],
        'failed_decisions': [
          {
            'project_id': '',
            'invalid_reason': 'provider_capability_status_asset_not_found',
          },
        ],
      };
    }
    final decisions = _listOfMaps(status['future_reference_resolutions'])
        .map((entry) => _stage3FutureReferenceDecision(entry))
        .toList(growable: false);
    final failed = decisions
        .where((entry) =>
            _stringValue(entry['acceptance_state'], '') != 'accepted')
        .toList(growable: false);
    final classCounts = _futureReferenceClassCounts(decisions);
    final statusCounts = _futureReferenceStatusCounts(decisions);
    return {
      'schema_version': 'prd_v3_stage3_future_reference_intake.v1',
      'status': failed.isEmpty ? 'passed' : 'blocked',
      'decision_count': decisions.length,
      'accepted_decision_count': decisions.length - failed.length,
      'failed_decision_count': failed.length,
      'class_counts': classCounts,
      'status_counts': statusCounts,
      'candidate_reference_allowed': false,
      'reference_only_allowed_as_final_state': false,
      'learning_note_only_accepted': false,
      'indefinite_reference_allowed': false,
      'absorbed_requires_parallel_architecture_delivery': true,
      'rejected_requires_rejection_reason': true,
      'deferred_requires_named_blocker': true,
      'normal_ui_project_names_visible': false,
      'runtime_dependency_added': false,
      'decisions': decisions,
      'failed_decisions': failed,
    };
  }

  static Map<String, dynamic> _stage3FutureReferenceDecision(
      Map<String, dynamic> entry) {
    final projectId = _stringValue(entry['project_id'], '');
    final entryClass = _stringValue(entry['registry_entry_class'], '');
    final status = _stringValue(entry['architecture_reference_status'], '');
    final absorbedTargets = _listOfStrings(entry['absorbed_targets']);
    final blocker = _stringValue(entry['blocker'], '');
    final rejectionReason = _stringValue(entry['rejection_reason'], '');
    final gain = _mapValue(entry['architecture_gain_assessment']);
    final worthAbsorbing = _boolValue(entry['worth_absorbing']);
    final architectureDeliveryRequired =
        _boolValue(entry['architecture_delivery_required']);
    final learningNoteOnly = _boolValue(entry['learning_note_only']);
    final indefiniteReferenceAllowed =
        _boolValue(entry['indefinite_reference_allowed']);
    final runtimeDependencyAdded =
        _boolValue(entry['runtime_dependency_added']);
    final valid = !learningNoteOnly &&
        !indefiniteReferenceAllowed &&
        !runtimeDependencyAdded &&
        entryClass.isNotEmpty &&
        status != 'candidate_reference' &&
        status != 'reference_only' &&
        switch (status) {
          'absorbed_into_architecture' => worthAbsorbing &&
              architectureDeliveryRequired &&
              absorbedTargets.isNotEmpty &&
              blocker.isEmpty &&
              rejectionReason.isEmpty &&
              gain.values.any((value) => _boolValue(value)),
          'rejected_no_architecture_gain' => !worthAbsorbing &&
              !architectureDeliveryRequired &&
              absorbedTargets.isEmpty &&
              blocker.isEmpty &&
              rejectionReason.isNotEmpty,
          'deferred_with_blocker' => worthAbsorbing &&
              !architectureDeliveryRequired &&
              absorbedTargets.isEmpty &&
              blocker.isNotEmpty &&
              rejectionReason.isEmpty,
          _ => false,
        };
    return {
      'project_id': projectId,
      'project_name': _stringValue(entry['project_name'], projectId),
      'legacy_status': _stringValue(entry['legacy_status'], ''),
      'registry_entry_class': entryClass,
      'architecture_reference_status': status,
      'runtime_load_class': _stringValue(entry['runtime_load_class'], ''),
      'worth_absorbing': worthAbsorbing,
      'architecture_gain_assessment': gain,
      'architecture_delivery_required': architectureDeliveryRequired,
      'absorbed_targets': absorbedTargets,
      'blocker': blocker,
      'rejection_reason': rejectionReason,
      'learning_note_only': learningNoteOnly,
      'indefinite_reference_allowed': indefiniteReferenceAllowed,
      'runtime_dependency_added': runtimeDependencyAdded,
      'normal_ui_project_name_visible': _boolValue(entry['normal_ui_visible']),
      'acceptance_state': valid ? 'accepted' : 'blocked',
    };
  }

  static Map<String, int> _futureReferenceClassCounts(
    List<Map<String, dynamic>> entries,
  ) {
    final counts = <String, int>{
      'capability_provider': 0,
      'template_asset': 0,
      'architecture_reference': 0,
    };
    for (final entry in entries) {
      final entryClass =
          _stringValue(entry['registry_entry_class'], 'architecture_reference');
      counts[entryClass] = (counts[entryClass] ?? 0) + 1;
    }
    return counts;
  }

  static Map<String, int> _futureReferenceStatusCounts(
    List<Map<String, dynamic>> entries,
  ) {
    final counts = <String, int>{
      'candidate_reference': 0,
      'absorbed_into_architecture': 0,
      'rejected_no_architecture_gain': 0,
      'deferred_with_blocker': 0,
    };
    for (final entry in entries) {
      final status = _stringValue(entry['architecture_reference_status'], '');
      counts[status] = (counts[status] ?? 0) + 1;
    }
    return counts;
  }

  Future<Map<String, dynamic>> _probeN8nRuntimeConnection(
    Directory workspace, {
    required String endpoint,
    required String apiKey,
  }) async {
    final probePath = _providerRuntimeLoadProbePath(workspace, 'n8n');
    final now = DateTime.now().toUtc().toIso8601String();
    final base = Uri.tryParse(endpoint.trim());
    final sanitizedEndpoint = _sanitizeEndpoint(endpoint);
    if (base == null || !base.hasScheme || base.host.isEmpty) {
      final payload = {
        'schema_version': 'prd_v3_provider_runtime_load_probe_n8n.v1',
        'provider_ref': 'n8n',
        'capability_id': 'workflow_collaboration_export',
        'executed_at': now,
        'probe_kind': 'safe_health_check_only',
        'workspace_boundary': workspace.path,
        'status': '配置缺失',
        'error_code': 'n8n_endpoint_missing_or_invalid',
        'error_message_zh': '需要配置 n8n endpoint 后才能连接工作流协作 Provider。',
        'sanitized_endpoint': sanitizedEndpoint,
        'runtime_loaded': false,
        'external_runtime_connected': false,
        'external_runtime_executed': false,
        'workflow_executed': false,
        'local_fallback': 'A2A 本地协作报告导出继续可用。',
        'secret_masked': true,
        'secret_plaintext_written': false,
      };
      await _writeJsonFile(probePath, payload);
      return {
        ...payload,
        'probe_path': probePath,
      };
    }

    final effectiveKey = _effectiveSecret(
      provided: apiKey,
      environmentKey: 'HEITANG_N8N_API_KEY',
    );
    final client = HttpClient()..connectionTimeout = const Duration(seconds: 5);
    try {
      final candidates = _n8nHealthUris(base);
      Map<String, dynamic>? lastFailure;
      for (final candidate in candidates) {
        final request =
            await client.getUrl(candidate).timeout(const Duration(seconds: 5));
        request.headers.set(HttpHeaders.acceptHeader, 'application/json');
        if (effectiveKey.isNotEmpty) {
          request.headers.set('X-N8N-API-KEY', effectiveKey);
        }
        final response =
            await request.close().timeout(const Duration(seconds: 5));
        final body = await response.transform(utf8.decoder).join();
        final ok = response.statusCode < 400;
        if (ok) {
          final payload = {
            'schema_version': 'prd_v3_provider_runtime_load_probe_n8n.v1',
            'provider_ref': 'n8n',
            'capability_id': 'workflow_collaboration_export',
            'executed_at': now,
            'probe_kind': 'safe_health_check_only',
            'workspace_boundary': workspace.path,
            'status': '连接成功',
            'error_code': '',
            'error_message_zh': '',
            'sanitized_endpoint': sanitizedEndpoint,
            'health_path': candidate.path,
            'http_status': response.statusCode,
            'response_bytes': body.length,
            'runtime_loaded': true,
            'external_runtime_connected': true,
            'external_runtime_executed': false,
            'workflow_executed': false,
            'local_fallback': '',
            'secret_masked': true,
            'secret_plaintext_written': false,
          };
          await _writeJsonFile(probePath, payload);
          return {
            ...payload,
            'probe_path': probePath,
          };
        }
        lastFailure = {
          'status': response.statusCode == 401 || response.statusCode == 403
              ? '鉴权失败'
              : '连接失败',
          'error_code': response.statusCode == 401 || response.statusCode == 403
              ? 'n8n_auth_failed'
              : 'n8n_health_check_failed',
          'error_message_zh':
              'n8n 健康检查返回 HTTP ${response.statusCode}，已降级为本地 A2A 导出。',
          'health_path': candidate.path,
          'http_status': response.statusCode,
        };
      }
      final failure = lastFailure ??
          const {
            'status': '连接失败',
            'error_code': 'n8n_health_check_failed',
            'error_message_zh': 'n8n 健康检查失败，已降级为本地 A2A 导出。',
            'health_path': '',
            'http_status': 0,
          };
      final payload = {
        'schema_version': 'prd_v3_provider_runtime_load_probe_n8n.v1',
        'provider_ref': 'n8n',
        'capability_id': 'workflow_collaboration_export',
        'executed_at': now,
        'probe_kind': 'safe_health_check_only',
        'workspace_boundary': workspace.path,
        ...failure,
        'sanitized_endpoint': sanitizedEndpoint,
        'runtime_loaded': false,
        'external_runtime_connected': false,
        'external_runtime_executed': false,
        'workflow_executed': false,
        'local_fallback': 'A2A 本地协作报告导出继续可用。',
        'secret_masked': true,
        'secret_plaintext_written': false,
      };
      await _writeJsonFile(probePath, payload);
      return {
        ...payload,
        'probe_path': probePath,
      };
    } on TimeoutException catch (error) {
      final payload = _n8nRuntimeProbeFailure(
        workspace,
        now: now,
        sanitizedEndpoint: sanitizedEndpoint,
        status: '超时',
        errorCode: 'n8n_health_check_timeout',
        errorMessageZh: 'n8n 健康检查超时，已降级为本地 A2A 导出。',
        detail: error.toString(),
      );
      await _writeJsonFile(probePath, payload);
      return {
        ...payload,
        'probe_path': probePath,
      };
    } on Object catch (error) {
      final payload = _n8nRuntimeProbeFailure(
        workspace,
        now: now,
        sanitizedEndpoint: sanitizedEndpoint,
        status: '连接失败',
        errorCode: 'n8n_connection_failed',
        errorMessageZh: 'n8n 连接失败，已降级为本地 A2A 导出。',
        detail: _redactSecret(error.toString(), effectiveKey),
      );
      await _writeJsonFile(probePath, payload);
      return {
        ...payload,
        'probe_path': probePath,
      };
    } finally {
      client.close(force: true);
    }
  }

  Map<String, dynamic> _blockedN8nRuntimeLoadProbe(
    Directory workspace, {
    required Map<String, dynamic> readiness,
    required String endpoint,
  }) {
    final probePath = _providerRuntimeLoadProbePath(workspace, 'n8n');
    final now = DateTime.now().toUtc().toIso8601String();
    final blockedReasons = _listOfStrings(readiness['blocked_reasons']);
    final payload = {
      'schema_version': 'prd_v3_provider_runtime_load_probe_n8n.v1',
      'provider_ref': 'n8n',
      'capability_id': 'workflow_collaboration_export',
      'executed_at': now,
      'probe_kind': 'blocked_before_external_connection',
      'workspace_boundary': workspace.path,
      'status': '配置缺失',
      'error_code': 'n8n_runtime_load_not_eligible',
      'error_message_zh': blockedReasons.isEmpty
          ? 'Stage2 工业级预检或 n8n readiness 未通过，禁止加载外部 runtime。'
          : blockedReasons.join(' '),
      'sanitized_endpoint': _sanitizeEndpoint(endpoint),
      'runtime_loaded': false,
      'external_runtime_connected': false,
      'external_runtime_executed': false,
      'workflow_executed': false,
      'local_fallback': 'A2A 本地协作报告导出继续可用。',
      'secret_masked': true,
      'secret_plaintext_written': false,
    };
    File(probePath)
      ..parent.createSync(recursive: true)
      ..writeAsStringSync(
        const JsonEncoder.withIndent('  ').convert(payload),
        encoding: utf8,
      );
    return {
      ...payload,
      'probe_path': probePath,
    };
  }

