          'enabled': _userStatus(parser['status']) != '已禁用',
          'test_parse': _userStatus(parser['status']),
          'fallback_policy': '内置 Parser 可用；外部 Parser 失败时回退本地解析。',
        },
        'exporter_provider': {
          'config_id': active.exporterConfigId,
