      'invalid_assets': invalidAssets,
      'passed': passed,
      'status': passed ? '连接成功' : '已配置未测试',
      'error_message_zh': passed ? '' : 'Agent 记忆生命周期证据不完整，暂不能启用 Agent 记忆能力增强。',
