      ...defaults,
      ...saved,
      'provider': {
        ..._mapValue(defaults['provider']),
        ..._mapValue(saved['provider']),
      },
      'redis': {
        ..._mapValue(defaults['redis']),
        ..._mapValue(saved['redis']),
      },
      'qdrant': {
        ..._mapValue(defaults['qdrant']),
        ..._mapValue(saved['qdrant']),
      },
      'exporters': {
        ..._mapValue(defaults['exporters']),
        ..._mapValue(saved['exporters']),
      },
    };
