  static Map<String, dynamic> _auditModuleSummary(
      List<Map<String, Object?>> records) {
    final modules = <String, Map<String, dynamic>>{};
    for (final record in records) {
      final module = _stringValue(record['module'], 'unknown');
      final status = _stringValue(record['status'], 'unknown');
      final row = modules.putIfAbsent(
        module,
        () => {
          'module': module,
          'record_count': 0,
          'success_count': 0,
          'not_run_count': 0,
          'failure_count': 0,
          'artifact_count': 0,
        },
      );
      row['record_count'] = (_asInt(row['record_count']) ?? 0) + 1;
      if (status == 'success') {
        row['success_count'] = (_asInt(row['success_count']) ?? 0) + 1;
      } else if (status == 'not_run') {
        row['not_run_count'] = (_asInt(row['not_run_count']) ?? 0) + 1;
      } else if (status == 'failed' ||
          status == 'blocked' ||
          status == 'degraded') {
        row['failure_count'] = (_asInt(row['failure_count']) ?? 0) + 1;
      }
      if (_stringValue(record['artifact'], '').isNotEmpty) {
        row['artifact_count'] = (_asInt(row['artifact_count']) ?? 0) + 1;
      }
    }
    final rows = modules.values.toList(growable: false)
      ..sort((a, b) => _stringValue(a['module'], '')
          .compareTo(_stringValue(b['module'], '')));
    return {
      'schema_version': 'prd_v3_audit_module_summary.v1',
      'module_count': rows.length,
      'record_count': records.length,
      'success_count': rows.fold<int>(
          0, (sum, row) => sum + (_asInt(row['success_count']) ?? 0)),
      'not_run_count': rows.fold<int>(
          0, (sum, row) => sum + (_asInt(row['not_run_count']) ?? 0)),
      'failure_count': rows.fold<int>(
          0, (sum, row) => sum + (_asInt(row['failure_count']) ?? 0)),
      'modules': rows,
    };
  }

  static Map<String, dynamic> _auditEventLedgerSummary(
      List<Map<String, dynamic>> rows) {
    final eventTypes = rows
        .map((row) => _stringValue(row['event_type'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false)
      ..sort();
    final statuses = <String, int>{};
    for (final row in rows) {
      final status = _stringValue(row['status'], 'unknown');
      statuses[status] = (statuses[status] ?? 0) + 1;
    }
    return {
      'schema_version': 'prd_v3_audit_event_ledger_summary.v1',
      'path': '',
      'record_count': rows.length,
      'event_type_count': eventTypes.length,
      'event_types': eventTypes.take(20).toList(growable: false),
      'status_counts': statuses,
    };
  }

  static Map<String, dynamic> _auditArtifactCatalogSummary(
      List<Map<String, dynamic>> rows) {
    final artifactTypes = rows
        .map((row) => _stringValue(row['artifact_type'], ''))
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false)
      ..sort();
    final activeCount = rows
        .where((row) =>
            _stringValue(row['status'], '') != 'deleted' &&
            _stringValue(row['file_path'], '').isNotEmpty)
        .length;
    final statuses = <String, int>{};
    for (final row in rows) {
      final status = _stringValue(row['status'], 'unknown');
      statuses[status] = (statuses[status] ?? 0) + 1;
    }
    return {
      'schema_version': 'prd_v3_audit_artifact_catalog_summary.v1',
      'path': '',
      'record_count': rows.length,
      'active_count': activeCount,
      'artifact_type_count': artifactTypes.length,
      'artifact_types': artifactTypes.take(20).toList(growable: false),
      'status_counts': statuses,
    };
  }

  Future<List<String>> _sourceNames() async {
    final workspace = _requireWorkspace();
    final manifest =
        await _readJsonObject(_join(workspace.path, 'source_manifest.json'));
    final sources = manifest['sources'];
    if (sources is List) {
      return sources
          .whereType<Map>()
          .map((item) =>
              (item['relative_path'] ?? item['source_name'] ?? '').toString())
          .where((name) => name.isNotEmpty)
          .toList(growable: false);
    }
    final sourceName = (manifest['source_name'] ?? '').toString();
    return sourceName.isEmpty ? const [] : [sourceName];
  }

  static String _compact(Object? value, {int maxLength = 180}) {
    final text =
        (value ?? '').toString().replaceAll(RegExp(r'\s+'), ' ').trim();
    if (text.length <= maxLength) return text;
    return '${text.substring(0, maxLength)}...';
  }

  static int _countJsonl(String path) {
    final file = File(path);
    if (!file.existsSync()) {
      return 0;
    }
    return file
        .readAsLinesSync(encoding: utf8)
        .where((line) => line.trim().isNotEmpty)
        .length;
  }

  static Future<Map<String, Object>> _sourceStructureStats(File file) async {
    final extension = _extension(file.path).toLowerCase();
    if (!{'.md', '.txt', '.url.md'}.contains(extension)) {
      return const {
        'word_count': 0,
        'image_count': 0,
        'table_count': 0,
        'link_count': 0,
        'structure_status': 'requires_parser',
      };
    }
    final text = await file.readAsString(encoding: utf8);
    final words = RegExp(r'[\p{L}\p{N}_]+', unicode: true).allMatches(text);
    final markdownImages = RegExp(r'!\[[^\]]*\]\([^)]+\)').allMatches(text);
    final explicitLinks = RegExp(r'https?://\S+').allMatches(text).length;
    final markdownLinks = RegExp(r'\[[^\]]+\]\([^)]+\)')
        .allMatches(text)
        .where((match) => match.start == 0 || text[match.start - 1] != '!')
        .length;
    final tableLines = text
        .split(RegExp(r'\r?\n'))
        .where(
            (line) => line.trim().startsWith('|') && line.trim().endsWith('|'))
        .length;
    return {
      'word_count': words.length,
      'image_count': markdownImages.length,
      'table_count': tableLines >= 2 ? 1 : 0,
      'link_count': explicitLinks + markdownLinks,
      'structure_status': 'local_text_scan',
    };
  }

  static int? _asInt(Object? value) {
    if (value is int) return value;
    if (value is num) return value.toInt();
    if (value is String) return int.tryParse(value);
    return null;
  }

  static double? _asDouble(Object? value) {
    if (value is double) return value;
    if (value is num) return value.toDouble();
    if (value is String) return double.tryParse(value);
    return null;
  }

  static bool _boolValue(Object? value) {
    if (value is bool) return value;
    return value?.toString().toLowerCase() == 'true';
  }

  static String _safeFileName(String name) {
    final cleaned = name.replaceAll(RegExp(r'[<>:"/\\|?*]'), '_');
    return cleaned.trim().isEmpty ? 'source.md' : cleaned;
  }

  static Future<File> _uniqueInputFile(
      Directory inputDir, String fileName) async {
    final extension = fileName.toLowerCase().endsWith('.url.md')
        ? '.url.md'
        : _extension(fileName);
    final stem = extension.isEmpty
        ? fileName
        : fileName.substring(0, fileName.length - extension.length);
    var candidate = File(_join(inputDir.path, fileName));
    var suffix = 1;
    while (await candidate.exists()) {
      candidate = File(_join(inputDir.path, '${stem}_$suffix$extension'));
      suffix += 1;
    }
    return candidate;
  }

  static Stream<File> _supportedSourceFiles(Directory root) async* {
    await for (final entity in root.list(recursive: true, followLinks: false)) {
      if (entity is File && _supportedSourceExtension(entity.path)) {
        yield entity;
      }
    }
  }

  static bool _supportedSourceExtension(String path) =>
      {'.md', '.txt', '.pdf', '.docx'}.contains(_extension(path).toLowerCase());

  static String _extension(String path) {
    final fileName = path.split(RegExp(r'[\\/]')).last;
    final dot = fileName.lastIndexOf('.');
    return dot < 0 ? '' : fileName.substring(dot);
  }

  static String _relativePath(String childPath, String parentPath) {
    final normalizedParent = parentPath
        .replaceAll('/', Platform.pathSeparator)
        .replaceAll(RegExp(r'[\\\/]+$'), '');
    final normalizedChild = childPath.replaceAll('/', Platform.pathSeparator);
    final prefix = '$normalizedParent${Platform.pathSeparator}';
    if (normalizedChild.toLowerCase().startsWith(prefix.toLowerCase())) {
      return normalizedChild.substring(prefix.length);
    }
    return normalizedChild.split(Platform.pathSeparator).last;
  }

  static String _joinNested(String root, String relative) {
    final segments = relative
        .split(RegExp(r'[\\/]'))
        .where((segment) => segment.trim().isNotEmpty)
        .map(_safeFileName)
        .toList(growable: false);
    return ([root, ...segments]).join(Platform.pathSeparator);
  }

  static String _primarySkillPath(String skillRoot) {
    final primary = _join(skillRoot, 'knowledge_qa_skill');
    return Directory(primary).existsSync() ? primary : skillRoot;
  }

  static String _documentId(Map<String, dynamic> source) {
    final seed = (source['relative_path'] ?? source['source_name'] ?? 'source')
        .toString()
        .replaceAll('\\', '/');
    final hash = _stableHash(seed);
    return 'doc_$hash';
  }

  static int _stableHash(String value) {
    return value.codeUnits
        .fold<int>(17, (hash, unit) => (hash * 31 + unit) & 0x7fffffff);
  }

  static String _normalizePathKey(Object? value) {
    return (value ?? '').toString().replaceAll('\\', '/').trim().toLowerCase();
  }

  static Future<Directory> _uniqueExportDirectory(
      Directory root, String baseName) async {
    var candidate = Directory(_join(root.path, baseName));
    var suffix = 1;
    while (await candidate.exists()) {
      candidate = Directory(_join(root.path, '${baseName}_$suffix'));
      suffix += 1;
    }
    return candidate;
  }

  static Future<void> _copyDirectory(
      Directory source, Directory destination) async {
    if (!await source.exists()) {
      return;
    }
    await destination.create(recursive: true);
    await for (final entity in source.list(recursive: true)) {
      final relative = _relativePath(entity.path, source.path);
      final target = _joinNested(destination.path, relative);
      if (entity is Directory) {
        await Directory(target).create(recursive: true);
      } else if (entity is File) {
        await Directory(target).parent.create(recursive: true);
        await entity.copy(target);
      }
    }
  }

  static bool _isInsideDirectory(String childPath, String parentPath) {
    final normalizedParent = parentPath
        .replaceAll('/', Platform.pathSeparator)
        .toLowerCase()
        .replaceAll(RegExp(r'[\\\/]+$'), '');
    final normalizedChild =
        childPath.replaceAll('/', Platform.pathSeparator).toLowerCase();
    return normalizedChild == normalizedParent ||
        normalizedChild
            .startsWith('$normalizedParent${Platform.pathSeparator}');
  }

  static String _join(String first, String second, [String? third]) {
    final separator = Platform.pathSeparator;
    final parts = [first, second, if (third != null) third];
    return parts
        .map((part) => part.replaceAll(RegExp(r'[\\\/]+$'), ''))
        .join(separator);
  }
}

class _StoredZipEncoder {
  final _output = BytesBuilder(copy: false);
  final _centralDirectory = <_StoredZipEntry>[];

  void addText(String path, String content) {
    final nameBytes = utf8.encode(path.replaceAll('\\', '/'));
    final data = utf8.encode(content);
    final offset = _output.length;
    final crc = _crc32(data);
    _writeUint32(0x04034b50);
    _writeUint16(20);
    _writeUint16(0);
    _writeUint16(0);
    _writeUint16(0);
    _writeUint16(0);
    _writeUint32(crc);
    _writeUint32(data.length);
    _writeUint32(data.length);
    _writeUint16(nameBytes.length);
    _writeUint16(0);
    _output.add(nameBytes);
    _output.add(data);
    _centralDirectory.add(_StoredZipEntry(
      nameBytes: nameBytes,
      crc32: crc,
      size: data.length,
      offset: offset,
    ));
  }

  List<int> finish() {
    final centralStart = _output.length;
    for (final entry in _centralDirectory) {
      _writeUint32(0x02014b50);
      _writeUint16(20);
      _writeUint16(20);
      _writeUint16(0);
      _writeUint16(0);
      _writeUint16(0);
      _writeUint16(0);
      _writeUint32(entry.crc32);
      _writeUint32(entry.size);
      _writeUint32(entry.size);
      _writeUint16(entry.nameBytes.length);
      _writeUint16(0);
      _writeUint16(0);
      _writeUint16(0);
      _writeUint16(0);
      _writeUint32(0);
      _writeUint32(entry.offset);
      _output.add(entry.nameBytes);
    }
    final centralSize = _output.length - centralStart;
    _writeUint32(0x06054b50);
    _writeUint16(0);
    _writeUint16(0);
    _writeUint16(_centralDirectory.length);
    _writeUint16(_centralDirectory.length);
    _writeUint32(centralSize);
    _writeUint32(centralStart);
    _writeUint16(0);
    return _output.takeBytes();
  }

  void _writeUint16(int value) {
    _output.add([
      value & 0xff,
      (value >> 8) & 0xff,
    ]);
  }

  void _writeUint32(int value) {
    _output.add([
      value & 0xff,
      (value >> 8) & 0xff,
      (value >> 16) & 0xff,
      (value >> 24) & 0xff,
    ]);
  }

  static int _crc32(List<int> bytes) {
    var crc = 0xffffffff;
    for (final byte in bytes) {
      crc ^= byte;
      for (var i = 0; i < 8; i += 1) {
        crc = (crc & 1) == 1 ? (crc >> 1) ^ 0xedb88320 : crc >> 1;
      }
    }
    return (crc ^ 0xffffffff) & 0xffffffff;
  }
}

class _StoredZipEntry {
  const _StoredZipEntry({
    required this.nameBytes,
    required this.crc32,
    required this.size,
    required this.offset,
  });

  final List<int> nameBytes;
  final int crc32;
  final int size;
  final int offset;
}

